  KG = 'kg',
  M = 'm',
  M2 = 'm²',
  HOUR = 'h'
}

export interface Client {
  id: string;
  name: string;
  email: string;
  phone: string;
  nif: string; // Tax ID
  address: string;
  postalCode: string;
  city: string;
}

