import React, { useState, useRef } from 'react';
import { PlusIcon, SparklesIcon, TrashIcon, PencilIcon, CameraIcon, MagnifyingGlassIcon } from '@heroicons/react/24/outline';
import { Article, UnitType } from '../types';
import { generateArticleDescription } from '../services/geminiService';
import SchematicDesigner from './SchematicDesigner';

interface ArticleManagerProps {
  articles: Article[];
  setArticles: (articles: Article[]) => void;
}

const ArticleManager: React.FC<ArticleManagerProps> = ({ articles, setArticles }) => {
  const [isEditing, setIsEditing] = useState(false);
  const [showDesigner, setShowDesigner] = useState(false);
  const [loadingAi, setLoadingAi] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  const [currentArticle, setCurrentArticle] = useState<Partial<Article>>({
    name: '',
    description: '',
    price: 0,
    unit: UnitType.UN
  });

  const handleSave = () => {
    if (!currentArticle.name || currentArticle.price === undefined) return;

    if (currentArticle.id) {
      // Update
      const updated = articles.map(a => a.id === currentArticle.id ? currentArticle as Article : a);
      setArticles(updated);
    } else {
      // Create
      const newArticle: Article = {
        ...currentArticle as Article,
        id: crypto.randomUUID()
      };
      setArticles([...articles, newArticle]);
    }
    setIsEditing(false);
    setCurrentArticle({ name: '', description: '', price: 0, unit: UnitType.UN });
  };

  const handleDelete = (id: string) => {
    if (confirm('Tem a certeza que deseja apagar este artigo?')) {
      setArticles(articles.filter(a => a.id !== id));
    }
  };

  const handleEdit = (article: Article) => {
    setCurrentArticle(article);
    setIsEditing(true);
  };

  const handleAiDescription = async () => {
    if (!currentArticle.name) return;
    setLoadingAi(true);
    const desc = await generateArticleDescription(currentArticle.name);
    setCurrentArticle(prev => ({ ...prev, description: desc }));
    setLoadingAi(false);
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
        const file = e.target.files[0];
        const reader = new FileReader();
        reader.onload = (ev) => {
            setCurrentArticle({ ...currentArticle, image: ev.target?.result as string });
        };
        reader.readAsDataURL(file);
    }
  };

  const filteredArticles = articles.filter(a => 
      a.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
      a.description.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="max-w-6xl mx-auto">
      {showDesigner && (
          <SchematicDesigner 
            onSave={(img) => { setCurrentArticle({...currentArticle, image: img}); setShowDesigner(false); }}
            onCancel={() => setShowDesigner(false)}
          />
      )}

      <div className="flex flex-col md:flex-row justify-between items-center mb-6 gap-4">
        <h2 className="text-2xl font-bold text-metal-800">Catálogo de Artigos</h2>

        <div className="flex gap-2 w-full md:w-auto">
            <div className="relative flex-1 md:w-64">
                <MagnifyingGlassIcon className="absolute left-3 top-2.5 w-5 h-5 text-gray-400" />
                <input 
                    type="text" 
                    placeholder="Procurar artigo..." 
                    value={searchTerm}
                    onChange={e => setSearchTerm(e.target.value)}
                    className="w-full pl-10 pr-4 py-2 border border-metal-300 rounded-lg bg-white text-gray-900 focus:ring-2 focus:ring-primary-500 outline-none"
                />
            </div>
            <button
            onClick={() => {
                setCurrentArticle({ name: '', description: '', price: 0, unit: UnitType.UN });
                setIsEditing(true);
            }}
            className="bg-primary-600 hover:bg-primary-700 text-white px-4 py-2 rounded-lg flex items-center shadow-sm whitespace-nowrap"
            >
            <PlusIcon className="w-5 h-5 mr-2" />
            Novo
            </button>
        </div>
      </div>

      {isEditing && (
        <div className="bg-white p-6 rounded-xl shadow-lg border border-metal-200 mb-8 animate-fade-in">
          <h3 className="text-lg font-semibold mb-4 text-metal-700">
            {currentArticle.id ? 'Editar Artigo' : 'Novo Artigo'}
          </h3>
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">

            {/* Image Area */}
            <div className="col-span-1">
                <label className="block text-sm font-medium text-metal-600 mb-2">Imagem / Desenho</label>
                <div className="border-2 border-dashed border-gray-300 rounded-lg h-48 flex flex-col items-center justify-center bg-gray-50 relative overflow-hidden group">
                    {currentArticle.image ? (
                        <>
                            <img src={currentArticle.image} alt="Preview" className="w-full h-full object-contain" />
                            <div className="absolute inset-0 bg-black/50 opacity-0 group-hover:opacity-100 transition-opacity flex flex-col items-center justify-center gap-2">
                                <button onClick={() => setCurrentArticle({...currentArticle, image: undefined})} className="text-white text-sm hover:underline">Remover</button>
                            </div>
                        </>
                    ) : (
                        <div className="text-center p-4">
                            <CameraIcon className="w-10 h-10 text-gray-300 mx-auto mb-2" />
                            <p className="text-xs text-gray-500">Carregar ou Desenhar</p>
                        </div>
                    )}
                </div>
                <div className="flex gap-2 mt-2">
                    <button onClick={() => fileInputRef.current?.click()} className="flex-1 text-xs bg-gray-100 hover:bg-gray-200 p-2 rounded text-gray-700">Carregar Foto</button>
                    <button onClick={() => setShowDesigner(true)} className="flex-1 text-xs bg-blue-100 hover:bg-blue-200 p-2 rounded text-blue-700">Criar Desenho</button>
                    <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleImageUpload} />
                </div>
            </div>

            {/* Form Fields */}
            <div className="col-span-1 md:col-span-2 grid grid-cols-1 md:grid-cols-2 gap-4">
                <div className="md:col-span-2">
                <label className="block text-sm font-medium text-metal-600 mb-1">Nome do Artigo</label>
                <input
                    type="text"
                    value={currentArticle.name}
                    onChange={e => setCurrentArticle({...currentArticle, name: e.target.value})}
                    className="w-full bg-white text-gray-900 border border-gray-300 rounded-lg p-2 focus:ring-2 focus:ring-primary-500 outline-none"
                    placeholder="Ex: Portão de Correr"
                />
                </div>

                <div className="md:col-span-2">
                <label className="block text-sm font-medium text-metal-600 mb-1">Descrição</label>
                <div className="flex gap-2">
                    <textarea
                    value={currentArticle.description}
                    onChange={e => setCurrentArticle({...currentArticle, description: e.target.value})}
                    className="w-full bg-white text-gray-900 border border-gray-300 rounded-lg p-2 focus:ring-2 focus:ring-primary-500 outline-none h-20"
                    />
                    <button 
                        onClick={handleAiDescription}
                        disabled={loadingAi || !currentArticle.name}
                        className="flex-shrink-0 bg-purple-50 hover:bg-purple-100 text-purple-700 border border-purple-200 rounded-lg px-3 flex flex-col items-center justify-center"
                    >
                        <SparklesIcon className={`w-5 h-5 ${loadingAi ? 'animate-spin' : ''}`} />
                    </button>
                </div>
                </div>

                <div>
                <label className="block text-sm font-medium text-metal-600 mb-1">Preço Unitário (€)</label>
                <input
                    type="number"
                    value={currentArticle.price === 0 ? '' : currentArticle.price}
                    onChange={e => setCurrentArticle({...currentArticle, price: Number(e.target.value)})}
                    className="w-full bg-white text-gray-900 border border-gray-300 rounded-lg p-2 focus:ring-2 focus:ring-primary-500 outline-none"
                    min="0"
                    step="0.01"
                />
                </div>

                <div>
                <label className="block text-sm font-medium text-metal-600 mb-1">Unidade</label>
                <select
                    value={currentArticle.unit}
                    onChange={e => setCurrentArticle({...currentArticle, unit: e.target.value as UnitType})}
                    className="w-full bg-white text-gray-900 border border-gray-300 rounded-lg p-2 focus:ring-2 focus:ring-primary-500 outline-none"
                >
                    {Object.values(UnitType).map(u => (
                        <option key={u} value={u}>{u.toUpperCase()}</option>
                    ))}
                </select>
                </div>
            </div>
          </div>

          <div className="flex justify-end gap-3 mt-6 pt-4 border-t border-gray-100">
            <button onClick={() => setIsEditing(false)} className="px-4 py-2 text-metal-600 hover:bg-metal-100 rounded-lg">Cancelar</button>
            <button onClick={handleSave} className="px-6 py-2 bg-primary-600 hover:bg-primary-700 text-white rounded-lg shadow-sm font-medium">Guardar</button>
          </div>
        </div>
      )}

      <div className="bg-white rounded-xl shadow-sm border border-metal-200 overflow-hidden">
        <div className="overflow-x-auto">
            <table className="w-full text-left border-collapse">
            <thead className="bg-metal-50 text-metal-600 text-sm uppercase font-semibold">
                <tr>
                <th className="p-4 border-b border-metal-100 w-20">Foto</th>
                <th className="p-4 border-b border-metal-100">Artigo</th>
                <th className="p-4 border-b border-metal-100">Unidade</th>
                <th className="p-4 border-b border-metal-100 text-right">Preço</th>
                <th className="p-4 border-b border-metal-100 text-center w-32">Ações</th>
                </tr>
            </thead>
            <tbody className="divide-y divide-metal-100">
                {filteredArticles.length === 0 && (
                    <tr>
                        <td colSpan={5} className="p-8 text-center text-metal-400">Nenhum artigo encontrado.</td>
                    </tr>
                )}
                {filteredArticles.map((article) => (
                <tr key={article.id} className="hover:bg-metal-50 transition-colors">
                    <td className="p-2">
                        {article.image ? (
                            <img src={article.image} alt="" className="w-12 h-12 object-contain rounded border border-gray-200 bg-white" />
                        ) : (
                            <div className="w-12 h-12 bg-gray-100 rounded flex items-center justify-center text-gray-400"><CameraIcon className="w-6 h-6"/></div>
                        )}
                    </td>
                    <td className="p-4">
                        <div className="font-semibold text-metal-900">{article.name}</div>
                        <div className="text-sm text-metal-500 truncate max-w-md">{article.description}</div>
                    </td>
                    <td className="p-4 text-metal-600 font-mono text-sm">{article.unit.toUpperCase()}</td>
                    <td className="p-4 text-right font-medium text-metal-900">
                        {article.price.toFixed(2)} €
                    </td>
                    <td className="p-4 text-center">
                    <div className="flex justify-center gap-2">
                        <button onClick={() => handleEdit(article)} className="p-1.5 text-blue-600 hover:bg-blue-50 rounded-md">
                            <PencilIcon className="w-5 h-5" />
                        </button>
                        <button onClick={() => handleDelete(article.id)} className="p-1.5 text-red-600 hover:bg-red-50 rounded-md">
                            <TrashIcon className="w-5 h-5" />
                        </button>
                    </div>
                    </td>
                </tr>
                ))}
            </tbody>
            </table>
        </div>
      </div>
    </div>
  );
};

export default ArticleManager;

import React, { useState } from 'react';
import { PlusIcon, TrashIcon, PencilIcon, UserIcon, PhoneIcon, EnvelopeIcon, MagnifyingGlassIcon, ChartPieIcon } from '@heroicons/react/24/outline';
import { Client, Quote, QuoteStatus } from '../types';

interface ClientManagerProps {
  clients: Client[];
  setClients: (clients: Client[]) => void;
  quotes?: Quote[]; // Para calcular estatísticas
}

const ClientManager: React.FC<ClientManagerProps> = ({ clients, setClients, quotes = [] }) => {
  const [isEditing, setIsEditing] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [currentClient, setCurrentClient] = useState<Partial<Client>>({});

  const handleSave = () => {
    if (!currentClient.name) return;

    if (currentClient.id) {
      const updated = clients.map(c => c.id === currentClient.id ? currentClient as Client : c);
      setClients(updated);
    } else {
      const newClient: Client = {
        id: crypto.randomUUID(),
        name: currentClient.name || '',
        email: currentClient.email || '',
        phone: currentClient.phone || '',
        nif: currentClient.nif || '',
        address: currentClient.address || '',
        postalCode: currentClient.postalCode || '',
        city: currentClient.city || ''
      };
      setClients([...clients, newClient]);
    }
    setIsEditing(false);
    setCurrentClient({});
  };

  const handleDelete = (id: string) => {
    if (confirm('Apagar este cliente?')) {
      setClients(clients.filter(c => c.id !== id));
    }
  };

  const handleEdit = (client: Client) => {
    setCurrentClient(client);
    setIsEditing(true);
  };

  const filteredClients = clients.filter(c => 
      c.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
      c.nif.includes(searchTerm)
  );

  const getClientStats = (clientId: string) => {
      const clientQuotes = quotes.filter(q => q.clientId === clientId);
      const accepted = clientQuotes.filter(q => q.status === QuoteStatus.ACCEPTED);
      const rejected = clientQuotes.filter(q => q.status === QuoteStatus.REJECTED);
      const totalInvoiced = accepted.reduce((sum, q) => sum + q.total, 0);

      return {
          totalQuotes: clientQuotes.length,
          acceptedCount: accepted.length,
          rejectedCount: rejected.length,
          totalInvoiced
      };
  };

  return (
    <div className="max-w-6xl mx-auto">
      <div className="flex flex-col md:flex-row justify-between items-center mb-6 gap-4">
        <h2 className="text-2xl font-bold text-metal-800">Meus Clientes</h2>

        <div className="flex gap-2 w-full md:w-auto">
            <div className="relative flex-1 md:w-64">
                <MagnifyingGlassIcon className="absolute left-3 top-2.5 w-5 h-5 text-gray-400" />
                <input 
                    type="text" 
                    placeholder="Filtrar por nome ou NIF..." 
                    value={searchTerm}
                    onChange={e => setSearchTerm(e.target.value)}
                    className="w-full pl-10 pr-4 py-2 border border-metal-300 rounded-lg bg-white text-gray-900 focus:ring-2 focus:ring-primary-500 outline-none"
                />
            </div>
            <button
            onClick={() => {
                setCurrentClient({});
                setIsEditing(true);
            }}
            className="bg-primary-600 hover:bg-primary-700 text-white px-4 py-2 rounded-lg flex items-center shadow-sm whitespace-nowrap"
            >
            <PlusIcon className="w-5 h-5 mr-2" />
            Novo
            </button>
        </div>
      </div>

      {isEditing && (
        <div className="bg-white p-6 rounded-xl shadow-lg border border-metal-200 mb-8 animate-fade-in">
          <h3 className="text-lg font-semibold mb-4 text-metal-700">Ficha de Cliente</h3>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="md:col-span-2">
              <label className="block text-sm font-medium text-metal-600 mb-1">Nome Completo / Empresa</label>
              <input
                type="text"
                value={currentClient.name || ''}
                onChange={e => setCurrentClient({...currentClient, name: e.target.value})}
                className="w-full bg-white text-gray-900 border border-gray-300 rounded-lg p-2 focus:ring-2 focus:ring-primary-500 outline-none"
              />
            </div>

            <div>
              <label className="block text-sm font-medium text-metal-600 mb-1">Email</label>
              <input
                type="email"
                value={currentClient.email || ''}
                onChange={e => setCurrentClient({...currentClient, email: e.target.value})}
                className="w-full bg-white text-gray-900 border border-gray-300 rounded-lg p-2 focus:ring-2 focus:ring-primary-500 outline-none"
              />
            </div>

            <div>
              <label className="block text-sm font-medium text-metal-600 mb-1">Telefone</label>
              <input
                type="tel"
                value={currentClient.phone || ''}
                onChange={e => setCurrentClient({...currentClient, phone: e.target.value})}
                className="w-full bg-white text-gray-900 border border-gray-300 rounded-lg p-2 focus:ring-2 focus:ring-primary-500 outline-none"
              />
            </div>

            <div>
              <label className="block text-sm font-medium text-metal-600 mb-1">NIF</label>
              <input
                type="text"
                value={currentClient.nif || ''}
                onChange={e => setCurrentClient({...currentClient, nif: e.target.value})}
                className="w-full bg-white text-gray-900 border border-gray-300 rounded-lg p-2 focus:ring-2 focus:ring-primary-500 outline-none"
              />
            </div>

            <div>
                 <label className="block text-sm font-medium text-metal-600 mb-1">Morada</label>
                 <input
                    type="text"
                    value={currentClient.address || ''}
                    onChange={e => setCurrentClient({...currentClient, address: e.target.value})}
                    className="w-full bg-white text-gray-900 border border-gray-300 rounded-lg p-2 focus:ring-2 focus:ring-primary-500 outline-none"
                 />
            </div>

            <div className="flex gap-2">
                <div className="w-1/3">
                    <label className="block text-sm font-medium text-metal-600 mb-1">C. Postal</label>
                    <input
                        type="text"
                        value={currentClient.postalCode || ''}
                        onChange={e => setCurrentClient({...currentClient, postalCode: e.target.value})}
                        className="w-full bg-white text-gray-900 border border-gray-300 rounded-lg p-2 focus:ring-2 focus:ring-primary-500 outline-none"
                    />
                </div>
                <div className="flex-1">
                    <label className="block text-sm font-medium text-metal-600 mb-1">Localidade</label>
                    <input
                        type="text"
                        value={currentClient.city || ''}
                        onChange={e => setCurrentClient({...currentClient, city: e.target.value})}
                        className="w-full bg-white text-gray-900 border border-gray-300 rounded-lg p-2 focus:ring-2 focus:ring-primary-500 outline-none"
                    />
                </div>
            </div>
          </div>

          <div className="flex justify-end gap-3 mt-6">
            <button
              onClick={() => setIsEditing(false)}
              className="px-4 py-2 text-metal-600 hover:bg-metal-100 rounded-lg"
            >
              Cancelar
            </button>
            <button
              onClick={handleSave}
              className="px-6 py-2 bg-primary-600 hover:bg-primary-700 text-white rounded-lg shadow-sm font-medium"
            >
              Guardar Cliente
            </button>
          </div>
        </div>
      )}

      {/* Tabela de Clientes */}
      <div className="bg-white rounded-xl shadow-sm border border-metal-200 overflow-hidden">
        <div className="overflow-x-auto">
            <table className="w-full text-left border-collapse">
            <thead className="bg-metal-50 text-metal-600 text-sm uppercase font-semibold">
                <tr>
                <th className="p-4 border-b border-metal-100">Cliente</th>
                <th className="p-4 border-b border-metal-100">Contactos</th>
                <th className="p-4 border-b border-metal-100">Localização</th>
                <th className="p-4 border-b border-metal-100">Estatísticas</th>
                <th className="p-4 border-b border-metal-100 text-center">Ações</th>
                </tr>
            </thead>
            <tbody className="divide-y divide-metal-100">
                {filteredClients.length === 0 && (
                    <tr>
                        <td colSpan={5} className="p-8 text-center text-metal-400">
                            Nenhum cliente encontrado.
                        </td>
                    </tr>
                )}
                {filteredClients.map((client) => {
                    const stats = getClientStats(client.id);
                    return (
                        <tr key={client.id} className="hover:bg-metal-50 transition-colors">
                            <td className="p-4">
                                <div className="font-bold text-metal-900">{client.name}</div>
                                <div className="text-xs text-metal-500">NIF: {client.nif || 'N/A'}</div>
                            </td>
                            <td className="p-4 text-sm">
                                <div className="flex items-center gap-1 text-metal-700"><PhoneIcon className="w-3 h-3"/> {client.phone || '-'}</div>
                                <div className="flex items-center gap-1 text-metal-500 text-xs"><EnvelopeIcon className="w-3 h-3"/> {client.email || '-'}</div>
                            </td>
                            <td className="p-4 text-sm text-metal-600">
                                <div className="truncate max-w-[200px]">{client.address}</div>
                                <div className="text-xs text-metal-400">{client.postalCode} {client.city}</div>
                            </td>
                            <td className="p-4">
                                <div className="flex items-center gap-2 text-xs">
                                    <span className="bg-green-100 text-green-700 px-1.5 rounded">{stats.acceptedCount} Aceites</span>
                                    <span className="bg-red-50 text-red-600 px-1.5 rounded">{stats.rejectedCount} Rej.</span>
                                </div>
                                <div className="text-xs font-bold text-metal-700 mt-1">Total: {stats.totalInvoiced.toFixed(0)}€</div>
                            </td>
                            <td className="p-4 text-center">
                            <div className="flex justify-center gap-2">
                                <button onClick={() => handleEdit(client)} className="p-1.5 text-blue-600 hover:bg-blue-50 rounded-md">
                                    <PencilIcon className="w-5 h-5" />
                                </button>
                                <button onClick={() => handleDelete(client.id)} className="p-1.5 text-red-600 hover:bg-red-50 rounded-md">
                                    <TrashIcon className="w-5 h-5" />
                                </button>
                            </div>
                            </td>
                        </tr>
                    );
                })}
            </tbody>
            </table>
        </div>
      </div>
    </div>
  );
};

export default ClientManager;

