import React, { useState } from 'react';
import { PlusIcon, TrashIcon, PencilIcon, CubeIcon } from '@heroicons/react/24/outline';
import { RawMaterial, UnitType } from '../types';

interface MaterialManagerProps {
  materials: RawMaterial[];
  setMaterials: (materials: RawMaterial[]) => void;
  materialTypes?: string[];
}

const MaterialManager: React.FC<MaterialManagerProps> = ({ materials, setMaterials, materialTypes = ['Ferro', 'Outro'] }) => {
  const [isEditing, setIsEditing] = useState(false);
  const [currentMaterial, setCurrentMaterial] = useState<Partial<RawMaterial>>({
    name: '',
    type: materialTypes[0] || 'Outro',
    unit: UnitType.UN,
    pricePerUnit: 0
  });

  const handleSave = () => {
    if (!currentMaterial.name) return;

    if (currentMaterial.id) {
      const updated = materials.map(m => m.id === currentMaterial.id ? currentMaterial as RawMaterial : m);
      setMaterials(updated);
    } else {
      const newMaterial: RawMaterial = {
        ...currentMaterial as RawMaterial,
        id: crypto.randomUUID()
      };
      setMaterials([...materials, newMaterial]);
    }
    setIsEditing(false);
    setCurrentMaterial({ name: '', type: materialTypes[0], unit: UnitType.UN, pricePerUnit: 0 });
  };

  const handleDelete = (id: string) => {
    if (confirm('Apagar este material?')) {
      setMaterials(materials.filter(m => m.id !== id));
    }
  };

  const handleEdit = (material: RawMaterial) => {
    setCurrentMaterial(material);
    setIsEditing(true);
  };

  return (
    <div className="max-w-5xl mx-auto">
      <div className="flex justify-between items-center mb-6">
        <h2 className="text-2xl font-bold text-metal-800">Matérias-Primas</h2>
        <button
          onClick={() => {
            setCurrentMaterial({ name: '', type: materialTypes[0], unit: UnitType.UN, pricePerUnit: 0 });
            setIsEditing(true);
          }}
          className="bg-primary-600 hover:bg-primary-700 text-white px-4 py-2 rounded-lg flex items-center shadow-sm"
        >
          <PlusIcon className="w-5 h-5 mr-2" />
          Novo Material
        </button>
      </div>

      {isEditing && (
        <div className="bg-white p-6 rounded-xl shadow-lg border border-metal-200 mb-8">
          <h3 className="text-lg font-semibold mb-4 text-metal-700">Ficha de Material</h3>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="md:col-span-2">
              <label className="block text-sm font-medium text-metal-600 mb-1">Nome do Material</label>
              <input
                type="text"
                value={currentMaterial.name}
                onChange={e => setCurrentMaterial({...currentMaterial, name: e.target.value})}
                className="w-full bg-white text-gray-900 border border-gray-300 rounded-lg p-2 focus:ring-2 focus:ring-primary-500 outline-none"
                placeholder="Ex: Tubo 40x40x2"
              />
            </div>

            <div>
              <label className="block text-sm font-medium text-metal-600 mb-1">Tipo</label>
              <select
                value={currentMaterial.type}
                onChange={e => setCurrentMaterial({...currentMaterial, type: e.target.value})}
                className="w-full bg-white text-gray-900 border border-gray-300 rounded-lg p-2 focus:ring-2 focus:ring-primary-500 outline-none"
              >
                  {materialTypes.map((type) => (
                      <option key={type} value={type}>{type}</option>
                  ))}
              </select>
            </div>

            <div className="flex gap-4">
                <div className="flex-1">
                    <label className="block text-sm font-medium text-metal-600 mb-1">Preço de Custo</label>
                    <input
                        type="number"
                        step="0.01"
                        value={currentMaterial.pricePerUnit === 0 ? '' : currentMaterial.pricePerUnit}
                        onChange={e => setCurrentMaterial({...currentMaterial, pricePerUnit: Number(e.target.value)})}
                        className="w-full bg-white text-gray-900 border border-gray-300 rounded-lg p-2 focus:ring-2 focus:ring-primary-500 outline-none"
                    />
                </div>
                <div className="w-32">
                    <label className="block text-sm font-medium text-metal-600 mb-1">Unidade</label>
                    <select
                        value={currentMaterial.unit}
                        onChange={e => setCurrentMaterial({...currentMaterial, unit: e.target.value as UnitType})}
                        className="w-full bg-white text-gray-900 border border-gray-300 rounded-lg p-2 focus:ring-2 focus:ring-primary-500 outline-none"
                    >
                        {Object.values(UnitType).map(u => (
                            <option key={u} value={u}>{u.toUpperCase()}</option>
                        ))}
                    </select>
                </div>
            </div>
          </div>

          <div className="flex justify-end gap-3 mt-6">
            <button
              onClick={() => setIsEditing(false)}
              className="px-4 py-2 text-metal-600 hover:bg-metal-100 rounded-lg"
            >
              Cancelar
            </button>
            <button
              onClick={handleSave}
              className="px-6 py-2 bg-primary-600 hover:bg-primary-700 text-white rounded-lg shadow-sm font-medium"
            >
              Guardar
            </button>
          </div>
        </div>
      )}

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          {materialTypes.map((typeLabel) => {
              const typeMaterials = materials.filter(m => m.type === typeLabel);
              if (typeMaterials.length === 0) return null;

              return (
                  <div key={typeLabel} className="col-span-1 md:col-span-3">
                      <h3 className="text-md font-bold text-metal-600 uppercase border-b border-metal-200 pb-2 mb-4 mt-4">{typeLabel}</h3>
                      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                          {typeMaterials.map(material => (
                              <div key={material.id} className="bg-white p-4 rounded-xl border border-metal-200 shadow-sm flex justify-between items-center group">
                                  <div>
                                      <div className="font-bold text-metal-900">{material.name}</div>
                                      <div className="text-sm text-metal-500">
                                          {material.pricePerUnit.toFixed(2)}€ / {material.unit}
                                      </div>
                                  </div>
                                  <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                                      <button onClick={() => handleEdit(material)} className="p-1.5 text-blue-600 hover:bg-blue-50 rounded"><PencilIcon className="w-4 h-4" /></button>
                                      <button onClick={() => handleDelete(material.id)} className="p-1.5 text-red-600 hover:bg-red-50 rounded"><TrashIcon className="w-4 h-4" /></button>
                                  </div>
                              </div>
                          ))}
                      </div>
                  </div>
              )
          })}
          {materials.length === 0 && (
              <div className="col-span-full text-center py-12 text-metal-400">
                  <CubeIcon className="w-12 h-12 mx-auto mb-2 opacity-50" />
                  Sem materiais registados.
              </div>
          )}
      </div>
    </div>
  );
};

export default MaterialManager;

import React, { useEffect, useState } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import ClientManager from './components/ClientManager';
import ArticleManager from './components/ArticleManager';
import QuoteManager from './components/QuoteManager';
import MaterialManager from './components/MaterialManager';
import PriceCalculator from './components/PriceCalculator';
import Login from './components/Login';
import SettingsManager from './components/SettingsManager';
import { AppData, Client, Article, Quote, User, CompanySettings, RawMaterial } from './types';
import { loadData, saveData } from './services/storage';

const App: React.FC = () => {
  const [data, setData] = useState<AppData>({
    clients: [],
    articles: [],
    quotes: [],
    nextQuoteNumber: 1,
    users: [],
    companySettings: {
        name: '', address: '', postalCode: '', city: '', nif: '', phone: '', email: '', quoteFooterText: '', materialTypes: []
    },
    rawMaterials: []
  });
  const [activeTab, setActiveTab] = useState('dashboard');
  const [loaded, setLoaded] = useState(false);
  const [currentUser, setCurrentUser] = useState<User | null>(null);

  // Load data on mount
  useEffect(() => {
    const stored = loadData();
    setData(stored);
    setLoaded(true);
  }, []);

  // Save data on change
  useEffect(() => {
    if (loaded) {
      saveData(data);
    }
  }, [data, loaded]);

  const updateClients = (newClients: Client[]) => {
    setData(prev => ({ ...prev, clients: newClients }));
  };

  const updateArticles = (newArticles: Article[]) => {
    setData(prev => ({ ...prev, articles: newArticles }));
  };

  const updateMaterials = (newMaterials: RawMaterial[]) => {
    setData(prev => ({ ...prev, rawMaterials: newMaterials }));
  };

  const updateUsers = (newUsers: User[]) => {
    setData(prev => ({ ...prev, users: newUsers }));
  };

  const updateSettings = (newSettings: CompanySettings) => {
    setData(prev => ({ ...prev, companySettings: newSettings }));
  };

  const handleImportData = (newData: AppData) => {
    setData(newData);
    alert('Base de dados importada com sucesso!');
  };

  const saveQuote = (quote: Quote) => {
    setData(prev => {
      const exists = prev.quotes.find(q => q.id === quote.id);
      let newQuotes;
      let nextNum = prev.nextQuoteNumber;

      if (exists) {
        newQuotes = prev.quotes.map(q => q.id === quote.id ? quote : q);
      } else {
        newQuotes = [...prev.quotes, quote];
        nextNum = prev.nextQuoteNumber + 1;
      }
      return { ...prev, quotes: newQuotes, nextQuoteNumber: nextNum };
    });
  };

  const deleteQuote = (id: string) => {
    if (confirm('Tem a certeza que deseja eliminar este orçamento?')) {
        setData(prev => ({ ...prev, quotes: prev.quotes.filter(q => q.id !== id) }));
    }
  };

  const handleSaveArticleFromCalculator = (article: Article) => {
      updateArticles([...data.articles, article]);
      setActiveTab('articles');
  };

  const handleLogin = (user: User) => {
    setCurrentUser(user);
    setActiveTab('dashboard');
  };

  const handleLogout = () => {
    setCurrentUser(null);
  };

  if (!loaded) return <div className="flex h-screen items-center justify-center text-metal-500">A carregar...</div>;

  if (!currentUser) {
    return <Login users={data.users} onLogin={handleLogin} />;
  }

  return (
    <Layout 
        activeTab={activeTab} 
        onChangeTab={setActiveTab} 
        currentUser={currentUser} 
        onLogout={handleLogout}
        companySettings={data.companySettings}
    >
      {activeTab === 'dashboard' && (
        <Dashboard 
            quotes={data.quotes} 
            clients={data.clients} 
            articles={data.articles} 
        />
      )}
      {activeTab === 'clients' && (
        <ClientManager clients={data.clients} setClients={updateClients} quotes={data.quotes} />
      )}
      {activeTab === 'articles' && (
        <ArticleManager articles={data.articles} setArticles={updateArticles} />
      )}
      {activeTab === 'materials' && (
        <MaterialManager 
            materials={data.rawMaterials} 
            setMaterials={updateMaterials} 
            materialTypes={data.companySettings.materialTypes}
        />
      )}
      {activeTab === 'calculator' && (
        <PriceCalculator materials={data.rawMaterials} onSaveArticle={handleSaveArticleFromCalculator} />
      )}
      {activeTab === 'quotes' && (
        <QuoteManager 
          quotes={data.quotes}
          clients={data.clients}
          articles={data.articles}
          nextQuoteNumber={data.nextQuoteNumber}
          companySettings={data.companySettings}
          onSaveQuote={saveQuote}
          onDeleteQuote={deleteQuote}
        />
      )}
      {activeTab === 'settings' && (
        <SettingsManager 
            settings={data.companySettings}
            users={data.users}
            fullData={data}
            onUpdateSettings={updateSettings}
            onUpdateUsers={updateUsers}
            onImportData={handleImportData}
        />
      )}
    </Layout>
  );
};

export default App;

import React, { useRef, useState, useEffect } from 'react';

interface SchematicDesignerProps {
    onSave: (imageData: string) => void;
    onCancel: () => void;
}

type SchematicType = 'window_1' | 'window_2' | 'door_1' | 'gate_sliding' | 'gate_2_leaf' | 'panel';

const SchematicDesigner: React.FC<SchematicDesignerProps> = ({ onSave, onCancel }) => {
    const canvasRef = useRef<HTMLCanvasElement>(null);
    const [width, setWidth] = useState(1000);
    const [height, setHeight] = useState(1000);
    const [type, setType] = useState<SchematicType>('window_1');
    const [color, setColor] = useState('#000000');

    useEffect(() => {
        draw();
    }, [width, height, type, color]);

    const draw = () => {
        const canvas = canvasRef.current;
        if (!canvas) return;
        const ctx = canvas.getContext('2d');
        if (!ctx) return;

        // Clear
        ctx.fillStyle = '#ffffff';
        ctx.fillRect(0, 0, canvas.width, canvas.height);

        // Scale factors to fit in canvas 400x400
        const padding = 40;
        const maxDrawW = canvas.width - (padding * 2);
        const maxDrawH = canvas.height - (padding * 2);

        const scaleW = maxDrawW / width;
        const scaleH = maxDrawH / height;
        const scale = Math.min(scaleW, scaleH);

        const drawW = width * scale;
        const drawH = height * scale;

        const startX = (canvas.width - drawW) / 2;
        const startY = (canvas.height - drawH) / 2;

        ctx.strokeStyle = color;
        ctx.lineWidth = 3;
        ctx.lineJoin = 'round';

        // Draw Outer Frame
        ctx.strokeRect(startX, startY, drawW, drawH);

        // Dimensions Text
        ctx.fillStyle = '#000';
        ctx.font = '14px Arial';
        ctx.textAlign = 'center';
        ctx.fillText(`${width}mm`, canvas.width / 2, startY - 10);

        ctx.textAlign = 'left';
        ctx.save();
        ctx.translate(startX - 15, canvas.height / 2);
        ctx.rotate(-Math.PI / 2);
        ctx.fillText(`${height}mm`, 0, 0);
        ctx.restore();

        // Specifics
        ctx.beginPath();
        if (type === 'window_1') {
            // Dashed lines for opening
            ctx.setLineDash([5, 5]);
            ctx.moveTo(startX, startY);
            ctx.lineTo(startX + drawW/2, startY + drawH/2);
            ctx.lineTo(startX, startY + drawH);
        } else if (type === 'window_2') {
            // Middle bar
            ctx.moveTo(startX + drawW/2, startY);
            ctx.lineTo(startX + drawW/2, startY + drawH);
            // Dashed
            ctx.setLineDash([5, 5]);
            ctx.moveTo(startX, startY);
            ctx.lineTo(startX + drawW/2, startY + drawH/2);
            ctx.lineTo(startX, startY + drawH);

            ctx.moveTo(startX + drawW, startY);
            ctx.lineTo(startX + drawW/2, startY + drawH/2);
            ctx.lineTo(startX + drawW, startY + drawH);
        } else if (type === 'door_1') {
             // Handle
             ctx.beginPath();
             ctx.arc(startX + drawW - (drawW * 0.1), startY + drawH/2, 5, 0, 2 * Math.PI);
             ctx.fill();
        } else if (type === 'gate_sliding') {
            // Arrow
            ctx.moveTo(startX, startY + drawH/2);
            ctx.lineTo(startX + drawW, startY + drawH/2);
            // Arrow head
            ctx.lineTo(startX + drawW - 20, startY + drawH/2 - 10);
            ctx.moveTo(startX + drawW, startY + drawH/2);
            ctx.lineTo(startX + drawW - 20, startY + drawH/2 + 10);
        } else if (type === 'gate_2_leaf') {
             // Middle bar
            ctx.moveTo(startX + drawW/2, startY);
            ctx.lineTo(startX + drawW/2, startY + drawH);
            // Hinges
            ctx.fillRect(startX - 5, startY + drawH * 0.2, 5, 20);
            ctx.fillRect(startX - 5, startY + drawH * 0.8, 5, 20);
            ctx.fillRect(startX + drawW, startY + drawH * 0.2, 5, 20);
            ctx.fillRect(startX + drawW, startY + drawH * 0.8, 5, 20);
        } else if (type === 'panel') {
            // Diagonal hatching
            ctx.save();
            ctx.clip(new Path2D(`M${startX},${startY} h${drawW} v${drawH} h-${drawW} Z`));
            ctx.lineWidth = 1;
            for (let i = -drawH; i < drawW; i += 20) {
                ctx.moveTo(startX + i, startY);
                ctx.lineTo(startX + i + drawH, startY + drawH);
            }
            ctx.restore();
        }
        ctx.setLineDash([]);
        ctx.stroke();
    };

    const handleSaveClick = () => {
        if (canvasRef.current) {
            onSave(canvasRef.current.toDataURL('image/png'));
        }
    };

    return (
        <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4">
            <div className="bg-white rounded-xl shadow-2xl w-full max-w-lg overflow-hidden flex flex-col">
                <div className="p-4 border-b bg-gray-50 flex justify-between items-center">
                    <h3 className="font-bold text-lg text-gray-800">Desenhar Esquema</h3>
                    <button onClick={onCancel} className="text-gray-500 hover:text-gray-800">✕</button>
                </div>

                <div className="p-4 grid grid-cols-2 gap-4">
                    <div>
                        <label className="text-xs font-bold text-gray-500">Tipo</label>
                        <select 
                            value={type} 
                            onChange={(e) => setType(e.target.value as SchematicType)}
                            className="w-full border rounded p-1 text-sm text-gray-900 bg-white"
                        >
                            <option value="window_1">Janela 1 Folha</option>
                            <option value="window_2">Janela 2 Folhas</option>
                            <option value="door_1">Porta</option>
                            <option value="gate_sliding">Portão Correr</option>
                            <option value="gate_2_leaf">Portão 2 Folhas</option>
                            <option value="panel">Painel Fixo / Chapa</option>
                        </select>
                    </div>
                    <div>
                        <label className="text-xs font-bold text-gray-500">Cor</label>
                        <input type="color" value={color} onChange={e => setColor(e.target.value)} className="w-full h-8" />
                    </div>
                    <div>
                        <label className="text-xs font-bold text-gray-500">Largura (mm)</label>
                        <input type="number" value={width} onChange={e => setWidth(Number(e.target.value))} className="w-full border rounded p-1 text-sm text-gray-900 bg-white" />
                    </div>
                    <div>
                        <label className="text-xs font-bold text-gray-500">Altura (mm)</label>
                        <input type="number" value={height} onChange={e => setHeight(Number(e.target.value))} className="w-full border rounded p-1 text-sm text-gray-900 bg-white" />
                    </div>
                </div>

                <div className="flex justify-center bg-gray-100 p-4 border-y">
                    <canvas ref={canvasRef} width={400} height={300} className="bg-white shadow-sm border" />
                </div>

                <div className="p-4 flex justify-end gap-2">
                    <button onClick={onCancel} className="px-4 py-2 text-gray-600 hover:bg-gray-100 rounded">Cancelar</button>
                    <button onClick={handleSaveClick} className="px-4 py-2 bg-blue-600 text-white rounded hover:bg-blue-700">Usar Desenho</button>
                </div>
            </div>
        </div>
    );
};

export default SchematicDesigner;

import React, { useState, useRef } from 'react';
import { 
  PlusIcon, 
  PrinterIcon, 
  TrashIcon, 
  ArrowLeftIcon, 
  SparklesIcon, 
  CameraIcon,
  MagnifyingGlassIcon,
  XMarkIcon,
  EnvelopeIcon,
  ArrowDownTrayIcon
} from '@heroicons/react/24/outline';
import { Quote, Client, Article, QuoteItem, QuoteStatus, UnitType, CompanySettings, QuoteItemDetail } from '../types';
import { generateQuoteNotes } from '../services/geminiService';
import SchematicDesigner from './SchematicDesigner';

declare const html2pdf: any;

interface QuoteManagerProps {
  quotes: Quote[];
  clients: Client[];
  articles: Article[];
  nextQuoteNumber: number;
  companySettings: CompanySettings;
  onSaveQuote: (quote: Quote) => void;
  onDeleteQuote: (id: string) => void;
}

const QuoteManager: React.FC<QuoteManagerProps> = ({ 
  quotes, clients, articles, nextQuoteNumber, companySettings, onSaveQuote, onDeleteQuote 
}) => {
  const [view, setView] = useState<'list' | 'edit' | 'print'>('list');
  const [currentQuote, setCurrentQuote] = useState<Quote | null>(null);
  const [loadingAi, setLoadingAi] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [activeItemIdForUpload, setActiveItemIdForUpload] = useState<string | null>(null);
  const [showSchematicDesigner, setShowSchematicDesigner] = useState(false);

  // List Filters
  const [filterClient, setFilterClient] = useState('');
  const [filterDateStart, setFilterDateStart] = useState('');
  const [filterDateEnd, setFilterDateEnd] = useState('');

  // Client Search State (Edit Mode)
  const [clientSearchTerm, setClientSearchTerm] = useState('');
  const [showClientResults, setShowClientResults] = useState(false);
  const [showClientListModal, setShowClientListModal] = useState(false);

  // Helper to init a new quote
  const initNewQuote = () => {
    const newQuote: Quote = {
      id: crypto.randomUUID(),
      clientId: '',
      number: nextQuoteNumber,
      date: new Date().toISOString().split('T')[0],
      validUntil: new Date(Date.now() + 15 * 24 * 60 * 60 * 1000).toISOString().split('T')[0],
      items: [],
      subtotal: 0,
      taxRate: 23,
      taxAmount: 0,
      total: 0,
      status: QuoteStatus.DRAFT,
      notes: '',
      internalNotes: '',
      upfrontPercentage: 50 // Default 50%
    };
    setCurrentQuote(newQuote);
    setClientSearchTerm('');
    setView('edit');
  };

  const calculateTotals = (quote: Quote): Quote => {
    const updatedItems = quote.items.map(item => {
        const detailsSum = item.details?.reduce((acc, d) => acc + (d.price || 0), 0) || 0;
        const total = item.quantity * (item.unitPrice + detailsSum);
        return { ...item, total };
    });

    const subtotal = updatedItems.reduce((sum, item) => sum + item.total, 0);
    const taxAmount = subtotal * (quote.taxRate / 100);
    const total = subtotal + taxAmount;
    return { ...quote, items: updatedItems, subtotal, taxAmount, total };
  };

  const handleAddItem = () => {
    if (!currentQuote) return;
    const newItem: QuoteItem = {
      id: crypto.randomUUID(),
      articleId: '',
      name: '',
      quantity: 1,
      unitPrice: 0,
      unit: UnitType.UN,
      total: 0,
      details: []
    };
    setCurrentQuote({ ...currentQuote, items: [...currentQuote.items, newItem] });
  };

  const handleItemChange = (itemId: string, field: keyof QuoteItem, value: any) => {
    if (!currentQuote) return;
    const updatedItems = currentQuote.items.map(item => {
      if (item.id !== itemId) return item;

      const updatedItem = { ...item, [field]: value };

      // Auto-fill from article
      if (field === 'articleId') {
        const article = articles.find(a => a.id === value);
        if (article) {
          updatedItem.name = article.name;
          updatedItem.description = article.description;
          updatedItem.unitPrice = article.price;
          updatedItem.unit = article.unit;
          // If article has image and item doesn't, use article image
          if(article.image && !updatedItem.image) {
              updatedItem.image = article.image;
          }
        }
      }

      return updatedItem;
    });

    setCurrentQuote(calculateTotals({ ...currentQuote, items: updatedItems }));
  };

  const handleDeleteItem = (itemId: string) => {
    if (!currentQuote) return;
    const updatedItems = currentQuote.items.filter(i => i.id !== itemId);
    setCurrentQuote(calculateTotals({ ...currentQuote, items: updatedItems }));
  };

  // --- ITEM DETAILS / OPTIONS LOGIC ---
  const handleAddDetail = (itemId: string) => {
    if (!currentQuote) return;
    const updatedItems = currentQuote.items.map(item => {
        if (item.id === itemId) {
            const newDetail: QuoteItemDetail = { id: crypto.randomUUID(), label: '', value: '', price: 0 };
            return { ...item, details: [...(item.details || []), newDetail] };
        }
        return item;
    });
    setCurrentQuote(calculateTotals({ ...currentQuote, items: updatedItems }));
  };

  const handleUpdateDetail = (itemId: string, detailId: string, field: 'label' | 'value' | 'price', val: any) => {
    if (!currentQuote) return;
    const updatedItems = currentQuote.items.map(item => {
        if (item.id === itemId) {
            const updatedDetails = (item.details || []).map(d => 
                d.id === detailId ? { ...d, [field]: val } : d
            );
            return { ...item, details: updatedDetails };
        }
        return item;
    });
    setCurrentQuote(calculateTotals({ ...currentQuote, items: updatedItems }));
  };

  const handleDeleteDetail = (itemId: string, detailId: string) => {
    if (!currentQuote) return;
    const updatedItems = currentQuote.items.map(item => {
        if (item.id === itemId) {
            return { ...item, details: (item.details || []).filter(d => d.id !== detailId) };
        }
        return item;
    });
    setCurrentQuote(calculateTotals({ ...currentQuote, items: updatedItems }));
  };

  // Image Upload Logic
  const triggerImageUpload = (itemId: string) => {
    setActiveItemIdForUpload(itemId);
    if (fileInputRef.current) {
        fileInputRef.current.click();
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0] && activeItemIdForUpload) {
        const file = e.target.files[0];
        const reader = new FileReader();
        reader.onload = (event) => {
             handleItemChange(activeItemIdForUpload, 'image', event.target?.result as string);
             setActiveItemIdForUpload(null);
        };
        reader.readAsDataURL(file);
    }
    e.target.value = '';
  };

  const handleSaveSchematic = (imgData: string) => {
      if (activeItemIdForUpload) {
          handleItemChange(activeItemIdForUpload, 'image', imgData);
          setShowSchematicDesigner(false);
          setActiveItemIdForUpload(null);
      }
  };

  const handleGenerateNotes = async () => {
    if (!currentQuote || currentQuote.items.length === 0) return;
    setLoadingAi(true);
    const itemNames = currentQuote.items.map(i => i.name);
    const notes = await generateQuoteNotes(itemNames);
    setCurrentQuote(prev => prev ? { ...prev, notes } : null);
    setLoadingAi(false);
  };

  const handleDownloadPdf = () => {
      const element = document.getElementById('print-area');
      const opt = {
          margin: 0,
          filename: `Orcamento_${currentQuote?.number}.pdf`,
          image: { type: 'jpeg', quality: 0.98 },
          html2canvas: { scale: 2, useCORS: true },
          jsPDF: { unit: 'mm', format: 'a4', orientation: 'portrait' },
          pagebreak: { mode: ['avoid-all', 'css', 'legacy'] }
      };
      // @ts-ignore
      html2pdf().set(opt).from(element).save();
  };

  const handleSendGmail = () => {
    if (!currentQuote) return;
    const client = clients.find(c => c.id === currentQuote.clientId);
    if (!client || !client.email) {
        alert("Cliente não tem email definido ou selecionado.");
        return;
    }

    const subject = encodeURIComponent(`Orçamento Nº ${currentQuote.number} - ${companySettings.name}`);
    const body = encodeURIComponent(
`Olá ${client.name},

Segue em anexo o Orçamento Nº ${currentQuote.number}.

Valor Total: ${currentQuote.total.toFixed(2)} €
Validade: ${new Date(currentQuote.validUntil).toLocaleDateString('pt-PT')}

Melhores cumprimentos,
${companySettings.name}`
    );

    alert("O PDF será descarregado. Por favor anexe-o manualmente no email que irá abrir.");
    handleDownloadPdf();
    setTimeout(() => {
        window.open(`https://mail.google.com/mail/?view=cm&fs=1&to=${client.email}&su=${subject}&body=${body}`, '_blank');
    }, 1500);
  };

  // --- CLIENT SEARCH & FILTER LOGIC ---
  const filteredClients = clients.filter(c => 
    c.name.toLowerCase().includes(clientSearchTerm.toLowerCase()) || 
    c.nif.includes(clientSearchTerm)
  );

  const selectClient = (client: Client) => {
    if (currentQuote) {
        setCurrentQuote({ ...currentQuote, clientId: client.id });
        setClientSearchTerm('');
        setShowClientResults(false);
        setShowClientListModal(false);
    }
  };

  const filteredQuotes = quotes.filter(q => {
      const client = clients.find(c => c.id === q.clientId);
      const matchesClient = filterClient === '' || client?.name.toLowerCase().includes(filterClient.toLowerCase());
      const matchesDateStart = filterDateStart === '' || q.date >= filterDateStart;
      const matchesDateEnd = filterDateEnd === '' || q.date <= filterDateEnd;
      return matchesClient && matchesDateStart && matchesDateEnd;
  });

  // --- RENDERERS ---

  if (view === 'list') {
    return (
      <div className="max-w-6xl mx-auto">
        <div className="flex justify-between items-center mb-6">
          <h2 className="text-2xl font-bold text-metal-800">Orçamentos</h2>
          <button onClick={initNewQuote} className="bg-primary-600 hover:bg-primary-700 text-white px-4 py-2 rounded-lg flex items-center shadow-sm">
            <PlusIcon className="w-5 h-5 mr-2" />
            Criar Orçamento
          </button>
        </div>

        {/* Filters */}
        <div className="bg-white p-4 rounded-xl shadow-sm border border-metal-200 mb-6 flex flex-wrap gap-4 items-end">
            <div className="flex-1 min-w-[200px]">
                <label className="text-xs text-metal-500 mb-1 block">Filtrar Cliente</label>
                <div className="relative">
                    <MagnifyingGlassIcon className="absolute left-2 top-2.5 w-4 h-4 text-gray-400" />
                    <input type="text" value={filterClient} onChange={e => setFilterClient(e.target.value)} className="w-full pl-8 p-2 border border-gray-300 rounded-lg text-sm bg-white text-gray-900" placeholder="Nome..." />
                </div>
            </div>
            <div>
                <label className="text-xs text-metal-500 mb-1 block">De</label>
                <input type="date" value={filterDateStart} onChange={e => setFilterDateStart(e.target.value)} className="p-2 border border-gray-300 rounded-lg text-sm bg-white text-gray-900" />
            </div>
            <div>
                <label className="text-xs text-metal-500 mb-1 block">Até</label>
                <input type="date" value={filterDateEnd} onChange={e => setFilterDateEnd(e.target.value)} className="p-2 border border-gray-300 rounded-lg text-sm bg-white text-gray-900" />
            </div>
            <button onClick={() => {setFilterClient(''); setFilterDateStart(''); setFilterDateEnd('')}} className="p-2 text-metal-500 hover:text-metal-800" title="Limpar Filtros">
                <XMarkIcon className="w-5 h-5" />
            </button>
        </div>

        <div className="bg-white rounded-xl shadow-sm border border-metal-200 overflow-hidden">
          <table className="w-full text-left">
            <thead className="bg-metal-50 text-metal-600 text-sm font-semibold">
              <tr>
                <th className="p-4">Nº</th>
                <th className="p-4">Cliente</th>
                <th className="p-4">Data</th>
                <th className="p-4">Total</th>
                <th className="p-4">Estado</th>
                <th className="p-4 text-center">Ações</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-metal-100">
              {filteredQuotes.length === 0 && (
                <tr><td colSpan={6} className="p-8 text-center text-metal-400">Sem orçamentos encontrados.</td></tr>
              )}
              {filteredQuotes.map(quote => {
                const client = clients.find(c => c.id === quote.clientId);
                return (
                  <tr key={quote.id} className="hover:bg-metal-50 cursor-pointer" onClick={() => { setCurrentQuote(quote); setView('edit'); }}>
                    <td className="p-4 font-mono text-metal-600">#{quote.number.toString().padStart(4, '0')}</td>
                    <td className="p-4 font-medium text-metal-900">{client?.name || 'Cliente Removido'}</td>
                    <td className="p-4 text-metal-600">{new Date(quote.date).toLocaleDateString('pt-PT')}</td>
                    <td className="p-4 font-bold text-metal-900">{quote.total.toFixed(2)} €</td>
                    <td className="p-4">
                      <span className={`px-2 py-1 rounded-full text-xs font-medium ${
                        quote.status === QuoteStatus.ACCEPTED ? 'bg-green-100 text-green-700' :
                        quote.status === QuoteStatus.SENT ? 'bg-blue-100 text-blue-700' :
                        'bg-gray-100 text-gray-700'
                      }`}>
                        {quote.status}
                      </span>
                    </td>
                    <td className="p-4 text-center">
                      <button 
                        onClick={(e) => { e.stopPropagation(); onDeleteQuote(quote.id); }}
                        className="p-2 text-red-500 hover:bg-red-50 rounded"
                      >
                        <TrashIcon className="w-4 h-4" />
                      </button>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </div>
    );
  }

  if (view === 'edit' && currentQuote) {
    const selectedClient = clients.find(c => c.id === currentQuote.clientId);

    return (
      <div className="max-w-5xl mx-auto space-y-6 pb-20">
        {/* Hidden Inputs/Modals */}
        <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleFileChange} />
        {showSchematicDesigner && (
            <SchematicDesigner 
                onSave={handleSaveSchematic} 
                onCancel={() => { setShowSchematicDesigner(false); setActiveItemIdForUpload(null); }} 
            />
        )}

        {/* Client Selection Modal */}
        {showClientListModal && (
            <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4">
