import React, { useState } from 'react';
import { RawMaterial, Article, UnitType } from '../types';
import { CalculatorIcon, PlusIcon, XMarkIcon, ArrowDownTrayIcon } from '@heroicons/react/24/outline';

interface PriceCalculatorProps {
    materials: RawMaterial[];
    onSaveArticle: (article: Article) => void;
}

interface CalcItem {
    id: string;
    materialId: string;
    quantity: number;
}

const PriceCalculator: React.FC<PriceCalculatorProps> = ({ materials, onSaveArticle }) => {
    const [items, setItems] = useState<CalcItem[]>([]);
    const [laborHours, setLaborHours] = useState(1);
    const [laborRate, setLaborRate] = useState(15); // Default 15€/hour
    const [profitMargin, setProfitMargin] = useState(30); // 30%
    const [productName, setProductName] = useState('');
    const [productDescription, setProductDescription] = useState('');

    const addItem = () => {
        setItems([...items, { id: crypto.randomUUID(), materialId: '', quantity: 1 }]);
    };

    const updateItem = (id: string, field: keyof CalcItem, value: any) => {
        setItems(items.map(i => i.id === id ? { ...i, [field]: value } : i));
    };

    const removeItem = (id: string) => {
        setItems(items.filter(i => i.id !== id));
    };

    // Calculations
    const materialsCost = items.reduce((sum, item) => {
        const mat = materials.find(m => m.id === item.materialId);
        return sum + (mat ? mat.pricePerUnit * item.quantity : 0);
    }, 0);

    const laborCost = laborHours * laborRate;
    const totalCost = materialsCost + laborCost;
    const profitAmount = totalCost * (profitMargin / 100);
    const finalPrice = totalCost + profitAmount;

    const handleSaveAsArticle = () => {
        if (!productName) {
            alert("Defina um nome para o artigo.");
            return;
        }
        const newArticle: Article = {
            id: crypto.randomUUID(),
            name: productName,
            description: productDescription || `Produzido com materiais: ${items.length} itens.`,
            price: Number(finalPrice.toFixed(2)),
            unit: UnitType.UN
        };
        onSaveArticle(newArticle);
        alert("Artigo criado com sucesso!");
        // Reset
        setProductName('');
        setProductDescription('');
        setItems([]);
    };

    return (
        <div className="max-w-5xl mx-auto space-y-6">
            <h2 className="text-2xl font-bold text-metal-800 flex items-center">
                <CalculatorIcon className="w-8 h-8 mr-2 text-primary-600" />
                Calculadora de Produção
            </h2>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                {/* Left Column: Build Product */}
                <div className="lg:col-span-2 space-y-6">
                    <div className="bg-white p-6 rounded-xl shadow-sm border border-metal-200">
                        <h3 className="font-semibold text-metal-700 mb-4 border-b pb-2">1. Materiais Utilizados</h3>

                        <div className="space-y-4">
                            {items.length === 0 && (
                                <p className="text-metal-400 text-sm italic text-center py-4">Adicione ferros, perfis ou acessórios...</p>
                            )}
                            {items.map(item => {
                                const material = materials.find(m => m.id === item.materialId);
                                const lineTotal = material ? material.pricePerUnit * item.quantity : 0;

                                return (
                                    <div key={item.id} className="flex gap-2 items-start bg-metal-50 p-2 rounded-lg border border-metal-100">
                                        <div className="flex-1">
                                            <label className="text-xs text-metal-500 block mb-1">Material</label>
                                            <select 
                                                className="w-full p-2 border border-metal-300 rounded-lg text-sm bg-white text-gray-900"
                                                value={item.materialId}
                                                onChange={(e) => updateItem(item.id, 'materialId', e.target.value)}
                                            >
                                                <option value="">Selecione...</option>
                                                {materials.map(m => (
                                                    <option key={m.id} value={m.id}>
                                                        {m.name} ({m.pricePerUnit.toFixed(2)}€ / {m.unit})
                                                    </option>
                                                ))}
                                            </select>
