export const generateArticleDescription = async (itemName: string): Promise<string> => {
  const ai = getAiClient();
  if (!ai) return "Descrição não disponível (Chave API em falta).";

  try {
    const prompt = `Escreva uma descrição técnica curta e profissional para um item de serralharia: "${itemName}".
    Foque em materiais, acabamento e durabilidade. Máximo 1 frase. Em Português.`;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });

    return response.text?.trim() || "";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "";
  }
};

export const generateQuoteNotes = async (itemsList: string[]): Promise<string> => {
    const ai = getAiClient();
    if (!ai) return "";

    try {
      const prompt = `Crie uma nota profissional de observações para um orçamento de serralharia que inclui: ${itemsList.join(', ')}.
      Inclua menção genérica a: prazos de entrega (estimado 15 dias), condições de pagamento (50% adjudicação), e exclusão de trabalhos de alvenaria. 
      Seja formal e breve. Em Português.`;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
      });

      return response.text?.trim() || "";
    } catch (error) {
      console.error("Gemini Error:", error);
      return "";
    }
  };

