import React, { useRef, useState, useEffect } from 'react';

interface SchematicDesignerProps {
    onSave: (imageData: string) => void;
    onCancel: () => void;
}

type SchematicType = 'window_1' | 'window_2' | 'door_1' | 'gate_sliding' | 'gate_2_leaf' | 'panel' | 'railing_vertical' | 'garage_sectional' | 'fixed_cross';

const SchematicDesigner: React.FC<SchematicDesignerProps> = ({ onSave, onCancel }) => {
    const canvasRef = useRef<HTMLCanvasElement>(null);
    const [width, setWidth] = useState(1000);
    const [height, setHeight] = useState(1000);
    const [type, setType] = useState<SchematicType>('window_1');
    const [color, setColor] = useState('#000000');

    useEffect(() => {
        draw();
    }, [width, height, type, color]);

    const draw = () => {
        const canvas = canvasRef.current;
        if (!canvas) return;
        const ctx = canvas.getContext('2d');
        if (!ctx) return;

        // Clear
        ctx.fillStyle = '#ffffff';
        ctx.fillRect(0, 0, canvas.width, canvas.height);

        // Scale factors to fit in canvas 400x400
        const padding = 40;
        const maxDrawW = canvas.width - (padding * 2);
        const maxDrawH = canvas.height - (padding * 2);

        const scaleW = maxDrawW / width;
        const scaleH = maxDrawH / height;
        const scale = Math.min(scaleW, scaleH);

        const drawW = width * scale;
        const drawH = height * scale;

        const startX = (canvas.width - drawW) / 2;
        const startY = (canvas.height - drawH) / 2;

        ctx.strokeStyle = color;
        ctx.lineWidth = 3;
        ctx.lineJoin = 'round';

        // Draw Outer Frame
        ctx.strokeRect(startX, startY, drawW, drawH);

        // Dimensions Text
        ctx.fillStyle = '#000';
        ctx.font = '14px Arial';
        ctx.textAlign = 'center';
        ctx.fillText(`${width}mm`, canvas.width / 2, startY - 10);

        ctx.textAlign = 'left';
        ctx.save();
        ctx.translate(startX - 15, canvas.height / 2);
        ctx.rotate(-Math.PI / 2);
        ctx.fillText(`${height}mm`, 0, 0);
        ctx.restore();

        // Specifics
        ctx.beginPath();
        if (type === 'window_1') {
            // Dashed lines for opening
            ctx.setLineDash([5, 5]);
            ctx.moveTo(startX, startY);
            ctx.lineTo(startX + drawW/2, startY + drawH/2);
            ctx.lineTo(startX, startY + drawH);
        } else if (type === 'window_2') {
            // Middle bar
            ctx.moveTo(startX + drawW/2, startY);
            ctx.lineTo(startX + drawW/2, startY + drawH);
            // Dashed
            ctx.setLineDash([5, 5]);
            ctx.moveTo(startX, startY);
            ctx.lineTo(startX + drawW/2, startY + drawH/2);
            ctx.lineTo(startX, startY + drawH);

            ctx.moveTo(startX + drawW, startY);
            ctx.lineTo(startX + drawW/2, startY + drawH/2);
            ctx.lineTo(startX + drawW, startY + drawH);
        } else if (type === 'door_1') {
             // Handle
             ctx.beginPath();
             ctx.arc(startX + drawW - (drawW * 0.1), startY + drawH/2, 5, 0, 2 * Math.PI);
             ctx.fill();
        } else if (type === 'gate_sliding') {
            // Arrow
            ctx.moveTo(startX, startY + drawH/2);
            ctx.lineTo(startX + drawW, startY + drawH/2);
            // Arrow head
            ctx.lineTo(startX + drawW - 20, startY + drawH/2 - 10);
            ctx.moveTo(startX + drawW, startY + drawH/2);
            ctx.lineTo(startX + drawW - 20, startY + drawH/2 + 10);
        } else if (type === 'gate_2_leaf') {
             // Middle bar
            ctx.moveTo(startX + drawW/2, startY);
            ctx.lineTo(startX + drawW/2, startY + drawH);
            // Hinges
            ctx.fillRect(startX - 5, startY + drawH * 0.2, 5, 20);
            ctx.fillRect(startX - 5, startY + drawH * 0.8, 5, 20);
            ctx.fillRect(startX + drawW, startY + drawH * 0.2, 5, 20);
            ctx.fillRect(startX + drawW, startY + drawH * 0.8, 5, 20);
        } else if (type === 'panel') {
            // Diagonal hatching
            ctx.save();
            ctx.clip(new Path2D(`M${startX},${startY} h${drawW} v${drawH} h-${drawW} Z`));
            ctx.lineWidth = 1;
            for (let i = -drawH; i < drawW; i += 20) {
                ctx.moveTo(startX + i, startY);
                ctx.lineTo(startX + i + drawH, startY + drawH);
            }
            ctx.restore();
        } else if (type === 'railing_vertical') {
            // Grade Vertical
            const bars = 10;
            const gap = drawW / (bars + 1);
            for(let i = 1; i <= bars; i++) {
                ctx.moveTo(startX + gap * i, startY);
                ctx.lineTo(startX + gap * i, startY + drawH);
            }
        } else if (type === 'garage_sectional') {
            // Portão Seccionado (Linhas horizontais)
            const panels = 5;
            const hGap = drawH / panels;
            for(let i = 1; i < panels; i++) {
                ctx.moveTo(startX, startY + hGap * i);
                ctx.lineTo(startX + drawW, startY + hGap * i);
            }
        } else if (type === 'fixed_cross') {
             // Cruz a meio
             ctx.moveTo(startX + drawW/2, startY);
             ctx.lineTo(startX + drawW/2, startY + drawH);
             ctx.moveTo(startX, startY + drawH/2);
             ctx.lineTo(startX + drawW, startY + drawH/2);
        }
        ctx.setLineDash([]);
        ctx.stroke();
    };

    const handleSaveClick = () => {
        if (canvasRef.current) {
            onSave(canvasRef.current.toDataURL('image/png'));
        }
    };

    return (
        <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4">
            <div className="bg-white rounded-xl shadow-2xl w-full max-w-lg overflow-hidden flex flex-col max-h-[90vh] overflow-y-auto">
                <div className="p-4 border-b bg-gray-50 flex justify-between items-center">
                    <h3 className="font-bold text-lg text-gray-800">Desenhar Esquema</h3>
                    <button onClick={onCancel} className="text-gray-500 hover:text-gray-800">✕</button>
                </div>

                <div className="p-4 grid grid-cols-2 gap-4">
                    <div className="col-span-2">
                        <label className="text-xs font-bold text-gray-500">Modelo</label>
                        <select 
                            value={type} 
                            onChange={(e) => setType(e.target.value as SchematicType)}
                            className="w-full border rounded p-2 text-sm text-gray-900 bg-white"
                        >
                            <option value="window_1">Janela 1 Folha</option>
                            <option value="window_2">Janela 2 Folhas</option>
                            <option value="fixed_cross">Caixilho Fixo Cruz</option>
                            <option value="door_1">Porta</option>
                            <option value="gate_sliding">Portão Correr</option>
                            <option value="gate_2_leaf">Portão 2 Folhas</option>
                            <option value="garage_sectional">Portão Seccionado</option>
                            <option value="railing_vertical">Grade Vertical</option>
                            <option value="panel">Painel Fixo / Chapa</option>
                        </select>
                    </div>
                    <div>
                        <label className="text-xs font-bold text-gray-500">Largura (mm)</label>
                        <input type="number" value={width} onChange={e => setWidth(Number(e.target.value))} className="w-full border rounded p-1 text-sm text-gray-900 bg-white" />
                    </div>
                    <div>
                        <label className="text-xs font-bold text-gray-500">Altura (mm)</label>
                        <input type="number" value={height} onChange={e => setHeight(Number(e.target.value))} className="w-full border rounded p-1 text-sm text-gray-900 bg-white" />
                    </div>
                    <div className="col-span-2 flex items-center gap-2">
                         <label className="text-xs font-bold text-gray-500">Cor Linha</label>
                         <input type="color" value={color} onChange={e => setColor(e.target.value)} className="w-full h-8 cursor-pointer" />
                    </div>
                </div>

                <div className="flex justify-center bg-gray-100 p-4 border-y">
                    <canvas ref={canvasRef} width={400} height={300} className="bg-white shadow-sm border" />
                </div>

                <div className="p-4 flex justify-end gap-2">
                    <button onClick={onCancel} className="px-4 py-2 text-gray-600 hover:bg-gray-100 rounded">Cancelar</button>
                    <button onClick={handleSaveClick} className="px-4 py-2 bg-blue-600 text-white rounded hover:bg-blue-700">Usar Desenho</button>
                </div>
            </div>
        </div>
    );
};

