                    )}

                    {/* Notes */}
                    {currentQuote.notes && (
                        <div className="bg-metal-50 p-4 rounded-lg border border-metal-100 mb-8 break-inside-avoid">
                            <h4 className="text-xs font-bold uppercase text-metal-500 mb-2">Notas Específicas</h4>
