                    </div>
                    <div className="overflow-y-auto flex-1 p-2">
                        {filteredClients.map(client => (
                            <div key={client.id} onClick={() => selectClient(client)} className="p-3 hover:bg-gray-50 cursor-pointer border-b border-gray-100 flex justify-between">
                                <div>
                                    <div className="font-medium text-gray-900">{client.name}</div>
                                    <div className="text-xs text-gray-500">{client.nif}</div>
                                </div>
                                <button className="px-3 py-1 bg-primary-100 text-primary-700 rounded text-xs">Selecionar</button>
                            </div>
                        ))}
                    </div>
                </div>
            </div>
        )}

        <div className="flex items-center justify-between">
            <button onClick={() => setView('list')} className="flex items-center text-metal-500 hover:text-metal-800">
                <ArrowLeftIcon className="w-4 h-4 mr-1" /> Voltar
            </button>
            <div className="flex gap-2">
                 <button onClick={handleSendGmail} className="flex items-center px-3 py-2 border border-red-200 text-red-600 rounded-lg hover:bg-red-50 text-sm font-medium">
                    <EnvelopeIcon className="w-4 h-4 mr-1" /> Email
                </button>
                 <button onClick={() => { setView('print'); }} className="flex items-center px-4 py-2 border border-metal-300 rounded-lg bg-white hover:bg-metal-50 text-metal-700">
                    <PrinterIcon className="w-4 h-4 mr-2" /> Pré-visualizar
                </button>
                <button onClick={() => { onSaveQuote(currentQuote); setView('list'); }} className="bg-primary-600 hover:bg-primary-700 text-white px-6 py-2 rounded-lg font-medium shadow-sm">
                    Guardar
                </button>
            </div>
        </div>

        {/* Header Info */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-metal-200 grid grid-cols-1 md:grid-cols-3 gap-6">
           {/* Client Search Section */}
           <div>
             <label className="block text-sm font-medium text-metal-600 mb-1">Cliente</label>
             {selectedClient ? (
                 <div className="flex items-center justify-between p-2 border border-blue-200 bg-blue-50 rounded-lg">
                     <div>
                         <div className="font-bold text-blue-900">{selectedClient.name}</div>
                         <div className="text-xs text-blue-700">NIF: {selectedClient.nif || 'N/A'}</div>
                     </div>
                     <button onClick={() => setCurrentQuote({...currentQuote, clientId: ''})} className="text-blue-500 hover:text-blue-700 p-1"><XMarkIcon className="w-5 h-5" /></button>
                 </div>
             ) : (
                 <div className="flex gap-2">
                    <button onClick={() => setShowClientListModal(true)} className="flex-1 text-left px-3 py-2 border border-metal-300 rounded-lg bg-white text-gray-500 text-sm hover:bg-gray-50">Selecionar Cliente...</button>
                 </div>
             )}
           </div>

           <div>
             <label className="block text-sm font-medium text-metal-600 mb-1">Validade (Data)</label>
             <input type="date" value={currentQuote.validUntil} onChange={(e) => setCurrentQuote({...currentQuote, validUntil: e.target.value})} className="w-full border border-metal-300 rounded-lg p-2 bg-white text-gray-900" />
           </div>

           <div>
             <label className="block text-sm font-medium text-metal-600 mb-1">Condição de Pagamento</label>
             <div className="flex items-center gap-2 mb-2">
                <input 
                    type="checkbox" 
                    checked={currentQuote.enableUpfrontPayment ?? true}
                    onChange={(e) => setCurrentQuote({...currentQuote, enableUpfrontPayment: e.target.checked})}
                    className="w-4 h-4 text-primary-600"
                />
                <span className="text-sm">Ativar Adjudicação (%)</span>
             </div>
             {(currentQuote.enableUpfrontPayment ?? true) && (
                 <div className="flex items-center">
                     <input 
                        type="number" min="0" max="100" 
                        value={currentQuote.upfrontPercentage ?? 50} 
                        onChange={(e) => setCurrentQuote({...currentQuote, upfrontPercentage: Number(e.target.value)})} 
                        className="w-20 border border-metal-300 rounded-lg p-2 bg-white text-gray-900 text-right mr-2" 
                     />
                     <span className="text-sm text-metal-600">%</span>
                 </div>
             )}
           </div>
        </div>

        {/* Items */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-metal-200">
            <h3 className="text-lg font-bold text-metal-800 mb-4">Itens do Orçamento</h3>
            <div className="space-y-4">
                {currentQuote.items.map((item, index) => (
                    <div key={item.id} className="p-4 bg-metal-50 rounded-lg border border-metal-100 animate-fade-in">
                        <div className="flex flex-col md:flex-row gap-4 items-start">
                            {/* Image Uploader */}
                            <div className="flex-shrink-0 flex flex-col gap-2">
                                <div 
                                    className="w-24 h-24 rounded-lg border-2 border-dashed border-metal-300 bg-white flex flex-col items-center justify-center overflow-hidden relative"
                                >
                                    {item.image ? (
                                        <img src={item.image} alt="Preview" className="w-full h-full object-contain" />
                                    ) : (
                                        <CameraIcon className="w-6 h-6 text-metal-300" />
                                    )}
                                </div>
                                <div className="flex gap-1">
                                    <button onClick={() => triggerImageUpload(item.id)} className="text-[10px] bg-white border p-1 rounded hover:bg-gray-50 flex-1">Foto</button>
                                    <button onClick={() => { setActiveItemIdForUpload(item.id); setShowSchematicDesigner(true); }} className="text-[10px] bg-white border p-1 rounded hover:bg-gray-50 flex-1">Desenho</button>
                                </div>
                            </div>

                            {/* Main Inputs */}
                            <div className="flex-1 space-y-2 w-full">
                                <div className="flex gap-2">
                                    <select 
                                        value={item.articleId}
                                        onChange={(e) => handleItemChange(item.id, 'articleId', e.target.value)}
                                        className="w-1/3 border border-metal-300 rounded-lg p-2 text-sm bg-white text-gray-900"
                                    >
                                        <option value="">Personalizado</option>
                                        {articles.map(a => <option key={a.id} value={a.id}>{a.name}</option>)}
                                    </select>
                                    <input 
                                        type="text" 
                                        placeholder="Nome do Item"
                                        value={item.name}
                                        onChange={(e) => handleItemChange(item.id, 'name', e.target.value)}
                                        className="flex-1 border border-metal-300 rounded-lg p-2 text-sm font-medium bg-white text-gray-900"
                                    />
                                </div>
                                <textarea 
                                    placeholder="Descrição detalhada..."
                                    value={item.description || ''}
                                    onChange={(e) => handleItemChange(item.id, 'description', e.target.value)}
                                    className="w-full border border-metal-300 rounded-lg p-2 text-sm h-16 resize-none bg-white text-gray-900"
                                />
                            </div>

                            {/* Qty & Price */}
                            <div className="flex gap-2 w-full md:w-auto items-start">
                                <div className="w-20">
                                    <label className="text-xs text-metal-500">Qtd</label>
                                    <input 
                                        type="number"
                                        min="1"
                                        value={item.quantity === 0 ? '' : item.quantity}
                                        onChange={(e) => handleItemChange(item.id, 'quantity', Number(e.target.value))}
                                        className="w-full border border-metal-300 rounded-lg p-2 text-sm bg-white text-gray-900"
                                    />
                                </div>
                                <div className="w-24">
                                    <label className="text-xs text-metal-500">Preço Unit.</label>
                                    <input 
                                        type="number"
                                        min="0"
                                        step="0.01"
                                        value={item.unitPrice === 0 ? '' : item.unitPrice}
                                        onChange={(e) => handleItemChange(item.id, 'unitPrice', Number(e.target.value))}
                                        className="w-full border border-metal-300 rounded-lg p-2 text-sm bg-white text-gray-900"
                                    />
                                </div>
                                <div className="w-24">
                                    <label className="text-xs text-metal-500">Total</label>
                                    <div className="p-2 bg-metal-100 rounded-lg text-sm font-bold text-right text-gray-900">
                                        {item.total.toFixed(2)}€
                                    </div>
                                </div>
                                <button 
                                    onClick={() => handleDeleteItem(item.id)}
                                    className="mt-5 text-red-500 hover:bg-red-50 p-2 rounded"
                                >
                                    <TrashIcon className="w-5 h-5" />
                                </button>
                            </div>
                        </div>

                        {/* PRODUCT OPTIONS / DETAILS */}
                        <div className="mt-4 pl-0 md:pl-28">
