           <div>
             <label className="block text-sm font-medium text-metal-600 mb-1">Validade (Data)</label>
             <input type="date" value={currentQuote.validUntil} onChange={(e) => setCurrentQuote({...currentQuote, validUntil: e.target.value})} className="w-full border border-metal-300 rounded-lg p-2 bg-white text-gray-900" />
           </div>

           <div>
             <label className="block text-sm font-medium text-metal-600 mb-1">Condição de Pagamento</label>
             <div className="flex items-center gap-2 mb-2">
                <input 
                    type="checkbox" 
                    checked={currentQuote.enableUpfrontPayment ?? true}
                    onChange={(e) => setCurrentQuote({...currentQuote, enableUpfrontPayment: e.target.checked})}
