import React, { useState, useMemo } from 'react';
import { Quote, Client, Article, QuoteStatus } from '../types';
import { CurrencyEuroIcon, UserGroupIcon, DocumentTextIcon, CalendarIcon } from '@heroicons/react/24/outline';
import { 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer, 
  PieChart, 
  Pie, 
  Cell, 
  Legend 
} from 'recharts';

interface DashboardProps {
    quotes: Quote[];
    clients: Client[];
    articles: Article[];
}

const COLORS = ['#94a3b8', '#3b82f6', '#22c55e', '#ef4444', '#1f2937']; // Draft, Sent, Accepted, Rejected, Closed

const Dashboard: React.FC<DashboardProps> = ({ quotes, clients, articles }) => {
    // Current Month Range Default
    const date = new Date();
    const firstDay = new Date(date.getFullYear(), date.getMonth(), 1).toISOString().split('T')[0];
    const lastDay = new Date(date.getFullYear(), date.getMonth() + 1, 0).toISOString().split('T')[0];

    const [startDate, setStartDate] = useState(firstDay);
    const [endDate, setEndDate] = useState(lastDay);

    // Calculate metrics based on range
    const filteredQuotes = quotes.filter(q => q.date >= startDate && q.date <= endDate);

    // Revenue Stats
    const acceptedQuotesInRange = filteredQuotes.filter(q => q.status === QuoteStatus.ACCEPTED || q.status === QuoteStatus.CLOSED);
    const revenueInRange = acceptedQuotesInRange.reduce((acc, q) => acc + q.total, 0);
    const totalQuotedInRange = filteredQuotes.reduce((acc, q) => acc + q.total, 0);
    const activeQuotes = quotes.filter(q => q.status === 'Enviado' || q.status === 'Rascunho').length;

    // --- CHART DATA PREPARATION ---

    // 1. Monthly Revenue (Last 6 Months) - Independent of date filter to show trend
    const monthlyRevenueData = useMemo(() => {
        const data = [];
        const today = new Date();

        for (let i = 5; i >= 0; i--) {
            const d = new Date(today.getFullYear(), today.getMonth() - i, 1);
            const monthName = d.toLocaleString('pt-PT', { month: 'short' });
            const year = d.getFullYear();
            const monthKey = `${year}-${String(d.getMonth() + 1).padStart(2, '0')}`;

            // Sum totals for this month (Accepted or Closed)
            const total = quotes
                .filter(q => {
                    const qDate = q.date.substring(0, 7); // YYYY-MM
                    return qDate === monthKey && (q.status === QuoteStatus.ACCEPTED || q.status === QuoteStatus.CLOSED);
                })
                .reduce((sum, q) => sum + q.total, 0);

            data.push({ name: monthName, total: total });
        }
        return data;
    }, [quotes]);

    // 2. Status Distribution (Based on filtered range)
    const statusData = useMemo(() => {
        const counts = {
            [QuoteStatus.DRAFT]: 0,
            [QuoteStatus.SENT]: 0,
            [QuoteStatus.ACCEPTED]: 0,
            [QuoteStatus.REJECTED]: 0,
            [QuoteStatus.CLOSED]: 0,
        };

        filteredQuotes.forEach(q => {
            if (counts[q.status] !== undefined) {
                counts[q.status]++;
            }
        });

        return [
            { name: 'Rascunho', value: counts[QuoteStatus.DRAFT], color: COLORS[0] },
            { name: 'Enviado', value: counts[QuoteStatus.SENT], color: COLORS[1] },
            { name: 'Aprovado', value: counts[QuoteStatus.ACCEPTED], color: COLORS[2] },
            { name: 'Rejeitado', value: counts[QuoteStatus.REJECTED], color: COLORS[3] },
            { name: 'Concluído', value: counts[QuoteStatus.CLOSED], color: COLORS[4] },
        ].filter(item => item.value > 0);
    }, [filteredQuotes]);

    return (
        <div className="max-w-7xl mx-auto pb-10">
            {/* Top Bar */}
            <div className="flex flex-col md:flex-row justify-between items-center mb-8 gap-4">
                <h2 className="text-2xl font-bold text-metal-800">Painel Geral</h2>

                <div className="flex gap-2 items-center bg-white p-2 rounded-lg shadow-sm border border-metal-200">
                    <CalendarIcon className="w-5 h-5 text-gray-400" />
                    <input type="date" value={startDate} onChange={e => setStartDate(e.target.value)} className="text-sm border-none outline-none text-gray-600 bg-transparent" />
                    <span className="text-gray-400">-</span>
                    <input type="date" value={endDate} onChange={e => setEndDate(e.target.value)} className="text-sm border-none outline-none text-gray-600 bg-transparent" />
                </div>
            </div>

            {/* KPI Cards */}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
                <div className="bg-white p-6 rounded-xl shadow-sm border border-metal-200 relative overflow-hidden group hover:shadow-md transition-shadow">
                    <div className="absolute top-0 left-0 w-1 h-full bg-green-500"></div>
                    <div className="flex justify-between items-start">
                        <div>
                            <p className="text-sm text-metal-500 font-medium">Faturado</p>
                            <p className="text-2xl font-bold text-metal-900 mt-1">{revenueInRange.toFixed(0)} €</p>
                            <p className="text-xs text-metal-400 mt-1">{acceptedQuotesInRange.length} obras ganhas</p>
                        </div>
                        <div className="p-3 bg-green-50 text-green-600 rounded-full group-hover:bg-green-100 transition-colors">
                            <CurrencyEuroIcon className="w-6 h-6" />
                        </div>
                    </div>
                </div>

                <div className="bg-white p-6 rounded-xl shadow-sm border border-metal-200 group hover:shadow-md transition-shadow">
                    <div className="flex justify-between items-start">
                        <div>
                            <p className="text-sm text-metal-500 font-medium">Total Orçamentado</p>
                            <p className="text-2xl font-bold text-metal-900 mt-1">{totalQuotedInRange.toFixed(0)} €</p>
                            <p className="text-xs text-metal-400 mt-1">Neste período</p>
                        </div>
                        <div className="p-3 bg-metal-50 text-metal-600 rounded-full group-hover:bg-metal-100 transition-colors">
                            <DocumentTextIcon className="w-6 h-6" />
                        </div>
                    </div>
                </div>

                <div className="bg-white p-6 rounded-xl shadow-sm border border-metal-200 group hover:shadow-md transition-shadow">
                    <div className="flex items-center justify-between">
                        <div>
                            <p className="text-sm text-metal-500 font-medium">Clientes Totais</p>
                            <p className="text-2xl font-bold text-metal-900 mt-1">{clients.length}</p>
                            <p className="text-xs text-metal-400 mt-1">Base de dados</p>
                        </div>
                        <div className="p-3 bg-purple-50 text-purple-600 rounded-full group-hover:bg-purple-100 transition-colors">
                            <UserGroupIcon className="w-6 h-6" />
                        </div>
                    </div>
                </div>

                <div className="bg-white p-6 rounded-xl shadow-sm border border-metal-200 group hover:shadow-md transition-shadow">
                    <div className="flex items-center justify-between">
                        <div>
                            <p className="text-sm text-metal-500 font-medium">Orçamentos Ativos</p>
                            <p className="text-2xl font-bold text-metal-900 mt-1">{activeQuotes}</p>
                            <p className="text-xs text-metal-400 mt-1">Pendentes de resposta</p>
                        </div>
                        <div className="p-3 bg-blue-50 text-blue-600 rounded-full group-hover:bg-blue-100 transition-colors">
                            <DocumentTextIcon className="w-6 h-6" />
                        </div>
                    </div>
                </div>
            </div>

            {/* Charts Section */}
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 mb-8">
                {/* Bar Chart: Revenue Trend */}
                <div className="bg-white p-6 rounded-xl shadow-sm border border-metal-200">
                    <h3 className="text-lg font-bold text-metal-800 mb-6">Evolução da Faturação (6 Meses)</h3>
                    <div className="h-64 w-full">
                        <ResponsiveContainer width="100%" height="100%">
                            <BarChart data={monthlyRevenueData}>
                                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#e2e8f0" />
                                <XAxis 
                                    dataKey="name" 
                                    tick={{fontSize: 12, fill: '#64748b'}} 
                                    axisLine={false} 
                                    tickLine={false} 
                                />
                                <YAxis 
                                    tick={{fontSize: 12, fill: '#64748b'}} 
                                    axisLine={false} 
                                    tickLine={false} 
                                    tickFormatter={(value) => `${value/1000}k`} 
                                />
                                <Tooltip 
                                    cursor={{fill: '#f1f5f9'}}
                                    contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                                    formatter={(value: number) => [`${value.toFixed(2)} €`, 'Total']}
                                />
                                <Bar 
                                    dataKey="total" 
                                    fill="#3b82f6" 
                                    radius={[4, 4, 0, 0]} 
                                    barSize={40}
                                />
                            </BarChart>
                        </ResponsiveContainer>
                    </div>
                </div>

                {/* Pie Chart: Status Distribution */}
                <div className="bg-white p-6 rounded-xl shadow-sm border border-metal-200">
                    <h3 className="text-lg font-bold text-metal-800 mb-6">Estado dos Orçamentos (Período)</h3>
                    <div className="h-64 w-full flex items-center justify-center">
                        {statusData.length > 0 ? (
                            <ResponsiveContainer width="100%" height="100%">
                                <PieChart>
                                    <Pie
                                        data={statusData}
                                        cx="50%"
                                        cy="50%"
                                        innerRadius={60}
                                        outerRadius={80}
                                        paddingAngle={5}
                                        dataKey="value"
                                    >
                                        {statusData.map((entry, index) => (
                                            <Cell key={`cell-${index}`} fill={entry.color} />
                                        ))}
                                    </Pie>
                                    <Tooltip 
                                        contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                                    />
                                    <Legend 
                                        verticalAlign="bottom" 
                                        height={36} 
                                        iconType="circle"
                                        formatter={(value, entry: any) => <span className="text-sm text-metal-600 ml-1">{value}</span>}
                                    />
                                </PieChart>
                            </ResponsiveContainer>
                        ) : (
                            <div className="text-metal-400 text-sm">Sem dados para mostrar neste período.</div>
                        )}
                    </div>
                </div>
            </div>

            {/* Recent Quotes List */}
            <div className="bg-white rounded-xl shadow-sm border border-metal-200 p-6">
                <div className="flex justify-between items-center mb-4">
                    <h3 className="font-bold text-metal-800">Últimos Orçamentos</h3>
                    <span className="text-xs text-metal-400">Mostrando os 5 mais recentes</span>
                </div>
                {quotes.length === 0 ? (
                    <p className="text-metal-500 text-sm py-4 text-center bg-metal-50 rounded-lg">Sem atividade recente.</p>
                ) : (
                    <div className="space-y-0">
                        {quotes.slice(-5).reverse().map((q, i) => {
                            const client = clients.find(c => c.id === q.clientId);
                            return (
                                <div key={q.id} className="flex justify-between items-center py-3 border-b border-metal-50 last:border-0 hover:bg-metal-50 px-2 rounded transition-colors">
                                    <div className="flex items-center gap-3">
                                        <div className="w-10 h-10 rounded-full bg-metal-100 flex items-center justify-center text-metal-500 font-mono text-xs">
                                            #{q.number}
                                        </div>
                                        <div>
                                            <p className="font-medium text-metal-900 text-sm">{client?.name || 'Cliente Desconhecido'}</p>
                                            <p className="text-xs text-metal-500">{new Date(q.date).toLocaleDateString()}</p>
                                        </div>
                                    </div>
                                    <div className="text-right">
                                        <p className="font-bold text-metal-900 text-sm">{q.total.toFixed(2)} €</p>
                                        <span className={`inline-flex items-center px-2 py-0.5 rounded text-xs font-medium mt-1 ${
                                            q.status === QuoteStatus.ACCEPTED ? 'bg-green-100 text-green-800' :
                                            q.status === QuoteStatus.CLOSED ? 'bg-gray-800 text-white' :
                                            q.status === QuoteStatus.REJECTED ? 'bg-red-100 text-red-800' :
                                            q.status === QuoteStatus.SENT ? 'bg-blue-100 text-blue-800' :
                                            'bg-gray-100 text-gray-800'
                                        }`}>
                                            {q.status}
                                        </span>
                                    </div>
                                </div>
                            );
                        })}
                    </div>
                )}
            </div>
        </div>
    );
}

export default Dashboard;

