  const [localUsers, setLocalUsers] = useState<User[]>(users);
  const [newUser, setNewUser] = useState({ username: '', password: '', name: '' });
  const [newMaterialType, setNewMaterialType] = useState('');
  const [syncing, setSyncing] = useState(false);
  const [showSqlHelp, setShowSqlHelp] = useState(false);
  const [showApiKey, setShowApiKey] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const importInputRef = useRef<HTMLInputElement>(null);

  const handleSaveSettings = () => {
    onUpdateSettings(localSettings);
    alert('Configurações guardadas com sucesso!');
  };

  const handleLogoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      const reader = new FileReader();
      reader.onload = (event) => {
        setLocalSettings({ ...localSettings, logo: event.target?.result as string });
      };
      reader.readAsDataURL(file);
    }
  };

  const handleAddUser = () => {
    if (!newUser.username || !newUser.password || !newUser.name) {
        alert("Preencha todos os campos do utilizador.");
        return;
    }
    const user: User = {
      id: crypto.randomUUID(),
      role: 'user',
      ...newUser
    };
    const updatedUsers = [...localUsers, user];
    setLocalUsers(updatedUsers);
    onUpdateUsers(updatedUsers);
    setNewUser({ username: '', password: '', name: '' });
  };

  const handleDeleteUser = (id: string) => {
    if (localUsers.length <= 1) {
      alert("Não pode apagar o último utilizador.");
      return;
    }
    if (confirm("Apagar utilizador?")) {
        const updatedUsers = localUsers.filter(u => u.id !== id);
        setLocalUsers(updatedUsers);
        onUpdateUsers(updatedUsers);
    }
  };

  // Material Types
  const handleAddMaterialType = () => {
      if(newMaterialType && !localSettings.materialTypes.includes(newMaterialType)){
          setLocalSettings({
              ...localSettings, 
              materialTypes: [...localSettings.materialTypes, newMaterialType]
          });
          setNewMaterialType('');
      }
  };

  const handleRemoveMaterialType = (type: string) => {
      if(confirm('Remover este tipo de material?')){
          setLocalSettings({
              ...localSettings,
              materialTypes: localSettings.materialTypes.filter(t => t !== type)
          });
      }
  };

  const handleExportData = () => {
    const dataStr = JSON.stringify(fullData, null, 2);
    const dataUri = 'data:application/json;charset=utf-8,'+ encodeURIComponent(dataStr);

    const exportFileDefaultName = `backup_serralharia_${new Date().toISOString().slice(0,10)}.json`;

    const linkElement = document.createElement('a');
    linkElement.setAttribute('href', dataUri);
    linkElement.setAttribute('download', exportFileDefaultName);
    linkElement.click();
  };

  const handleImportClick = () => {
    importInputRef.current?.click();
  };

  const handleImportFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
        const file = e.target.files[0];
        const reader = new FileReader();
        reader.onload = (event) => {
            try {
                const json = JSON.parse(event.target?.result as string);
                if (json.clients && json.quotes && json.companySettings) {
                    if (confirm('ATENÇÃO: Importar uma base de dados irá substituir TODOS os dados atuais. Deseja continuar?')) {
                        onImportData(json as AppData);
                        setLocalSettings(json.companySettings);
                        setLocalUsers(json.users);
                    }
                } else {
                    alert('Ficheiro inválido.');
                }
            } catch (err) {
                alert('Erro ao ler ficheiro.');
                console.error(err);
            }
        };
        reader.readAsText(file);
    }
    e.target.value = ''; // Reset
  };

  // --- CLOUD SYNC ---
  const handleCloudUpload = async () => {
    if (!localSettings.supabaseUrl || !localSettings.supabaseKey) {
        alert("Por favor configure o URL e Chave do Supabase primeiro.");
        return;
    }
    setSyncing(true);
    // Ensure settings are up to date before sync
    const dataToSync = { ...fullData, companySettings: localSettings };
    const result = await uploadDataToCloud(dataToSync, localSettings.supabaseUrl, localSettings.supabaseKey);
    alert(result.message);
    setSyncing(false);
  };

  const handleCloudDownload = async () => {
    if (!localSettings.supabaseUrl || !localSettings.supabaseKey) {
        alert("Por favor configure o URL e Chave do Supabase primeiro.");
        return;
    }
    if (!confirm("ATENÇÃO: Isto irá substituir os dados atuais pelos dados da nuvem. Continuar?")) return;

    setSyncing(true);
    const result = await downloadDataFromCloud(localSettings.supabaseUrl, localSettings.supabaseKey);
    if (result.success && result.data) {
        onImportData(result.data);
        setLocalSettings(result.data.companySettings);
        setLocalUsers(result.data.users);
        alert(result.message);
    } else {
        alert(result.message);
    }
    setSyncing(false);
  };

  const sqlCommand = `create table if not exists app_data (
  id int primary key,
  updated_at timestamptz default now(),
  data jsonb
);

insert into app_data (id, data) 
values (1, '{}') 
on conflict (id) do nothing;

alter table app_data enable row level security;
create policy "Public Access" on app_data for all using (true);`;

  return (
    <div className="max-w-5xl mx-auto space-y-8 pb-10">
      <h2 className="text-2xl font-bold text-gray-800">Configurações da Empresa</h2>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
          {/* Company Details */}
          <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-200">
            <h3 className="text-lg font-semibold text-gray-700 mb-4 border-b pb-2">Dados da Empresa</h3>

            <div className="grid grid-cols-1 gap-4">
            <div className="flex justify-center mb-4">
                <div 
                    className="w-40 h-24 border-2 border-dashed border-gray-300 rounded-lg flex items-center justify-center cursor-pointer hover:bg-gray-50 overflow-hidden relative"
                    onClick={() => fileInputRef.current?.click()}
                >
                    {localSettings.logo ? (
                        <img src={localSettings.logo} alt="Logo" className="w-full h-full object-contain" />
                    ) : (
                        <div className="text-center text-gray-400">
                            <CameraIcon className="w-8 h-8 mx-auto" />
                            <span className="text-xs">Carregar Logo</span>
                        </div>
                    )}
                    <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleLogoUpload} />
                </div>
            </div>

            <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Nome da Empresa</label>
                <input type="text" value={localSettings.name} onChange={e => setLocalSettings({...localSettings, name: e.target.value})} className="w-full bg-white text-gray-900 border border-gray-300 rounded-lg p-2" />
            </div>

            <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Morada</label>
                <input type="text" value={localSettings.address} onChange={e => setLocalSettings({...localSettings, address: e.target.value})} className="w-full bg-white text-gray-900 border border-gray-300 rounded-lg p-2" />
            </div>

            <div className="flex gap-2">
                <div className="w-1/3">
                    <label className="block text-sm font-medium text-gray-700 mb-1">C. Postal</label>
                    <input type="text" value={localSettings.postalCode} onChange={e => setLocalSettings({...localSettings, postalCode: e.target.value})} className="w-full bg-white text-gray-900 border border-gray-300 rounded-lg p-2" />
                </div>
                <div className="flex-1">
                    <label className="block text-sm font-medium text-gray-700 mb-1">Localidade</label>
                    <input type="text" value={localSettings.city} onChange={e => setLocalSettings({...localSettings, city: e.target.value})} className="w-full bg-white text-gray-900 border border-gray-300 rounded-lg p-2" />
                </div>
            </div>

            <div className="flex gap-2">
                 <div className="flex-1">
                    <label className="block text-sm font-medium text-gray-700 mb-1">NIF</label>
                    <input type="text" value={localSettings.nif} onChange={e => setLocalSettings({...localSettings, nif: e.target.value})} className="w-full bg-white text-gray-900 border border-gray-300 rounded-lg p-2" />
                 </div>
                 <div className="flex-1">
                    <label className="block text-sm font-medium text-gray-700 mb-1">Telefone</label>
                    <input type="text" value={localSettings.phone} onChange={e => setLocalSettings({...localSettings, phone: e.target.value})} className="w-full bg-white text-gray-900 border border-gray-300 rounded-lg p-2" />
                 </div>
            </div>

            <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Email</label>
                <input type="email" value={localSettings.email} onChange={e => setLocalSettings({...localSettings, email: e.target.value})} className="w-full bg-white text-gray-900 border border-gray-300 rounded-lg p-2" />
            </div>

            <div>
                <label className="block text-sm font-bold text-gray-700 mb-1">Mensagem Inicial (Capa)</label>
                <textarea 
                    value={localSettings.quoteIntroText || ''}
                    onChange={e => setLocalSettings({...localSettings, quoteIntroText: e.target.value})}
                    className="w-full bg-white text-gray-900 border border-gray-300 rounded-lg p-2 h-24 text-sm"
                    placeholder="Texto introdutório (ex: Exmos Senhores...)"
                />
            </div>

            <div>
                <label className="block text-sm font-bold text-gray-700 mb-1">Condições Gerais de Venda</label>
                <textarea 
                    value={localSettings.generalConditions || ''}
                    onChange={e => setLocalSettings({...localSettings, generalConditions: e.target.value})}
                    className="w-full bg-white text-gray-900 border border-gray-300 rounded-lg p-2 h-40 text-sm"
                    placeholder="Texto que aparece na primeira página..."
                />
            </div>

            <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Texto de Rodapé</label>
                <textarea 
                value={localSettings.quoteFooterText}
                onChange={e => setLocalSettings({...localSettings, quoteFooterText: e.target.value})}
                className="w-full bg-white text-gray-900 border border-gray-300 rounded-lg p-2 h-16"
                />
            </div>
            </div>
          </div>

          <div className="space-y-8">
             {/* User Management */}
             <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-200">
                <h3 className="text-lg font-semibold text-gray-700 mb-4 border-b pb-2">Gestão de Utilizadores</h3>

                {/* Add User */}
                <div className="grid grid-cols-1 md:grid-cols-3 gap-2 mb-4">
                    <input type="text" placeholder="Nome" value={newUser.name} onChange={e => setNewUser({...newUser, name: e.target.value})} className="p-2 border rounded text-sm bg-white" />
                    <input type="text" placeholder="Utilizador" value={newUser.username} onChange={e => setNewUser({...newUser, username: e.target.value})} className="p-2 border rounded text-sm bg-white" />
                    <div className="flex gap-2">
                        <input type="password" placeholder="Senha" value={newUser.password} onChange={e => setNewUser({...newUser, password: e.target.value})} className="p-2 border rounded text-sm flex-1 bg-white" />
                        <button onClick={handleAddUser} className="bg-primary-600 text-white p-2 rounded"><PlusIcon className="w-5 h-5"/></button>
                    </div>
                </div>

                {/* List Users */}
                <div className="space-y-2 max-h-40 overflow-y-auto">
                    {localUsers.map(u => (
                        <div key={u.id} className="flex justify-between items-center bg-gray-50 p-2 rounded border border-gray-100">
                            <div className="flex items-center gap-2">
                                <UserIcon className="w-4 h-4 text-gray-500" />
                                <span className="font-medium text-sm text-gray-800">{u.name}</span>
                                <span className="text-xs text-gray-400">({u.username})</span>
                            </div>
                            <button onClick={() => handleDeleteUser(u.id)} className="text-red-400 hover:text-red-600 p-1">
                                <TrashIcon className="w-4 h-4" />
                            </button>
                        </div>
                    ))}
                </div>
             </div>

             {/* Types Configuration */}
             <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-200">
                <h3 className="text-lg font-semibold text-gray-700 mb-4 border-b pb-2">Tipos de Materiais</h3>
                <div className="flex gap-2 mb-3">
                    <input 
                        type="text"
                        value={newMaterialType}
                        onChange={e => setNewMaterialType(e.target.value)}
                        placeholder="Novo tipo (ex: Alumínio)"
                        className="flex-1 border border-gray-300 rounded-lg p-2 text-sm bg-white text-gray-900"
                    />
                    <button onClick={handleAddMaterialType} className="bg-primary-600 text-white px-3 rounded-lg"><PlusIcon className="w-5 h-5"/></button>
                </div>
                <div className="flex flex-wrap gap-2">
                    {localSettings.materialTypes?.map(type => (
                        <div key={type} className="bg-gray-100 text-gray-700 px-3 py-1 rounded-full text-sm flex items-center">
                            {type}
                            <button onClick={() => handleRemoveMaterialType(type)} className="ml-2 text-red-400 hover:text-red-600"><XMarkIcon className="w-3 h-3"/></button>
                        </div>
                    ))}
                </div>
             </div>

             {/* Cloud Sync */}
             <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-200">
                <div className="flex justify-between items-start mb-4 border-b pb-2">
                    <h3 className="text-lg font-semibold text-gray-700 flex items-center gap-2">
                        <span className="bg-green-100 text-green-700 p-1 rounded">Nuvem</span>
                        Sincronização
                    </h3>
                    <button onClick={() => setShowSqlHelp(!showSqlHelp)} className="text-blue-600 hover:text-blue-800 text-sm flex items-center">
                        <QuestionMarkCircleIcon className="w-5 h-5 mr-1" />
                        Ajuda
                    </button>
                </div>

                {showSqlHelp && (
                    <div className="bg-blue-50 p-4 rounded-lg mb-4 border border-blue-100 text-sm">
                        <p className="font-bold text-blue-800 mb-2">Comando SQL (Supabase):</p>
                        <div className="relative">
                            <pre className="bg-slate-800 text-slate-100 p-3 rounded text-xs overflow-x-auto font-mono">
                                {sqlCommand}
                            </pre>
                            <button onClick={() => navigator.clipboard.writeText(sqlCommand)} className="absolute top-2 right-2 bg-white/20 hover:bg-white/30 text-white p-1 rounded">
                                <ClipboardDocumentIcon className="w-4 h-4" />
                            </button>
                        </div>
                    </div>
                )}

                <div className="grid grid-cols-1 gap-3 mb-4">
                    <input type="text" value={localSettings.supabaseUrl || ''} onChange={(e) => setLocalSettings({...localSettings, supabaseUrl: e.target.value})} className="w-full bg-gray-50 border border-gray-300 rounded-lg p-2 text-sm" placeholder="URL do Projeto" />

                    <div className="relative">
                        <input 
                            type={showApiKey ? "text" : "password"} 
                            value={localSettings.supabaseKey || ''} 
                            onChange={(e) => setLocalSettings({...localSettings, supabaseKey: e.target.value})} 
                            className="w-full bg-gray-50 border border-gray-300 rounded-lg p-2 text-sm pr-10" 
                            placeholder="Chave API (anon public key)" 
                        />
                        <button 
                            onClick={() => setShowApiKey(!showApiKey)}
                            className="absolute right-2 top-2 text-gray-400 hover:text-gray-600"
                            title={showApiKey ? "Ocultar" : "Mostrar"}
                        >
                            {showApiKey ? <EyeSlashIcon className="w-5 h-5" /> : <EyeIcon className="w-5 h-5" />}
                        </button>
                    </div>
                </div>

                <div className="flex gap-2">
                    <button onClick={handleCloudUpload} disabled={syncing} className="flex-1 flex justify-center items-center px-3 py-2 bg-green-600 text-white rounded-lg hover:bg-green-700 shadow-sm text-sm">
                        <CloudArrowUpIcon className="w-4 h-4 mr-2" />
                        {syncing ? '...' : 'Enviar'}
                    </button>
                    <button onClick={handleCloudDownload} disabled={syncing} className="flex-1 flex justify-center items-center px-3 py-2 bg-white text-gray-700 border border-gray-300 rounded-lg hover:bg-gray-50 shadow-sm text-sm">
                        <CloudArrowDownIcon className="w-4 h-4 mr-2" />
                        {syncing ? '...' : 'Receber'}
                    </button>
                </div>
             </div>

             {/* Backup Local */}
             <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-200">
                <h3 className="text-lg font-semibold text-gray-700 mb-4 border-b pb-2">Backup Ficheiro</h3>
                <div className="flex gap-2">
                    <button onClick={handleExportData} className="flex-1 flex justify-center items-center px-4 py-2 bg-blue-50 text-blue-700 rounded-lg hover:bg-blue-100 border border-blue-200 text-sm">
                        <ArrowDownTrayIcon className="w-4 h-4 mr-2" />
                        Exportar
                    </button>
                    <button onClick={handleImportClick} className="flex-1 flex justify-center items-center px-4 py-2 bg-orange-50 text-orange-700 rounded-lg hover:bg-orange-100 border border-orange-200 text-sm">
                        <ArrowUpTrayIcon className="w-4 h-4 mr-2" />
                        Importar
                    </button>
                    <input type="file" ref={importInputRef} className="hidden" accept=".json" onChange={handleImportFileChange} />
                </div>
             </div>

             <div className="text-right pt-4">
                 <button onClick={handleSaveSettings} className="bg-primary-600 hover:bg-primary-700 text-white px-8 py-3 rounded-lg font-bold shadow-md w-full">
                    Guardar Todas as Configurações
                 </button>
             </div>
          </div>
      </div>
    </div>
  );
};

export default SettingsManager;

import React from 'react';
import { 
  HomeIcon, 
  UsersIcon, 
  WrenchIcon, 
  DocumentTextIcon, 
  Bars3Icon,
  XMarkIcon,
  ArrowRightOnRectangleIcon,
  CalculatorIcon,
