    { id: 'calculator', label: 'Calculadora', icon: CalculatorIcon },
    { id: 'settings', label: 'Configurações', icon: Cog6ToothIcon },
  ];

  return (
    <div className="flex h-screen bg-metal-50 overflow-hidden">
      {/* Sidebar Desktop - ADDED no-print class */}
      <aside className="hidden md:flex flex-col w-64 bg-metal-900 text-white shadow-xl z-10 no-print">
        <div className="p-6 border-b border-metal-700">
          <h1 className="text-xl font-bold bg-gradient-to-r from-blue-400 to-blue-200 bg-clip-text text-transparent">
            {companySettings.name || 'Serralharia Pro'}
