        </div>
      </aside>

      {/* Main Content */}
      <div className="flex-1 flex flex-col h-full overflow-hidden w-full">
        {/* Mobile Header - ADDED no-print class */}
        <header className="md:hidden bg-metal-900 text-white p-4 flex justify-between items-center shadow-md no-print">
          <h1 className="text-lg font-bold">{companySettings.name || 'Serralharia Pro'}</h1>
          <button onClick={() => setMobileMenuOpen(!mobileMenuOpen)}>
            {mobileMenuOpen ? <XMarkIcon className="w-6 h-6" /> : <Bars3Icon className="w-6 h-6" />}
          </button>
        </header>

        {/* Sync Status Indicator (Desktop Top Right) */}
        <div className="hidden md:flex absolute top-4 right-8 z-20 items-center bg-white/80 backdrop-blur px-3 py-1.5 rounded-full shadow border border-metal-200 text-xs font-medium no-print">
