            {syncStatus === 'saved' && (
                <>
                    <CheckCircleIcon className="w-4 h-4 text-green-500 mr-2" />
                    <span className="text-green-600">Guardado na nuvem</span>
                </>
            )}
            {syncStatus === 'error' && (
                <>
                    <ExclamationCircleIcon className="w-4 h-4 text-red-500 mr-2" />
                    <span className="text-red-600">Erro sync</span>
                </>
            )}
            {syncStatus === 'idle' && (
                <span className="text-gray-400">Offline / Local</span>
            )}
        </div>

        {/* Mobile Menu */}
        {mobileMenuOpen && (
          <div className="md:hidden bg-metal-800 text-white absolute top-14 left-0 w-full z-20 shadow-xl border-t border-metal-700 no-print">
             <nav className="p-4 space-y-2">
              {navItems.map((item) => (
