export default Layout;

import React, { useEffect, useState, useRef } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import ClientManager from './components/ClientManager';
import ArticleManager from './components/ArticleManager';
import QuoteManager from './components/QuoteManager';
import MaterialManager from './components/MaterialManager';
import PriceCalculator from './components/PriceCalculator';
import Login from './components/Login';
import SettingsManager from './components/SettingsManager';
import { AppData, Client, Article, Quote, User, CompanySettings, RawMaterial } from './types';
import { loadData, saveData } from './services/storage';
import { uploadDataToCloud, downloadDataFromCloud } from './services/supabaseService';

type SyncStatus = 'idle' | 'syncing' | 'saved' | 'error';

const App: React.FC = () => {
  const [data, setData] = useState<AppData>({
    clients: [],
    articles: [],
    quotes: [],
    nextQuoteNumber: 1,
    users: [],
    companySettings: {
        name: '', address: '', postalCode: '', city: '', nif: '', phone: '', email: '', quoteFooterText: '', materialTypes: []
    },
    rawMaterials: []
  });
  const [activeTab, setActiveTab] = useState('dashboard');
  const [loaded, setLoaded] = useState(false);
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [syncStatus, setSyncStatus] = useState<SyncStatus>('idle');

  // Timer para debounce do auto-save
  const saveTimeoutRef = useRef<NodeJS.Timeout | null>(null);
  // Ref para evitar upload imediato após download
  const isDownloadingRef = useRef(false);

  // 1. Carregar dados locais ao iniciar
  useEffect(() => {
    const stored = loadData();
    setData(stored);
    setLoaded(true);
  }, []);

  // 2. Tentar descarregar da nuvem ao iniciar (se configurado)
  useEffect(() => {
    const initCloudLoad = async () => {
        if (!loaded) return;
        const { supabaseUrl, supabaseKey } = data.companySettings;

        if (supabaseUrl && supabaseKey) {
            setSyncStatus('syncing');
            isDownloadingRef.current = true;

            const result = await downloadDataFromCloud(supabaseUrl, supabaseKey);

            if (result.success && result.data) {
                console.log("Cloud data loaded on startup");
                setData(result.data);
                setSyncStatus('saved');
            } else {
                setSyncStatus(result.message.includes('Configuração') ? 'idle' : 'error');
            }

            // Pequeno delay para permitir que o estado estabilize antes de permitir uploads
            setTimeout(() => {
                isDownloadingRef.current = false;
            }, 1000);
        }
    };

    initCloudLoad();
  }, [loaded]); // Corre apenas uma vez quando o load local termina

  // 3. Auto-Save Local e Nuvem quando os dados mudam
  useEffect(() => {
    if (!loaded) return;

    // Save Local Storage (Sync)
    saveData(data);

    // Auto-Save Cloud (Async com Debounce)
    const { supabaseUrl, supabaseKey } = data.companySettings;

    if (supabaseUrl && supabaseKey && !isDownloadingRef.current) {
        setSyncStatus('syncing');

        // Limpar timeout anterior
        if (saveTimeoutRef.current) {
            clearTimeout(saveTimeoutRef.current);
        }

        // Definir novo timeout (2 segundos de inatividade para guardar)
        saveTimeoutRef.current = setTimeout(async () => {
            const result = await uploadDataToCloud(data, supabaseUrl, supabaseKey);
            setSyncStatus(result.success ? 'saved' : 'error');
        }, 2000);
    }

    return () => {
        if (saveTimeoutRef.current) {
            clearTimeout(saveTimeoutRef.current);
        }
    };
  }, [data, loaded]);

  const updateClients = (newClients: Client[]) => {
    setData(prev => ({ ...prev, clients: newClients }));
  };

  const updateArticles = (newArticles: Article[]) => {
    setData(prev => ({ ...prev, articles: newArticles }));
  };

  const updateMaterials = (newMaterials: RawMaterial[]) => {
    setData(prev => ({ ...prev, rawMaterials: newMaterials }));
  };

  const updateUsers = (newUsers: User[]) => {
    setData(prev => ({ ...prev, users: newUsers }));
  };

  const updateSettings = (newSettings: CompanySettings) => {
    setData(prev => ({ ...prev, companySettings: newSettings }));
  };

  const handleImportData = (newData: AppData) => {
    setData(newData);
    alert('Base de dados importada com sucesso!');
  };

  const saveQuote = (quote: Quote) => {
    setData(prev => {
      const exists = prev.quotes.find(q => q.id === quote.id);
      let newQuotes;
      let nextNum = prev.nextQuoteNumber;

      if (exists) {
        newQuotes = prev.quotes.map(q => q.id === quote.id ? quote : q);
      } else {
        newQuotes = [...prev.quotes, quote];
        nextNum = prev.nextQuoteNumber + 1;
      }
      return { ...prev, quotes: newQuotes, nextQuoteNumber: nextNum };
    });
  };

  const deleteQuote = (id: string) => {
    if (confirm('Tem a certeza que deseja eliminar este orçamento?')) {
        setData(prev => ({ ...prev, quotes: prev.quotes.filter(q => q.id !== id) }));
    }
  };

  const handleSaveArticleFromCalculator = (article: Article) => {
      updateArticles([...data.articles, article]);
      setActiveTab('articles');
  };

  const handleLogin = (user: User) => {
    setCurrentUser(user);
    setActiveTab('dashboard');
  };

  const handleLogout = () => {
    setCurrentUser(null);
  };

  if (!loaded) return <div className="flex h-screen items-center justify-center text-metal-500">A carregar...</div>;

  if (!currentUser) {
    return <Login users={data.users} onLogin={handleLogin} />;
  }

  return (
    <Layout 
        activeTab={activeTab} 
        onChangeTab={setActiveTab} 
        currentUser={currentUser} 
        onLogout={handleLogout}
        companySettings={data.companySettings}
        syncStatus={syncStatus}
    >
      {activeTab === 'dashboard' && (
        <Dashboard 
            quotes={data.quotes} 
            clients={data.clients} 
            articles={data.articles} 
        />
      )}
      {activeTab === 'clients' && (
        <ClientManager clients={data.clients} setClients={updateClients} quotes={data.quotes} />
      )}
      {activeTab === 'articles' && (
        <ArticleManager articles={data.articles} setArticles={updateArticles} />
      )}
      {activeTab === 'materials' && (
        <MaterialManager 
            materials={data.rawMaterials} 
            setMaterials={updateMaterials} 
            materialTypes={data.companySettings.materialTypes}
        />
      )}
      {activeTab === 'calculator' && (
        <PriceCalculator materials={data.rawMaterials} onSaveArticle={handleSaveArticleFromCalculator} />
      )}
      {activeTab === 'quotes' && (
        <QuoteManager 
          quotes={data.quotes}
          clients={data.clients}
          articles={data.articles}
          nextQuoteNumber={data.nextQuoteNumber}
          companySettings={data.companySettings}
          onSaveQuote={saveQuote}
          onDeleteQuote={deleteQuote}
        />
      )}
      {activeTab === 'settings' && (
        <SettingsManager 
            settings={data.companySettings}
            users={data.users}
            fullData={data}
            onUpdateSettings={updateSettings}
            onUpdateUsers={updateUsers}
            onImportData={handleImportData}
        />
      )}
    </Layout>
  );
};

export default App;

