import React, { useState, useRef } from 'react';
import { 
  PlusIcon, 
  PrinterIcon, 
  TrashIcon, 
  ArrowLeftIcon, 
  SparklesIcon, 
  CameraIcon,
  MagnifyingGlassIcon,
  XMarkIcon,
  EnvelopeIcon,
  ArrowDownTrayIcon,
  CheckBadgeIcon
} from '@heroicons/react/24/outline';
import { Quote, Client, Article, QuoteItem, QuoteStatus, UnitType, CompanySettings, QuoteItemDetail } from '../types';
import { generateQuoteNotes } from '../services/geminiService';
import SchematicDesigner from './SchematicDesigner';

declare const html2pdf: any;

interface QuoteManagerProps {
  quotes: Quote[];
  clients: Client[];
  articles: Article[];
  nextQuoteNumber: number;
  companySettings: CompanySettings;
  onSaveQuote: (quote: Quote) => void;
  onDeleteQuote: (id: string) => void;
}

const QuoteManager: React.FC<QuoteManagerProps> = ({ 
  quotes, clients, articles, nextQuoteNumber, companySettings, onSaveQuote, onDeleteQuote 
}) => {
  const [view, setView] = useState<'list' | 'edit' | 'print'>('list');
  const [currentQuote, setCurrentQuote] = useState<Quote | null>(null);
  const [loadingAi, setLoadingAi] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [activeItemIdForUpload, setActiveItemIdForUpload] = useState<string | null>(null);
  const [showSchematicDesigner, setShowSchematicDesigner] = useState(false);

  // List Filters
  const [filterClient, setFilterClient] = useState('');
  const [filterDateStart, setFilterDateStart] = useState('');
  const [filterDateEnd, setFilterDateEnd] = useState('');

  // Client Search State (Edit Mode)
  const [clientSearchTerm, setClientSearchTerm] = useState('');
  const [showClientResults, setShowClientResults] = useState(false);
  const [showClientListModal, setShowClientListModal] = useState(false);

  // Helper to init a new quote
  const initNewQuote = () => {
    const newQuote: Quote = {
      id: crypto.randomUUID(),
      clientId: '',
      number: nextQuoteNumber,
      date: new Date().toISOString().split('T')[0],
      validUntil: new Date(Date.now() + 15 * 24 * 60 * 60 * 1000).toISOString().split('T')[0],
      items: [],
      subtotal: 0,
      taxRate: 23,
      taxAmount: 0,
      total: 0,
      status: QuoteStatus.DRAFT,
      notes: '',
      internalNotes: '',
      upfrontPercentage: 50, // Default 50%
      enableUpfrontPayment: true
    };
    setCurrentQuote(newQuote);
    setClientSearchTerm('');
    setView('edit');
  };

  const calculateTotals = (quote: Quote): Quote => {
    const updatedItems = quote.items.map(item => {
        const detailsSum = item.details?.reduce((acc, d) => acc + (d.price || 0), 0) || 0;
        const total = item.quantity * (item.unitPrice + detailsSum);
        return { ...item, total };
    });

    const subtotal = updatedItems.reduce((sum, item) => sum + item.total, 0);
    const taxAmount = subtotal * (quote.taxRate / 100);
    const total = subtotal + taxAmount;
    return { ...quote, items: updatedItems, subtotal, taxAmount, total };
  };

  const handleAddItem = () => {
    if (!currentQuote) return;
    const newItem: QuoteItem = {
      id: crypto.randomUUID(),
      articleId: '',
      name: '',
      quantity: 1,
      unitPrice: 0,
      unit: UnitType.UN,
      total: 0,
      details: []
    };
    setCurrentQuote({ ...currentQuote, items: [...currentQuote.items, newItem] });
  };

  const handleItemChange = (itemId: string, field: keyof QuoteItem, value: any) => {
    if (!currentQuote) return;
    const updatedItems = currentQuote.items.map(item => {
      if (item.id !== itemId) return item;

      const updatedItem = { ...item, [field]: value };

      // Auto-fill from article
      if (field === 'articleId') {
        const article = articles.find(a => a.id === value);
        if (article) {
          updatedItem.name = article.name;
          updatedItem.description = article.description;
          updatedItem.unitPrice = article.price;
          updatedItem.unit = article.unit;
          // If article has image and item doesn't, use article image
          if(article.image && !updatedItem.image) {
              updatedItem.image = article.image;
          }
        }
      }

      return updatedItem;
    });

    setCurrentQuote(calculateTotals({ ...currentQuote, items: updatedItems }));
  };

  const handleDeleteItem = (itemId: string) => {
    if (!currentQuote) return;
    const updatedItems = currentQuote.items.filter(i => i.id !== itemId);
    setCurrentQuote(calculateTotals({ ...currentQuote, items: updatedItems }));
  };

  // --- ITEM DETAILS / OPTIONS LOGIC ---
  const handleAddDetail = (itemId: string) => {
    if (!currentQuote) return;
    const updatedItems = currentQuote.items.map(item => {
        if (item.id === itemId) {
            const newDetail: QuoteItemDetail = { id: crypto.randomUUID(), label: '', value: '', price: 0 };
            return { ...item, details: [...(item.details || []), newDetail] };
        }
        return item;
    });
    setCurrentQuote(calculateTotals({ ...currentQuote, items: updatedItems }));
  };

  const handleUpdateDetail = (itemId: string, detailId: string, field: 'label' | 'value' | 'price', val: any) => {
    if (!currentQuote) return;
    const updatedItems = currentQuote.items.map(item => {
        if (item.id === itemId) {
            const updatedDetails = (item.details || []).map(d => 
                d.id === detailId ? { ...d, [field]: val } : d
            );
            return { ...item, details: updatedDetails };
        }
        return item;
    });
    setCurrentQuote(calculateTotals({ ...currentQuote, items: updatedItems }));
  };

  const handleDeleteDetail = (itemId: string, detailId: string) => {
    if (!currentQuote) return;
    const updatedItems = currentQuote.items.map(item => {
        if (item.id === itemId) {
            return { ...item, details: (item.details || []).filter(d => d.id !== detailId) };
        }
        return item;
    });
    setCurrentQuote(calculateTotals({ ...currentQuote, items: updatedItems }));
  };

  // Image Upload Logic
  const triggerImageUpload = (itemId: string) => {
    setActiveItemIdForUpload(itemId);
    if (fileInputRef.current) {
        fileInputRef.current.click();
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0] && activeItemIdForUpload) {
        const file = e.target.files[0];
        const reader = new FileReader();
        reader.onload = (event) => {
             handleItemChange(activeItemIdForUpload, 'image', event.target?.result as string);
             setActiveItemIdForUpload(null);
        };
        reader.readAsDataURL(file);
    }
    e.target.value = '';
  };

  const handleSaveSchematic = (imgData: string) => {
      if (activeItemIdForUpload) {
          handleItemChange(activeItemIdForUpload, 'image', imgData);
          setShowSchematicDesigner(false);
          setActiveItemIdForUpload(null);
      }
  };

  const handleGenerateNotes = async () => {
    if (!currentQuote || currentQuote.items.length === 0) return;
    setLoadingAi(true);
    const itemNames = currentQuote.items.map(i => i.name);
    const notes = await generateQuoteNotes(itemNames);
    setCurrentQuote(prev => prev ? { ...prev, notes } : null);
    setLoadingAi(false);
  };

  const handleDownloadPdf = () => {
      const element = document.getElementById('print-area');
      const opt = {
          margin: [0, 0, 0, 0], // Margem zero, tratamos no CSS
          filename: `Orcamento_${currentQuote?.number}.pdf`,
          image: { type: 'jpeg', quality: 0.98 },
          html2canvas: { scale: 2, useCORS: true },
          jsPDF: { unit: 'mm', format: 'a4', orientation: 'portrait' },
          // AQUI: Forçar quebra antes do elemento com ID #page2-start
          pagebreak: { mode: ['css', 'legacy'], before: '#page2-start' }
      };

      // Gerar PDF e adicionar numeração de páginas
      // @ts-ignore
      html2pdf().from(element).set(opt).toPdf().get('pdf').then(function (pdf) {
        var totalPages = pdf.internal.getNumberOfPages();
        for (let i = 1; i <= totalPages; i++) {
            pdf.setPage(i);
            pdf.setFontSize(8);
            pdf.setTextColor(150);
            // Rodapé: Página X de Y
            pdf.text('Página ' + i + ' de ' + totalPages, pdf.internal.pageSize.getWidth() - 30, pdf.internal.pageSize.getHeight() - 10);
        }
      }).save();
  };

  const handleSendGmail = () => {
    if (!currentQuote) return;
    const client = clients.find(c => c.id === currentQuote.clientId);
    if (!client || !client.email) {
        alert("Cliente não tem email definido ou selecionado.");
        return;
    }

    const subject = encodeURIComponent(`Orçamento Nº ${currentQuote.number} - ${companySettings.name}`);
    const body = encodeURIComponent(
`Olá ${client.name},

Segue em anexo o Orçamento Nº ${currentQuote.number}.

Valor Total: ${currentQuote.total.toFixed(2)} €
Validade: ${new Date(currentQuote.validUntil).toLocaleDateString('pt-PT')}

Melhores cumprimentos,
${companySettings.name}`
    );

    alert("O PDF será descarregado. Por favor anexe-o manualmente no email que irá abrir.");
    handleDownloadPdf();
    setTimeout(() => {
        window.open(`https://mail.google.com/mail/?view=cm&fs=1&to=${client.email}&su=${subject}&body=${body}`, '_blank');
    }, 1500);
  };

  // --- CLIENT SEARCH & FILTER LOGIC ---
  const filteredClients = clients.filter(c => 
    c.name.toLowerCase().includes(clientSearchTerm.toLowerCase()) || 
    c.nif.includes(clientSearchTerm)
  );

  const selectClient = (client: Client) => {
    if (currentQuote) {
        setCurrentQuote({ ...currentQuote, clientId: client.id });
        setClientSearchTerm('');
        setShowClientResults(false);
        setShowClientListModal(false);
    }
  };

  const filteredQuotes = quotes.filter(q => {
      const client = clients.find(c => c.id === q.clientId);
      const matchesClient = filterClient === '' || client?.name.toLowerCase().includes(filterClient.toLowerCase());
      const matchesDateStart = filterDateStart === '' || q.date >= filterDateStart;
      const matchesDateEnd = filterDateEnd === '' || q.date <= filterDateEnd;
      return matchesClient && matchesDateStart && matchesDateEnd;
  });

  const getStatusColor = (status: QuoteStatus) => {
      switch(status) {
          case QuoteStatus.ACCEPTED: return 'bg-green-100 text-green-700';
          case QuoteStatus.SENT: return 'bg-blue-100 text-blue-700';
          case QuoteStatus.REJECTED: return 'bg-red-100 text-red-700';
          case QuoteStatus.CLOSED: return 'bg-gray-800 text-white';
          default: return 'bg-gray-100 text-gray-700';
      }
  };

  // --- RENDERERS ---

  if (view === 'list') {
    return (
      <div className="max-w-6xl mx-auto">
        <div className="flex justify-between items-center mb-6">
          <h2 className="text-2xl font-bold text-metal-800">Orçamentos</h2>
          <button onClick={initNewQuote} className="bg-primary-600 hover:bg-primary-700 text-white px-4 py-2 rounded-lg flex items-center shadow-sm">
            <PlusIcon className="w-5 h-5 mr-2" />
            Criar Orçamento
          </button>
        </div>

        {/* Filters */}
        <div className="bg-white p-4 rounded-xl shadow-sm border border-metal-200 mb-6 flex flex-wrap gap-4 items-end">
            <div className="flex-1 min-w-[200px]">
                <label className="text-xs text-metal-500 mb-1 block">Filtrar Cliente</label>
                <div className="relative">
                    <MagnifyingGlassIcon className="absolute left-2 top-2.5 w-4 h-4 text-gray-400" />
                    <input type="text" value={filterClient} onChange={e => setFilterClient(e.target.value)} className="w-full pl-8 p-2 border border-gray-300 rounded-lg text-sm bg-white text-gray-900" placeholder="Nome..." />
                </div>
            </div>
            <div>
                <label className="text-xs text-metal-500 mb-1 block">De</label>
                <input type="date" value={filterDateStart} onChange={e => setFilterDateStart(e.target.value)} className="p-2 border border-gray-300 rounded-lg text-sm bg-white text-gray-900" />
            </div>
            <div>
                <label className="text-xs text-metal-500 mb-1 block">Até</label>
                <input type="date" value={filterDateEnd} onChange={e => setFilterDateEnd(e.target.value)} className="p-2 border border-gray-300 rounded-lg text-sm bg-white text-gray-900" />
            </div>
            <button onClick={() => {setFilterClient(''); setFilterDateStart(''); setFilterDateEnd('')}} className="p-2 text-metal-500 hover:text-metal-800" title="Limpar Filtros">
                <XMarkIcon className="w-5 h-5" />
            </button>
        </div>

        <div className="bg-white rounded-xl shadow-sm border border-metal-200 overflow-hidden">
          <table className="w-full text-left">
            <thead className="bg-metal-50 text-metal-600 text-sm font-semibold">
              <tr>
                <th className="p-4">Nº</th>
                <th className="p-4">Cliente</th>
                <th className="p-4">Data</th>
                <th className="p-4">Total</th>
                <th className="p-4">Estado</th>
                <th className="p-4 text-center">Ações</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-metal-100">
              {filteredQuotes.length === 0 && (
                <tr><td colSpan={6} className="p-8 text-center text-metal-400">Sem orçamentos encontrados.</td></tr>
              )}
              {filteredQuotes.map(quote => {
                const client = clients.find(c => c.id === quote.clientId);
                return (
                  <tr key={quote.id} className="hover:bg-metal-50 cursor-pointer" onClick={() => { setCurrentQuote(quote); setView('edit'); }}>
                    <td className="p-4 font-mono text-metal-600">#{quote.number.toString().padStart(4, '0')}</td>
                    <td className="p-4 font-medium text-metal-900">{client?.name || 'Cliente Removido'}</td>
                    <td className="p-4 text-metal-600">{new Date(quote.date).toLocaleDateString('pt-PT')}</td>
                    <td className="p-4 font-bold text-metal-900">{quote.total.toFixed(2)} €</td>
                    <td className="p-4">
                      <span className={`px-2 py-1 rounded-full text-xs font-medium ${getStatusColor(quote.status)}`}>
                        {quote.status}
                      </span>
                    </td>
                    <td className="p-4 text-center">
                      <button 
                        onClick={(e) => { e.stopPropagation(); onDeleteQuote(quote.id); }}
                        className="p-2 text-red-500 hover:bg-red-50 rounded"
                      >
                        <TrashIcon className="w-4 h-4" />
                      </button>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </div>
    );
  }

  if (view === 'edit' && currentQuote) {
    const selectedClient = clients.find(c => c.id === currentQuote.clientId);

    return (
      <div className="max-w-5xl mx-auto space-y-6 pb-20">
        {/* Hidden Inputs/Modals */}
        <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleFileChange} />
        {showSchematicDesigner && (
            <SchematicDesigner 
                onSave={handleSaveSchematic} 
                onCancel={() => { setShowSchematicDesigner(false); setActiveItemIdForUpload(null); }} 
            />
        )}

        {/* Client Selection Modal */}
        {showClientListModal && (
            <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4">
                <div className="bg-white rounded-xl shadow-2xl w-full max-w-2xl max-h-[80vh] flex flex-col">
                    <div className="p-4 border-b border-metal-200 flex justify-between items-center">
                        <h3 className="text-lg font-bold text-metal-800">Selecionar Cliente</h3>
                        <button onClick={() => setShowClientListModal(false)} className="text-metal-400 hover:text-metal-600"><XMarkIcon className="w-6 h-6" /></button>
                    </div>
                    <div className="p-4 border-b border-metal-100">
                        <input 
                            type="text" autoFocus placeholder="Filtrar lista de clientes..." className="w-full p-2 border border-metal-300 rounded-lg text-sm bg-white text-gray-900"
                            value={clientSearchTerm} onChange={(e) => setClientSearchTerm(e.target.value)}
                        />
                    </div>
                    <div className="overflow-y-auto flex-1 p-2">
                        {filteredClients.map(client => (
                            <div key={client.id} onClick={() => selectClient(client)} className="p-3 hover:bg-gray-50 cursor-pointer border-b border-gray-100 flex justify-between">
                                <div>
                                    <div className="font-medium text-gray-900">{client.name}</div>
                                    <div className="text-xs text-gray-500">{client.nif}</div>
                                </div>
                                <button className="px-3 py-1 bg-primary-100 text-primary-700 rounded text-xs">Selecionar</button>
                            </div>
                        ))}
                    </div>
                </div>
            </div>
        )}

        <div className="flex items-center justify-between">
            <button onClick={() => setView('list')} className="flex items-center text-metal-500 hover:text-metal-800">
                <ArrowLeftIcon className="w-4 h-4 mr-1" /> Voltar
            </button>
            <div className="flex gap-2">
                 {/* Status Selector */}
                 <div className="relative">
                    <select 
                        value={currentQuote.status}
                        onChange={(e) => setCurrentQuote({...currentQuote, status: e.target.value as QuoteStatus})}
                        className={`appearance-none px-3 py-2 pr-8 border rounded-lg text-sm font-medium ${getStatusColor(currentQuote.status)}`}
                    >
                        {Object.values(QuoteStatus).map(status => (
                            <option key={status} value={status}>{status}</option>
                        ))}
                    </select>
                    <ArrowDownTrayIcon className="w-4 h-4 absolute right-2 top-2.5 opacity-50 pointer-events-none" />
                 </div>

                 <button onClick={handleSendGmail} className="flex items-center px-3 py-2 border border-red-200 text-red-600 rounded-lg hover:bg-red-50 text-sm font-medium">
                    <EnvelopeIcon className="w-4 h-4 mr-1" /> Email
                </button>
                 <button onClick={() => { setView('print'); }} className="flex items-center px-4 py-2 border border-metal-300 rounded-lg bg-white hover:bg-metal-50 text-metal-700">
                    <PrinterIcon className="w-4 h-4 mr-2" /> Pré-visualizar
                </button>
                <button onClick={() => { onSaveQuote(currentQuote); setView('list'); }} className="bg-primary-600 hover:bg-primary-700 text-white px-6 py-2 rounded-lg font-medium shadow-sm">
                    Guardar
                </button>
            </div>
        </div>

        {/* Header Info */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-metal-200 grid grid-cols-1 md:grid-cols-3 gap-6">
           {/* Client Search Section */}
           <div>
             <label className="block text-sm font-medium text-metal-600 mb-1">Cliente</label>
             {selectedClient ? (
                 <div className="flex items-center justify-between p-2 border border-blue-200 bg-blue-50 rounded-lg">
                     <div>
                         <div className="font-bold text-blue-900">{selectedClient.name}</div>
                         <div className="text-xs text-blue-700">NIF: {selectedClient.nif || 'N/A'}</div>
                     </div>
                     <button onClick={() => setCurrentQuote({...currentQuote, clientId: ''})} className="text-blue-500 hover:text-blue-700 p-1"><XMarkIcon className="w-5 h-5" /></button>
                 </div>
             ) : (
                 <div className="flex gap-2">
                    <button onClick={() => setShowClientListModal(true)} className="flex-1 text-left px-3 py-2 border border-metal-300 rounded-lg bg-white text-gray-500 text-sm hover:bg-gray-50">Selecionar Cliente...</button>
                 </div>
             )}
           </div>

           <div>
             <label className="block text-sm font-medium text-metal-600 mb-1">Validade (Data)</label>
             <input type="date" value={currentQuote.validUntil} onChange={(e) => setCurrentQuote({...currentQuote, validUntil: e.target.value})} className="w-full border border-metal-300 rounded-lg p-2 bg-white text-gray-900" />
           </div>

           <div>
             <label className="block text-sm font-medium text-metal-600 mb-1">Condição de Pagamento</label>
             <div className="flex items-center gap-2 mb-2">
                <input 
                    type="checkbox" 
                    checked={currentQuote.enableUpfrontPayment ?? true}
                    onChange={(e) => setCurrentQuote({...currentQuote, enableUpfrontPayment: e.target.checked})}
                    className="w-4 h-4 text-primary-600"
                />
                <span className="text-sm">Ativar Adjudicação (%)</span>
             </div>
             {(currentQuote.enableUpfrontPayment ?? true) && (
                 <div className="flex items-center">
                     <input 
                        type="number" min="0" max="100" 
                        value={currentQuote.upfrontPercentage ?? 50} 
                        onChange={(e) => setCurrentQuote({...currentQuote, upfrontPercentage: Number(e.target.value)})} 
                        className="w-20 border border-metal-300 rounded-lg p-2 bg-white text-gray-900 text-right mr-2" 
                     />
                     <span className="text-sm text-metal-600">%</span>
                 </div>
             )}
           </div>
        </div>

        {/* Items */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-metal-200">
            <h3 className="text-lg font-bold text-metal-800 mb-4">Itens do Orçamento</h3>
            <div className="space-y-4">
                {currentQuote.items.map((item, index) => (
                    <div key={item.id} className="p-4 bg-metal-50 rounded-lg border border-metal-100 animate-fade-in">
                        <div className="flex flex-col md:flex-row gap-4 items-start">
                            {/* Image Uploader */}
                            <div className="flex-shrink-0 flex flex-col gap-2">
                                <div 
                                    className="w-24 h-24 rounded-lg border-2 border-dashed border-metal-300 bg-white flex flex-col items-center justify-center overflow-hidden relative"
                                >
                                    {item.image ? (
                                        <img src={item.image} alt="Preview" className="w-full h-full object-contain" />
                                    ) : (
                                        <CameraIcon className="w-6 h-6 text-metal-300" />
                                    )}
                                </div>
                                <div className="flex gap-1">
                                    <button onClick={() => triggerImageUpload(item.id)} className="text-[10px] bg-white border p-1 rounded hover:bg-gray-50 flex-1">Foto</button>
                                    <button onClick={() => { setActiveItemIdForUpload(item.id); setShowSchematicDesigner(true); }} className="text-[10px] bg-white border p-1 rounded hover:bg-gray-50 flex-1">Desenho</button>
                                </div>
                            </div>

                            {/* Main Inputs */}
                            <div className="flex-1 space-y-2 w-full">
                                <div className="flex gap-2">
                                    <select 
                                        value={item.articleId}
                                        onChange={(e) => handleItemChange(item.id, 'articleId', e.target.value)}
                                        className="w-1/3 border border-metal-300 rounded-lg p-2 text-sm bg-white text-gray-900"
                                    >
                                        <option value="">Personalizado</option>
                                        {articles.map(a => <option key={a.id} value={a.id}>{a.name}</option>)}
                                    </select>
                                    <input 
                                        type="text" 
                                        placeholder="Nome do Item"
                                        value={item.name}
                                        onChange={(e) => handleItemChange(item.id, 'name', e.target.value)}
                                        className="flex-1 border border-metal-300 rounded-lg p-2 text-sm font-medium bg-white text-gray-900"
                                    />
                                </div>
                                <textarea 
                                    placeholder="Descrição detalhada..."
                                    value={item.description || ''}
                                    onChange={(e) => handleItemChange(item.id, 'description', e.target.value)}
                                    className="w-full border border-metal-300 rounded-lg p-2 text-sm h-16 resize-none bg-white text-gray-900"
                                />
                            </div>

                            {/* Qty & Price */}
                            <div className="flex gap-2 w-full md:w-auto items-start">
                                <div className="w-20">
                                    <label className="text-xs text-metal-500">Qtd</label>
                                    <input 
                                        type="number"
                                        min="1"
                                        value={item.quantity === 0 ? '' : item.quantity}
                                        onChange={(e) => handleItemChange(item.id, 'quantity', Number(e.target.value))}
                                        className="w-full border border-metal-300 rounded-lg p-2 text-sm bg-white text-gray-900"
                                    />
                                </div>
                                <div className="w-24">
                                    <label className="text-xs text-metal-500">Preço Unit.</label>
                                    <input 
                                        type="number"
                                        min="0"
                                        step="0.01"
                                        value={item.unitPrice === 0 ? '' : item.unitPrice}
                                        onChange={(e) => handleItemChange(item.id, 'unitPrice', Number(e.target.value))}
                                        className="w-full border border-metal-300 rounded-lg p-2 text-sm bg-white text-gray-900"
                                    />
                                </div>
                                <div className="w-24">
                                    <label className="text-xs text-metal-500">Total</label>
                                    <div className="p-2 bg-metal-100 rounded-lg text-sm font-bold text-right text-gray-900">
                                        {item.total.toFixed(2)}€
                                    </div>
                                </div>
                                <button 
                                    onClick={() => handleDeleteItem(item.id)}
                                    className="mt-5 text-red-500 hover:bg-red-50 p-2 rounded"
                                >
                                    <TrashIcon className="w-5 h-5" />
                                </button>
                            </div>
                        </div>

                        {/* PRODUCT OPTIONS / DETAILS */}
                        <div className="mt-4 pl-0 md:pl-28">
                            <h4 className="text-xs font-bold text-gray-500 uppercase mb-2">Acabamentos, Extras e Opções</h4>
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-2">
                                {item.details?.map((detail) => (
                                    <div key={detail.id} className="flex gap-2 items-center">
                                        <input type="text" placeholder="Ex: Cor" value={detail.label} onChange={(e) => handleUpdateDetail(item.id, detail.id, 'label', e.target.value)} className="w-1/4 p-1.5 text-xs border border-gray-300 rounded bg-white" />
                                        <input type="text" placeholder="Ex: Cinza" value={detail.value} onChange={(e) => handleUpdateDetail(item.id, detail.id, 'value', e.target.value)} className="w-1/3 p-1.5 text-xs border border-gray-300 rounded bg-white" />
                                        <div className="flex-1 flex items-center relative">
                                            <span className="absolute left-2 text-xs text-gray-500">+</span>
                                            <input type="number" placeholder="0.00" value={detail.price === 0 ? '' : detail.price} onChange={(e) => handleUpdateDetail(item.id, detail.id, 'price', Number(e.target.value))} className="w-full p-1.5 pl-4 text-xs border border-gray-300 rounded bg-white" />
                                            <span className="absolute right-2 text-xs text-gray-500">€</span>
                                        </div>
                                        <button onClick={() => handleDeleteDetail(item.id, detail.id)} className="text-red-400 hover:text-red-600"><XMarkIcon className="w-4 h-4" /></button>
                                    </div>
                                ))}
                                <button onClick={() => handleAddDetail(item.id)} className="flex items-center text-xs text-blue-600 hover:text-blue-800 font-medium py-1">
                                    <PlusIcon className="w-3 h-3 mr-1" /> Adicionar Opção
                                </button>
                            </div>
                        </div>
                    </div>
                ))}
            </div>

            <button onClick={handleAddItem} className="mt-4 flex items-center text-primary-600 hover:text-primary-700 font-medium">
                <PlusIcon className="w-5 h-5 mr-1" /> Adicionar Novo Item
            </button>
        </div>

        {/* Totals & Notes */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="space-y-6">
                <div className="bg-white p-6 rounded-xl shadow-sm border border-metal-200">
                    <div className="flex justify-between items-center mb-2">
                        <label className="block text-sm font-medium text-metal-600">Notas / Condições (Para o Cliente)</label>
                        <button onClick={handleGenerateNotes} disabled={loadingAi} className="text-purple-600 hover:text-purple-800 text-xs flex items-center font-medium">
                            <SparklesIcon className="w-3 h-3 mr-1" /> {loadingAi ? 'A Gerar...' : 'Sugestão IA'}
                        </button>
                    </div>
                    <textarea value={currentQuote.notes} onChange={(e) => setCurrentQuote({...currentQuote, notes: e.target.value})} className="w-full border border-metal-300 rounded-lg p-2 h-32 text-sm bg-white text-gray-900" placeholder="Prazos de entrega, condições de pagamento, etc." />
                </div>
            </div>

            <div className="bg-white p-6 rounded-xl shadow-sm border border-metal-200 space-y-3 h-fit">
                <div className="flex justify-between text-metal-600">
                    <span>Subtotal</span>
                    <span>{currentQuote.subtotal.toFixed(2)} €</span>
                </div>
                <div className="flex justify-between items-center text-metal-600">
                    <div className="flex items-center">
                        <span>IVA (%)</span>
                        <input type="number" value={currentQuote.taxRate === 0 ? '' : currentQuote.taxRate} onChange={(e) => setCurrentQuote(calculateTotals({...currentQuote, taxRate: Number(e.target.value)}))} className="ml-2 w-16 border border-metal-300 rounded p-1 text-right text-sm bg-white text-gray-900" />
                    </div>
                    <span>{currentQuote.taxAmount.toFixed(2)} €</span>
                </div>
                <div className="border-t border-metal-200 pt-3 flex justify-between text-xl font-bold text-metal-900">
                    <span>Total</span>
                    <span>{currentQuote.total.toFixed(2)} €</span>
                </div>
            </div>
        </div>
      </div>
    );
  }

  // Print View
  if (view === 'print' && currentQuote) {
     const client = clients.find(c => c.id === currentQuote.clientId);
     const upfront = currentQuote.total * ((currentQuote.upfrontPercentage || 50) / 100);
     const remaining = currentQuote.total - upfront;

     return (
        <div className="print-container">
            <div id="print-area" className="print-content relative bg-white">
                {/* Controls (Screen Only) */}
                <div className="fixed top-4 right-4 space-y-2 no-print flex flex-col items-end z-50">
                    <button onClick={handleDownloadPdf} className="bg-green-600 text-white px-6 py-3 rounded-full shadow-lg hover:bg-green-700 mb-2 font-bold flex items-center" title="Guardar PDF">
                        <ArrowDownTrayIcon className="w-6 h-6 mr-2" />
                        Descarregar PDF
                    </button>
                    {client?.email && (
                        <button onClick={handleSendGmail} className="bg-red-500 text-white p-3 rounded-full shadow-lg hover:bg-red-600 mb-2" title="Enviar por Gmail">
                            <EnvelopeIcon className="w-6 h-6" />
                        </button>
                    )}
                    <button onClick={() => setView('edit')} className="bg-gray-600 text-white p-3 rounded-full shadow-lg hover:bg-gray-700" title="Voltar">
                        <ArrowLeftIcon className="w-6 h-6" />
                    </button>
                </div>

                {/* PAGE 1: COVER PAGE ONLY */}
                <div className="h-[297mm] flex flex-col relative">

                    {/* LEFT HEADER: Logo + Company Info + Quote Info */}
                    <div className="absolute top-[15mm] left-[15mm] w-[90mm]">
                        {/* 1. Logo */}
                         <div className="mb-4">
                             {companySettings.logo && (
                                <img src={companySettings.logo} alt="Logo" className="h-20 w-auto object-contain" />
                            )}
                         </div>

                        {/* 2. Company Info */}
                         <div className="text-sm text-metal-600 mb-6">
                                <h1 className="font-bold text-metal-900 uppercase text-lg mb-1">{companySettings.name}</h1>
                                <p>{companySettings.address}</p>
                                <p>{companySettings.postalCode} {companySettings.city}</p>
                                <p>Tel: {companySettings.phone}</p>
                                <p>Email: {companySettings.email}</p>
                                <p>NIF: {companySettings.nif}</p>
                         </div>

                         {/* 3. Quote Meta Info */}
                         <div className="mt-4 border-t border-metal-200 pt-4">
                            <h2 className="text-xl font-light text-metal-500 mb-2 uppercase">Orçamento</h2>
                            <div className="text-lg font-bold text-metal-900">Nº {currentQuote.number.toString().padStart(4, '0')}</div>
                            <div className="text-sm text-metal-600 mt-2">
                                <span className="font-semibold block">Data:</span> {new Date(currentQuote.date).toLocaleDateString('pt-PT')}
                            </div>
                            <div className="text-sm text-metal-600 mt-1">
                                <span className="font-semibold block">Válido até:</span> {new Date(currentQuote.validUntil).toLocaleDateString('pt-PT')}
                            </div>
                        </div>
                    </div>

                    {/* RIGHT HEADER: Client Info (Window Envelope Position) */}
                    {/* Standard Position: Top ~45mm-50mm, Right side */}
                    <div className="absolute top-[50mm] right-[15mm] w-[85mm] h-[45mm] flex items-center border border-transparent">
                        <div className="w-full p-2">
                            <div className="font-bold text-metal-900 text-lg">{client?.name || 'Cliente Final'}</div>
                            <div className="text-metal-700">{client?.address}</div>
                            <div className="text-metal-700">{client?.postalCode} {client?.city}</div>
                            {client?.nif && <div className="text-metal-600 text-sm mt-1">NIF: {client.nif}</div>}
                        </div>
                    </div>

                    {/* MAIN CONTENT PAGE 1: Starts below headers */}
                    <div className="mt-[110mm] px-[15mm]">

                        {/* Intro Message */}
                        <div className="mb-10">
                             <div className="text-sm text-metal-700 whitespace-pre-line leading-relaxed italic">
                                {companySettings.quoteIntroText || 'Estimado cliente, segue a nossa proposta...'}
                            </div>
                        </div>

                        {/* Financial Summary Box */}
                        <div className="mb-8">
                            <div className="border border-metal-800 rounded-lg p-6 bg-gray-50 max-w-xl mx-auto">
                                <h3 className="text-sm font-bold uppercase text-metal-500 mb-4 border-b border-metal-300 pb-2 text-center">Resumo da Proposta</h3>
                                <div className="flex justify-between items-center mb-2 text-lg">
                                    <span>Total Ilíquido</span>
                                    <span>{currentQuote.subtotal.toFixed(2)} €</span>
                                </div>
                                <div className="flex justify-between items-center mb-4 text-lg">
                                    <span>IVA ({currentQuote.taxRate}%)</span>
                                    <span>{currentQuote.taxAmount.toFixed(2)} €</span>
                                </div>
                                <div className="flex justify-between items-center pt-4 border-t-2 border-metal-800 text-3xl font-bold text-metal-900">
                                    <span>Total Geral</span>
                                    <span>{currentQuote.total.toFixed(2)} €</span>
                                </div>
                            </div>
                        </div>

                        {/* General Conditions & Payment Terms */}
                        <div className="grid grid-cols-1 gap-6">
                            {(currentQuote.enableUpfrontPayment ?? true) && (
                                <div>
                                    <h4 className="text-xs font-bold uppercase text-blue-800 mb-2">Condições de Pagamento</h4>
                                    <div className="bg-blue-50 p-3 rounded border border-blue-100 text-sm">
                                        <div className="flex justify-between mb-1">
                                            <span>Adjudicação ({currentQuote.upfrontPercentage || 50}%)</span>
                                            <span className="font-bold">{upfront.toFixed(2)} €</span>
                                        </div>
                                        <div className="flex justify-between">
                                            <span>Final de Obra</span>
                                            <span className="font-bold">{remaining.toFixed(2)} €</span>
                                        </div>
                                    </div>
                                </div>
                            )}

                            <div>
                                <h3 className="text-sm font-bold uppercase text-metal-400 mb-2">Condições Gerais de Venda</h3>
                                <div className="text-xs text-metal-600 whitespace-pre-line leading-relaxed text-justify">
                                    {companySettings.generalConditions || 'Condições gerais não definidas nas configurações.'}
                                </div>
                            </div>
                        </div>
                    </div>

                    {/* Footer Page 1 */}
                    <div className="absolute bottom-[10mm] left-0 right-0 text-center text-xs text-metal-400 px-12">
                        {companySettings.quoteFooterText}
                    </div>
                </div>

                {/* Force Page Break */}
                <div className="html2pdf__page-break"></div>

                {/* PAGE 2+: DETAILS TABLE */}
                <div id="page2-start" className="pt-10 px-[15mm] page-break">

                    <div className="mb-6 border-b border-metal-300 pb-2 flex justify-between items-end">
                        <h2 className="text-xl font-bold text-metal-800">
                            Descrição Detalhada
                        </h2>
                        <span className="text-sm text-metal-500">Orçamento Nº {currentQuote.number}</span>
                    </div>

                    {/* Table Optimized: Image Left, Text Right */}
                    <table className="w-full mb-8 border-collapse">
                        <thead className="border-b-2 border-metal-800 bg-gray-50">
                            <tr className="text-left text-sm font-bold uppercase text-metal-900">
                                <th className="py-2 pl-2 w-32">Imagem</th>
                                <th className="py-2 pl-4">Descrição</th>
                                <th className="py-2 text-center w-24">Qtd</th>
                                <th className="py-2 text-right w-24">Unitário</th>
                                <th className="py-2 text-right w-24 pr-2">Total</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-metal-200">
                            {currentQuote.items.map(item => (
                                <tr key={item.id} className="break-inside-avoid">
                                    {/* Column 1: Image */}
                                    <td className="py-4 pl-2 align-top">
                                         {item.image ? (
                                            <div className="w-28 h-28 border border-gray-200 bg-white rounded p-1 flex items-center justify-center">
                                                <img src={item.image} alt="Item" className="max-w-full max-h-full object-contain" />
                                            </div>
                                        ) : (
                                            <div className="w-28 h-28 bg-gray-50 rounded flex items-center justify-center text-gray-300 text-xs">Sem Imagem</div>
                                        )}
                                    </td>

                                    {/* Column 2: Description */}
                                    <td className="py-4 pl-4 align-top">
                                        <div className="font-bold text-metal-800 text-base">{item.name}</div>
                                        <div className="text-sm text-metal-600 mt-1 whitespace-pre-line">{item.description}</div>
                                        {item.details && item.details.length > 0 && (
                                            <div className="mt-2 text-xs text-metal-500 bg-metal-50 p-2 rounded inline-block">
                                                {item.details.map((d, idx) => (
                                                    <div key={d.id} className="mr-3 inline-block">
                                                        <span className="font-semibold">{d.label}:</span> {d.value} 
                                                        {d.price && d.price > 0 && <span className="text-metal-400 ml-1">(+{d.price.toFixed(2)}€)</span>}
                                                    </div>
                                                ))}
                                            </div>
                                        )}
                                    </td>

                                    {/* Other Columns */}
                                    <td className="py-4 text-center align-top font-medium text-metal-700">{item.quantity} {item.unit}</td>
                                    <td className="py-4 text-right align-top text-metal-700">{item.unitPrice.toFixed(2)} €</td>
                                    <td className="py-4 text-right align-top font-bold text-metal-900 pr-2">{item.total.toFixed(2)} €</td>
                                </tr>
                            ))}
                        </tbody>
                    </table>

                    {/* Specific Notes for these items if any */}
                    {currentQuote.notes && (
                        <div className="bg-metal-50 p-4 rounded-lg border border-metal-100 mb-8 break-inside-avoid">
                            <h4 className="text-xs font-bold uppercase text-metal-500 mb-2">Notas Técnicas / Observações</h4>
                            <p className="text-sm text-metal-700 whitespace-pre-line">{currentQuote.notes}</p>
                        </div>
                    )}

                    {/* Small Repeater of Total at end of items (Optional but helpful) */}
                    <div className="text-right border-t border-metal-200 pt-4 mb-8 break-inside-avoid">
                         <span className="text-sm text-metal-500 mr-4">Total Geral:</span>
                         <span className="text-xl font-bold text-metal-900">{currentQuote.total.toFixed(2)} €</span>
                    </div>

                    <div className="text-center text-xs text-metal-400 mt-12 pt-4 border-t border-metal-100">
                        {companySettings.quoteFooterText}
                    </div>
                </div>
            </div>
        </div>
     )
  }

  return null;
};

export default QuoteManager;

import React, { useState, useRef } from 'react';
import { 
  PlusIcon, 
  PrinterIcon, 
  TrashIcon, 
  ArrowLeftIcon, 
  SparklesIcon, 
  CameraIcon,
  MagnifyingGlassIcon,
  XMarkIcon,
  EnvelopeIcon,
  ArrowDownTrayIcon,
  CheckBadgeIcon
} from '@heroicons/react/24/outline';
import { Quote, Client, Article, QuoteItem, QuoteStatus, UnitType, CompanySettings, QuoteItemDetail } from '../types';
import { generateQuoteNotes } from '../services/geminiService';
import SchematicDesigner from './SchematicDesigner';

declare const html2pdf: any;

interface QuoteManagerProps {
  quotes: Quote[];
  clients: Client[];
  articles: Article[];
  nextQuoteNumber: number;
  companySettings: CompanySettings;
  onSaveQuote: (quote: Quote) => void;
  onDeleteQuote: (id: string) => void;
}

const QuoteManager: React.FC<QuoteManagerProps> = ({ 
  quotes, clients, articles, nextQuoteNumber, companySettings, onSaveQuote, onDeleteQuote 
}) => {
  const [view, setView] = useState<'list' | 'edit' | 'print'>('list');
  const [currentQuote, setCurrentQuote] = useState<Quote | null>(null);
  const [loadingAi, setLoadingAi] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [activeItemIdForUpload, setActiveItemIdForUpload] = useState<string | null>(null);
  const [showSchematicDesigner, setShowSchematicDesigner] = useState(false);

  // List Filters
  const [filterClient, setFilterClient] = useState('');
  const [filterDateStart, setFilterDateStart] = useState('');
  const [filterDateEnd, setFilterDateEnd] = useState('');

  // Client Search State (Edit Mode)
  const [clientSearchTerm, setClientSearchTerm] = useState('');
  const [showClientResults, setShowClientResults] = useState(false);
  const [showClientListModal, setShowClientListModal] = useState(false);

  // Helper to init a new quote
  const initNewQuote = () => {
    const newQuote: Quote = {
      id: crypto.randomUUID(),
      clientId: '',
      number: nextQuoteNumber,
      date: new Date().toISOString().split('T')[0],
      validUntil: new Date(Date.now() + 15 * 24 * 60 * 60 * 1000).toISOString().split('T')[0],
      items: [],
      subtotal: 0,
      taxRate: 23,
      taxAmount: 0,
      total: 0,
      status: QuoteStatus.DRAFT,
      notes: '',
      internalNotes: '',
      upfrontPercentage: 50, // Default 50%
      enableUpfrontPayment: true
    };
    setCurrentQuote(newQuote);
    setClientSearchTerm('');
    setView('edit');
  };

  const calculateTotals = (quote: Quote): Quote => {
    const updatedItems = quote.items.map(item => {
        const detailsSum = item.details?.reduce((acc, d) => acc + (d.price || 0), 0) || 0;
        const total = item.quantity * (item.unitPrice + detailsSum);
        return { ...item, total };
    });

    const subtotal = updatedItems.reduce((sum, item) => sum + item.total, 0);
    const taxAmount = subtotal * (quote.taxRate / 100);
    const total = subtotal + taxAmount;
    return { ...quote, items: updatedItems, subtotal, taxAmount, total };
  };

  const handleAddItem = () => {
    if (!currentQuote) return;
    const newItem: QuoteItem = {
      id: crypto.randomUUID(),
      articleId: '',
      name: '',
      quantity: 1,
      unitPrice: 0,
      unit: UnitType.UN,
      total: 0,
      details: []
    };
    setCurrentQuote({ ...currentQuote, items: [...currentQuote.items, newItem] });
  };

  const handleItemChange = (itemId: string, field: keyof QuoteItem, value: any) => {
    if (!currentQuote) return;
    const updatedItems = currentQuote.items.map(item => {
      if (item.id !== itemId) return item;

      const updatedItem = { ...item, [field]: value };

      // Auto-fill from article
      if (field === 'articleId') {
        const article = articles.find(a => a.id === value);
        if (article) {
          updatedItem.name = article.name;
          updatedItem.description = article.description;
          updatedItem.unitPrice = article.price;
          updatedItem.unit = article.unit;
          // If article has image and item doesn't, use article image
          if(article.image && !updatedItem.image) {
              updatedItem.image = article.image;
          }
        }
      }

      return updatedItem;
    });

    setCurrentQuote(calculateTotals({ ...currentQuote, items: updatedItems }));
  };

  const handleDeleteItem = (itemId: string) => {
    if (!currentQuote) return;
    const updatedItems = currentQuote.items.filter(i => i.id !== itemId);
    setCurrentQuote(calculateTotals({ ...currentQuote, items: updatedItems }));
  };

  // --- ITEM DETAILS / OPTIONS LOGIC ---
  const handleAddDetail = (itemId: string) => {
    if (!currentQuote) return;
    const updatedItems = currentQuote.items.map(item => {
        if (item.id === itemId) {
            const newDetail: QuoteItemDetail = { id: crypto.randomUUID(), label: '', value: '', price: 0 };
            return { ...item, details: [...(item.details || []), newDetail] };
        }
        return item;
    });
    setCurrentQuote(calculateTotals({ ...currentQuote, items: updatedItems }));
  };

  const handleUpdateDetail = (itemId: string, detailId: string, field: 'label' | 'value' | 'price', val: any) => {
    if (!currentQuote) return;
    const updatedItems = currentQuote.items.map(item => {
        if (item.id === itemId) {
            const updatedDetails = (item.details || []).map(d => 
                d.id === detailId ? { ...d, [field]: val } : d
            );
            return { ...item, details: updatedDetails };
        }
        return item;
    });
    setCurrentQuote(calculateTotals({ ...currentQuote, items: updatedItems }));
  };

  const handleDeleteDetail = (itemId: string, detailId: string) => {
    if (!currentQuote) return;
    const updatedItems = currentQuote.items.map(item => {
        if (item.id === itemId) {
            return { ...item, details: (item.details || []).filter(d => d.id !== detailId) };
        }
        return item;
    });
    setCurrentQuote(calculateTotals({ ...currentQuote, items: updatedItems }));
  };

  // Image Upload Logic
  const triggerImageUpload = (itemId: string) => {
    setActiveItemIdForUpload(itemId);
    if (fileInputRef.current) {
        fileInputRef.current.click();
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0] && activeItemIdForUpload) {
        const file = e.target.files[0];
        const reader = new FileReader();
        reader.onload = (event) => {
             handleItemChange(activeItemIdForUpload, 'image', event.target?.result as string);
             setActiveItemIdForUpload(null);
        };
        reader.readAsDataURL(file);
    }
    e.target.value = '';
  };

  const handleSaveSchematic = (imgData: string) => {
      if (activeItemIdForUpload) {
          handleItemChange(activeItemIdForUpload, 'image', imgData);
          setShowSchematicDesigner(false);
          setActiveItemIdForUpload(null);
      }
  };

  const handleGenerateNotes = async () => {
    if (!currentQuote || currentQuote.items.length === 0) return;
    setLoadingAi(true);
    const itemNames = currentQuote.items.map(i => i.name);
    const notes = await generateQuoteNotes(itemNames);
    setCurrentQuote(prev => prev ? { ...prev, notes } : null);
    setLoadingAi(false);
  };

  const handleDownloadPdf = () => {
      // Switch to print view temporarily if not already
      const previousView = view;
      if (view !== 'print') {
          setView('print');
          // Wait for render
          setTimeout(() => executePdfGeneration(previousView), 500);
      } else {
          executePdfGeneration(previousView);
      }
  };

  const executePdfGeneration = (returnView: 'list' | 'edit' | 'print') => {
      const element = document.getElementById('print-area');
      if (!element) return;

      const opt = {
          margin: 0,
          filename: `Orcamento_${currentQuote?.number}.pdf`,
          image: { type: 'jpeg', quality: 0.98 },
          html2canvas: { scale: 2, useCORS: true, scrollY: 0 },
          jsPDF: { unit: 'mm', format: 'a4', orientation: 'portrait' },
          pagebreak: { mode: ['css', 'legacy'] }
      };

      // Gerar PDF e adicionar numeração de páginas
      // @ts-ignore
      html2pdf().from(element).set(opt).toPdf().get('pdf').then(function (pdf) {
        var totalPages = pdf.internal.getNumberOfPages();
        for (let i = 1; i <= totalPages; i++) {
            pdf.setPage(i);
            pdf.setFontSize(8);
            pdf.setTextColor(150);
            // Rodapé: Página X de Y
            pdf.text('Página ' + i + ' de ' + totalPages, pdf.internal.pageSize.getWidth() - 30, pdf.internal.pageSize.getHeight() - 10);
        }
      }).save().then(() => {
          if (returnView !== 'print') {
              setView(returnView);
          }
      });
  };

  const handleSendGmail = () => {
    if (!currentQuote) return;
    const client = clients.find(c => c.id === currentQuote.clientId);
    if (!client || !client.email) {
        alert("Cliente não tem email definido ou selecionado.");
        return;
    }

    const subject = encodeURIComponent(`Orçamento Nº ${currentQuote.number} - ${companySettings.name}`);
    const body = encodeURIComponent(
`Olá ${client.name},

Segue em anexo o Orçamento Nº ${currentQuote.number}.

Valor Total: ${currentQuote.total.toFixed(2)} €
Validade: ${new Date(currentQuote.validUntil).toLocaleDateString('pt-PT')}

Melhores cumprimentos,
${companySettings.name}`
    );

    alert("O PDF será descarregado. Por favor anexe-o manualmente no email que irá abrir.");
    handleDownloadPdf();
    setTimeout(() => {
        window.open(`https://mail.google.com/mail/?view=cm&fs=1&to=${client.email}&su=${subject}&body=${body}`, '_blank');
    }, 1500);
  };

  // --- CLIENT SEARCH & FILTER LOGIC ---
  const filteredClients = clients.filter(c => 
    c.name.toLowerCase().includes(clientSearchTerm.toLowerCase()) || 
    c.nif.includes(clientSearchTerm)
  );

  const selectClient = (client: Client) => {
    if (currentQuote) {
        setCurrentQuote({ ...currentQuote, clientId: client.id });
        setClientSearchTerm('');
        setShowClientResults(false);
        setShowClientListModal(false);
    }
  };

  const filteredQuotes = quotes.filter(q => {
      const client = clients.find(c => c.id === q.clientId);
      const matchesClient = filterClient === '' || client?.name.toLowerCase().includes(filterClient.toLowerCase());
      const matchesDateStart = filterDateStart === '' || q.date >= filterDateStart;
      const matchesDateEnd = filterDateEnd === '' || q.date <= filterDateEnd;
      return matchesClient && matchesDateStart && matchesDateEnd;
  });

  const getStatusColor = (status: QuoteStatus) => {
      switch(status) {
          case QuoteStatus.ACCEPTED: return 'bg-green-100 text-green-700';
          case QuoteStatus.SENT: return 'bg-blue-100 text-blue-700';
          case QuoteStatus.REJECTED: return 'bg-red-100 text-red-700';
          case QuoteStatus.CLOSED: return 'bg-gray-800 text-white';
          default: return 'bg-gray-100 text-gray-700';
      }
  };

  // --- RENDERERS ---

  if (view === 'list') {
    return (
      <div className="max-w-6xl mx-auto">
        <div className="flex justify-between items-center mb-6">
          <h2 className="text-2xl font-bold text-metal-800">Orçamentos</h2>
          <button onClick={initNewQuote} className="bg-primary-600 hover:bg-primary-700 text-white px-4 py-2 rounded-lg flex items-center shadow-sm">
            <PlusIcon className="w-5 h-5 mr-2" />
            Criar Orçamento
          </button>
        </div>

        {/* Filters */}
        <div className="bg-white p-4 rounded-xl shadow-sm border border-metal-200 mb-6 flex flex-wrap gap-4 items-end">
            <div className="flex-1 min-w-[200px]">
                <label className="text-xs text-metal-500 mb-1 block">Filtrar Cliente</label>
                <div className="relative">
                    <MagnifyingGlassIcon className="absolute left-2 top-2.5 w-4 h-4 text-gray-400" />
                    <input type="text" value={filterClient} onChange={e => setFilterClient(e.target.value)} className="w-full pl-8 p-2 border border-gray-300 rounded-lg text-sm bg-white text-gray-900" placeholder="Nome..." />
                </div>
            </div>
            <div>
                <label className="text-xs text-metal-500 mb-1 block">De</label>
                <input type="date" value={filterDateStart} onChange={e => setFilterDateStart(e.target.value)} className="p-2 border border-gray-300 rounded-lg text-sm bg-white text-gray-900" />
            </div>
            <div>
                <label className="text-xs text-metal-500 mb-1 block">Até</label>
                <input type="date" value={filterDateEnd} onChange={e => setFilterDateEnd(e.target.value)} className="p-2 border border-gray-300 rounded-lg text-sm bg-white text-gray-900" />
            </div>
            <button onClick={() => {setFilterClient(''); setFilterDateStart(''); setFilterDateEnd('')}} className="p-2 text-metal-500 hover:text-metal-800" title="Limpar Filtros">
                <XMarkIcon className="w-5 h-5" />
            </button>
        </div>

        <div className="bg-white rounded-xl shadow-sm border border-metal-200 overflow-hidden">
          <table className="w-full text-left">
            <thead className="bg-metal-50 text-metal-600 text-sm font-semibold">
              <tr>
                <th className="p-4">Nº</th>
                <th className="p-4">Cliente</th>
                <th className="p-4">Data</th>
                <th className="p-4">Total</th>
                <th className="p-4">Estado</th>
                <th className="p-4 text-center">Ações</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-metal-100">
              {filteredQuotes.length === 0 && (
                <tr><td colSpan={6} className="p-8 text-center text-metal-400">Sem orçamentos encontrados.</td></tr>
              )}
              {filteredQuotes.map(quote => {
                const client = clients.find(c => c.id === quote.clientId);
                return (
                  <tr key={quote.id} className="hover:bg-metal-50 cursor-pointer" onClick={() => { setCurrentQuote(quote); setView('edit'); }}>
                    <td className="p-4 font-mono text-metal-600">#{quote.number.toString().padStart(4, '0')}</td>
                    <td className="p-4 font-medium text-metal-900">{client?.name || 'Cliente Removido'}</td>
                    <td className="p-4 text-metal-600">{new Date(quote.date).toLocaleDateString('pt-PT')}</td>
                    <td className="p-4 font-bold text-metal-900">{quote.total.toFixed(2)} €</td>
                    <td className="p-4">
                      <span className={`px-2 py-1 rounded-full text-xs font-medium ${getStatusColor(quote.status)}`}>
                        {quote.status}
                      </span>
                    </td>
                    <td className="p-4 text-center">
                      <button 
                        onClick={(e) => { e.stopPropagation(); onDeleteQuote(quote.id); }}
                        className="p-2 text-red-500 hover:bg-red-50 rounded"
                      >
                        <TrashIcon className="w-4 h-4" />
                      </button>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </div>
    );
  }

  if (view === 'edit' && currentQuote) {
    const selectedClient = clients.find(c => c.id === currentQuote.clientId);

    return (
      <div className="max-w-5xl mx-auto space-y-6 pb-20">
        {/* Hidden Inputs/Modals */}
        <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleFileChange} />
        {showSchematicDesigner && (
            <SchematicDesigner 
                onSave={handleSaveSchematic} 
                onCancel={() => { setShowSchematicDesigner(false); setActiveItemIdForUpload(null); }} 
            />
        )}

        {/* Client Selection Modal */}
        {showClientListModal && (
            <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4">
                <div className="bg-white rounded-xl shadow-2xl w-full max-w-2xl max-h-[80vh] flex flex-col">
                    <div className="p-4 border-b border-metal-200 flex justify-between items-center">
                        <h3 className="text-lg font-bold text-metal-800">Selecionar Cliente</h3>
                        <button onClick={() => setShowClientListModal(false)} className="text-metal-400 hover:text-metal-600"><XMarkIcon className="w-6 h-6" /></button>
                    </div>
                    <div className="p-4 border-b border-metal-100">
                        <input 
                            type="text" autoFocus placeholder="Filtrar lista de clientes..." className="w-full p-2 border border-metal-300 rounded-lg text-sm bg-white text-gray-900"
                            value={clientSearchTerm} onChange={(e) => setClientSearchTerm(e.target.value)}
                        />
                    </div>
                    <div className="overflow-y-auto flex-1 p-2">
                        {filteredClients.map(client => (
                            <div key={client.id} onClick={() => selectClient(client)} className="p-3 hover:bg-gray-50 cursor-pointer border-b border-gray-100 flex justify-between">
                                <div>
                                    <div className="font-medium text-gray-900">{client.name}</div>
                                    <div className="text-xs text-gray-500">{client.nif}</div>
                                </div>
                                <button className="px-3 py-1 bg-primary-100 text-primary-700 rounded text-xs">Selecionar</button>
                            </div>
                        ))}
                    </div>
                </div>
            </div>
        )}

        <div className="flex items-center justify-between">
            <button onClick={() => setView('list')} className="flex items-center text-metal-500 hover:text-metal-800">
                <ArrowLeftIcon className="w-4 h-4 mr-1" /> Voltar
            </button>
            <div className="flex gap-2">
                 <button onClick={handleDownloadPdf} className="flex items-center px-3 py-2 bg-green-50 border border-green-200 text-green-700 rounded-lg hover:bg-green-100 text-sm font-medium">
                    <ArrowDownTrayIcon className="w-4 h-4 mr-2" /> Guardar PDF
                 </button>

                 {/* Status Selector */}
                 <div className="relative">
                    <select 
                        value={currentQuote.status}
                        onChange={(e) => setCurrentQuote({...currentQuote, status: e.target.value as QuoteStatus})}
                        className={`appearance-none px-3 py-2 pr-8 border rounded-lg text-sm font-medium ${getStatusColor(currentQuote.status)}`}
                    >
                        {Object.values(QuoteStatus).map(status => (
                            <option key={status} value={status}>{status}</option>
                        ))}
                    </select>
                    <ArrowDownTrayIcon className="w-4 h-4 absolute right-2 top-2.5 opacity-50 pointer-events-none" />
                 </div>

                 <button onClick={handleSendGmail} className="flex items-center px-3 py-2 border border-red-200 text-red-600 rounded-lg hover:bg-red-50 text-sm font-medium">
                    <EnvelopeIcon className="w-4 h-4 mr-1" /> Email
                </button>
                 <button onClick={() => { setView('print'); }} className="flex items-center px-4 py-2 border border-metal-300 rounded-lg bg-white hover:bg-metal-50 text-metal-700">
                    <PrinterIcon className="w-4 h-4 mr-2" /> Pré-visualizar
                </button>
                <button onClick={() => { onSaveQuote(currentQuote); setView('list'); }} className="bg-primary-600 hover:bg-primary-700 text-white px-6 py-2 rounded-lg font-medium shadow-sm">
                    Guardar
                </button>
            </div>
        </div>

        {/* Header Info */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-metal-200 grid grid-cols-1 md:grid-cols-3 gap-6">
           {/* Client Search Section */}
           <div>
             <label className="block text-sm font-medium text-metal-600 mb-1">Cliente</label>
             {selectedClient ? (
                 <div className="flex items-center justify-between p-2 border border-blue-200 bg-blue-50 rounded-lg">
                     <div>
                         <div className="font-bold text-blue-900">{selectedClient.name}</div>
                         <div className="text-xs text-blue-700">NIF: {selectedClient.nif || 'N/A'}</div>
                     </div>
                     <button onClick={() => setCurrentQuote({...currentQuote, clientId: ''})} className="text-blue-500 hover:text-blue-700 p-1"><XMarkIcon className="w-5 h-5" /></button>
                 </div>
             ) : (
                 <div className="flex gap-2">
                    <button onClick={() => setShowClientListModal(true)} className="flex-1 text-left px-3 py-2 border border-metal-300 rounded-lg bg-white text-gray-500 text-sm hover:bg-gray-50">Selecionar Cliente...</button>
                 </div>
             )}
           </div>

           <div>
             <label className="block text-sm font-medium text-metal-600 mb-1">Validade (Data)</label>
             <input type="date" value={currentQuote.validUntil} onChange={(e) => setCurrentQuote({...currentQuote, validUntil: e.target.value})} className="w-full border border-metal-300 rounded-lg p-2 bg-white text-gray-900" />
           </div>

           <div>
             <label className="block text-sm font-medium text-metal-600 mb-1">Condição de Pagamento</label>
             <div className="flex items-center gap-2 mb-2">
                <input 
                    type="checkbox" 
                    checked={currentQuote.enableUpfrontPayment ?? true}
                    onChange={(e) => setCurrentQuote({...currentQuote, enableUpfrontPayment: e.target.checked})}
                    className="w-4 h-4 text-primary-600"
                />
                <span className="text-sm">Ativar Adjudicação (%)</span>
             </div>
             {(currentQuote.enableUpfrontPayment ?? true) && (
                 <div className="flex items-center">
                     <input 
                        type="number" min="0" max="100" 
                        value={currentQuote.upfrontPercentage ?? 50} 
                        onChange={(e) => setCurrentQuote({...currentQuote, upfrontPercentage: Number(e.target.value)})} 
                        className="w-20 border border-metal-300 rounded-lg p-2 bg-white text-gray-900 text-right mr-2" 
                     />
                     <span className="text-sm text-metal-600">%</span>
                 </div>
             )}
           </div>
        </div>

        {/* Items */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-metal-200">
            <h3 className="text-lg font-bold text-metal-800 mb-4">Itens do Orçamento</h3>
            <div className="space-y-4">
                {currentQuote.items.map((item, index) => (
                    <div key={item.id} className="p-4 bg-metal-50 rounded-lg border border-metal-100 animate-fade-in">
                        <div className="flex flex-col md:flex-row gap-4 items-start">
                            {/* Image Uploader */}
                            <div className="flex-shrink-0 flex flex-col gap-2">
                                <div 
                                    className="w-24 h-24 rounded-lg border-2 border-dashed border-metal-300 bg-white flex flex-col items-center justify-center overflow-hidden relative"
                                >
                                    {item.image ? (
                                        <img src={item.image} alt="Preview" className="w-full h-full object-contain" />
                                    ) : (
                                        <CameraIcon className="w-6 h-6 text-metal-300" />
                                    )}
                                </div>
                                <div className="flex gap-1">
                                    <button onClick={() => triggerImageUpload(item.id)} className="text-[10px] bg-white border p-1 rounded hover:bg-gray-50 flex-1">Foto</button>
                                    <button onClick={() => { setActiveItemIdForUpload(item.id); setShowSchematicDesigner(true); }} className="text-[10px] bg-white border p-1 rounded hover:bg-gray-50 flex-1">Desenho</button>
                                </div>
                            </div>

                            {/* Main Inputs */}
                            <div className="flex-1 space-y-2 w-full">
                                <div className="flex gap-2">
                                    <select 
                                        value={item.articleId}
                                        onChange={(e) => handleItemChange(item.id, 'articleId', e.target.value)}
                                        className="w-1/3 border border-metal-300 rounded-lg p-2 text-sm bg-white text-gray-900"
                                    >
                                        <option value="">Personalizado</option>
                                        {articles.map(a => <option key={a.id} value={a.id}>{a.name}</option>)}
                                    </select>
                                    <input 
                                        type="text" 
                                        placeholder="Nome do Item"
                                        value={item.name}
                                        onChange={(e) => handleItemChange(item.id, 'name', e.target.value)}
                                        className="flex-1 border border-metal-300 rounded-lg p-2 text-sm font-medium bg-white text-gray-900"
                                    />
                                </div>
                                <textarea 
                                    placeholder="Descrição detalhada..."
                                    value={item.description || ''}
                                    onChange={(e) => handleItemChange(item.id, 'description', e.target.value)}
                                    className="w-full border border-metal-300 rounded-lg p-2 text-sm h-16 resize-none bg-white text-gray-900"
                                />
                            </div>

                            {/* Qty & Price */}
                            <div className="flex gap-2 w-full md:w-auto items-start">
                                <div className="w-20">
                                    <label className="text-xs text-metal-500">Qtd</label>
                                    <input 
                                        type="number"
                                        min="1"
                                        value={item.quantity === 0 ? '' : item.quantity}
                                        onChange={(e) => handleItemChange(item.id, 'quantity', Number(e.target.value))}
                                        className="w-full border border-metal-300 rounded-lg p-2 text-sm bg-white text-gray-900"
                                    />
                                </div>
                                <div className="w-24">
                                    <label className="text-xs text-metal-500">Preço Unit.</label>
                                    <input 
                                        type="number"
                                        min="0"
                                        step="0.01"
                                        value={item.unitPrice === 0 ? '' : item.unitPrice}
                                        onChange={(e) => handleItemChange(item.id, 'unitPrice', Number(e.target.value))}
                                        className="w-full border border-metal-300 rounded-lg p-2 text-sm bg-white text-gray-900"
                                    />
                                </div>
                                <div className="w-24">
                                    <label className="text-xs text-metal-500">Total</label>
                                    <div className="p-2 bg-metal-100 rounded-lg text-sm font-bold text-right text-gray-900">
                                        {item.total.toFixed(2)}€
                                    </div>
                                </div>
                                <button 
                                    onClick={() => handleDeleteItem(item.id)}
                                    className="mt-5 text-red-500 hover:bg-red-50 p-2 rounded"
                                >
                                    <TrashIcon className="w-5 h-5" />
                                </button>
                            </div>
                        </div>

                        {/* PRODUCT OPTIONS / DETAILS */}
                        <div className="mt-4 pl-0 md:pl-28">
                            <h4 className="text-xs font-bold text-gray-500 uppercase mb-2">Acabamentos, Extras e Opções</h4>
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-2">
                                {item.details?.map((detail) => (
                                    <div key={detail.id} className="flex gap-2 items-center">
                                        <input type="text" placeholder="Ex: Cor" value={detail.label} onChange={(e) => handleUpdateDetail(item.id, detail.id, 'label', e.target.value)} className="w-1/4 p-1.5 text-xs border border-gray-300 rounded bg-white" />
                                        <input type="text" placeholder="Ex: Cinza" value={detail.value} onChange={(e) => handleUpdateDetail(item.id, detail.id, 'value', e.target.value)} className="w-1/3 p-1.5 text-xs border border-gray-300 rounded bg-white" />
                                        <div className="flex-1 flex items-center relative">
                                            <span className="absolute left-2 text-xs text-gray-500">+</span>
                                            <input type="number" placeholder="0.00" value={detail.price === 0 ? '' : detail.price} onChange={(e) => handleUpdateDetail(item.id, detail.id, 'price', Number(e.target.value))} className="w-full p-1.5 pl-4 text-xs border border-gray-300 rounded bg-white" />
                                            <span className="absolute right-2 text-xs text-gray-500">€</span>
                                        </div>
                                        <button onClick={() => handleDeleteDetail(item.id, detail.id)} className="text-red-400 hover:text-red-600"><XMarkIcon className="w-4 h-4" /></button>
                                    </div>
                                ))}
                                <button onClick={() => handleAddDetail(item.id)} className="flex items-center text-xs text-blue-600 hover:text-blue-800 font-medium py-1">
                                    <PlusIcon className="w-3 h-3 mr-1" /> Adicionar Opção
                                </button>
                            </div>
                        </div>
                    </div>
                ))}
            </div>

            <button onClick={handleAddItem} className="mt-4 flex items-center text-primary-600 hover:text-primary-700 font-medium">
                <PlusIcon className="w-5 h-5 mr-1" /> Adicionar Novo Item
            </button>
        </div>

        {/* Totals & Notes */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="space-y-6">
                <div className="bg-white p-6 rounded-xl shadow-sm border border-metal-200">
                    <div className="flex justify-between items-center mb-2">
                        <label className="block text-sm font-medium text-metal-600">Notas / Condições (Para o Cliente)</label>
                        <button onClick={handleGenerateNotes} disabled={loadingAi} className="text-purple-600 hover:text-purple-800 text-xs flex items-center font-medium">
                            <SparklesIcon className="w-3 h-3 mr-1" /> {loadingAi ? 'A Gerar...' : 'Sugestão IA'}
                        </button>
                    </div>
                    <textarea value={currentQuote.notes} onChange={(e) => setCurrentQuote({...currentQuote, notes: e.target.value})} className="w-full border border-metal-300 rounded-lg p-2 h-32 text-sm bg-white text-gray-900" placeholder="Prazos de entrega, condições de pagamento, etc." />
                </div>
            </div>

            <div className="bg-white p-6 rounded-xl shadow-sm border border-metal-200 space-y-3 h-fit">
                <div className="flex justify-between text-metal-600">
                    <span>Subtotal</span>
                    <span>{currentQuote.subtotal.toFixed(2)} €</span>
                </div>
                <div className="flex justify-between items-center text-metal-600">
                    <div className="flex items-center">
                        <span>IVA (%)</span>
                        <input type="number" value={currentQuote.taxRate === 0 ? '' : currentQuote.taxRate} onChange={(e) => setCurrentQuote(calculateTotals({...currentQuote, taxRate: Number(e.target.value)}))} className="ml-2 w-16 border border-metal-300 rounded p-1 text-right text-sm bg-white text-gray-900" />
                    </div>
                    <span>{currentQuote.taxAmount.toFixed(2)} €</span>
                </div>
                <div className="border-t border-metal-200 pt-3 flex justify-between text-xl font-bold text-metal-900">
                    <span>Total</span>
                    <span>{currentQuote.total.toFixed(2)} €</span>
                </div>
            </div>
        </div>
      </div>
    );
  }

  // Print View
  if (view === 'print' && currentQuote) {
     const client = clients.find(c => c.id === currentQuote.clientId);
     const upfront = currentQuote.total * ((currentQuote.upfrontPercentage || 50) / 100);
     const remaining = currentQuote.total - upfront;

     return (
        <div className="print-container">
            <div id="print-area" className="print-content relative bg-white">
                {/* Controls (Screen Only) */}
                <div className="fixed top-4 right-4 space-y-2 no-print flex flex-col items-end z-50">
                    <button onClick={handleDownloadPdf} className="bg-green-600 text-white px-6 py-3 rounded-full shadow-lg hover:bg-green-700 mb-2 font-bold flex items-center" title="Guardar PDF">
                        <ArrowDownTrayIcon className="w-6 h-6 mr-2" />
                        Descarregar PDF
                    </button>
                    {client?.email && (
                        <button onClick={handleSendGmail} className="bg-red-500 text-white p-3 rounded-full shadow-lg hover:bg-red-600 mb-2" title="Enviar por Gmail">
                            <EnvelopeIcon className="w-6 h-6" />
                        </button>
                    )}
                    <button onClick={() => setView('edit')} className="bg-gray-600 text-white p-3 rounded-full shadow-lg hover:bg-gray-700" title="Voltar">
                        <ArrowLeftIcon className="w-6 h-6" />
                    </button>
                </div>

                {/* PAGE 1: COVER PAGE ONLY */}
                {/* Changed h-[297mm] to min-h to prevent cutting off if slightly large, but essentially full page */}
                <div className="min-h-[290mm] flex flex-col relative" style={{ height: '290mm' }}>

                    {/* LEFT HEADER: Logo + Company Info + Quote Info */}
                    <div className="absolute top-[15mm] left-[15mm] w-[90mm]">
                        {/* 1. Logo */}
                         <div className="mb-4">
                             {companySettings.logo && (
                                <img src={companySettings.logo} alt="Logo" className="h-20 w-auto object-contain" />
                            )}
                         </div>

                        {/* 2. Company Info */}
                         <div className="text-sm text-metal-600 mb-6">
                                <h1 className="font-bold text-metal-900 uppercase text-lg mb-1">{companySettings.name}</h1>
                                <p>{companySettings.address}</p>
                                <p>{companySettings.postalCode} {companySettings.city}</p>
                                <p>Tel: {companySettings.phone}</p>
                                <p>Email: {companySettings.email}</p>
                                <p>NIF: {companySettings.nif}</p>
                         </div>

                         {/* 3. Quote Meta Info */}
                         <div className="mt-4 border-t border-metal-200 pt-4">
                            <h2 className="text-xl font-light text-metal-500 mb-2 uppercase">Orçamento</h2>
                            <div className="text-lg font-bold text-metal-900">Nº {currentQuote.number.toString().padStart(4, '0')}</div>
                            <div className="text-sm text-metal-600 mt-2">
                                <span className="font-semibold block">Data:</span> {new Date(currentQuote.date).toLocaleDateString('pt-PT')}
                            </div>
                            <div className="text-sm text-metal-600 mt-1">
                                <span className="font-semibold block">Válido até:</span> {new Date(currentQuote.validUntil).toLocaleDateString('pt-PT')}
                            </div>
                        </div>
                    </div>

                    {/* RIGHT HEADER: Client Info (Window Envelope Position) */}
                    {/* Standard Position: Top ~45mm-50mm, Right side */}
                    <div className="absolute top-[50mm] right-[15mm] w-[85mm] h-[45mm] flex items-center border border-transparent">
                        <div className="w-full p-2">
                            <div className="font-bold text-metal-900 text-lg">{client?.name || 'Cliente Final'}</div>
                            <div className="text-metal-700">{client?.address}</div>
                            <div className="text-metal-700">{client?.postalCode} {client?.city}</div>
                            {client?.nif && <div className="text-metal-600 text-sm mt-1">NIF: {client.nif}</div>}
                        </div>
                    </div>

                    {/* MAIN CONTENT PAGE 1: Starts below headers */}
                    <div className="mt-[110mm] px-[15mm]">

                        {/* Intro Message */}
                        <div className="mb-10">
                             <div className="text-sm text-metal-700 whitespace-pre-line leading-relaxed italic">
                                {companySettings.quoteIntroText || 'Estimado cliente, segue a nossa proposta...'}
                            </div>
                        </div>

                        {/* Financial Summary Box */}
                        <div className="mb-8">
                            <div className="border border-metal-800 rounded-lg p-6 bg-gray-50 max-w-xl mx-auto">
                                <h3 className="text-sm font-bold uppercase text-metal-500 mb-4 border-b border-metal-300 pb-2 text-center">Resumo da Proposta</h3>
                                <div className="flex justify-between items-center mb-2 text-lg">
                                    <span>Total Ilíquido</span>
                                    <span>{currentQuote.subtotal.toFixed(2)} €</span>
                                </div>
                                <div className="flex justify-between items-center mb-4 text-lg">
                                    <span>IVA ({currentQuote.taxRate}%)</span>
                                    <span>{currentQuote.taxAmount.toFixed(2)} €</span>
                                </div>
                                <div className="flex justify-between items-center pt-4 border-t-2 border-metal-800 text-3xl font-bold text-metal-900">
                                    <span>Total Geral</span>
                                    <span>{currentQuote.total.toFixed(2)} €</span>
                                </div>
                            </div>
                        </div>

                        {/* General Conditions & Payment Terms */}
                        <div className="grid grid-cols-1 gap-6">
                            {(currentQuote.enableUpfrontPayment ?? true) && (
                                <div>
                                    <h4 className="text-xs font-bold uppercase text-blue-800 mb-2">Condições de Pagamento</h4>
                                    <div className="bg-blue-50 p-3 rounded border border-blue-100 text-sm">
                                        <div className="flex justify-between mb-1">
                                            <span>Adjudicação ({currentQuote.upfrontPercentage || 50}%)</span>
                                            <span className="font-bold">{upfront.toFixed(2)} €</span>
                                        </div>
                                        <div className="flex justify-between">
                                            <span>Final de Obra</span>
                                            <span className="font-bold">{remaining.toFixed(2)} €</span>
                                        </div>
                                    </div>
                                </div>
                            )}

                            <div>
                                <h3 className="text-sm font-bold uppercase text-metal-400 mb-2">Condições Gerais de Venda</h3>
                                <div className="text-xs text-metal-600 whitespace-pre-line leading-relaxed text-justify">
                                    {companySettings.generalConditions || 'Condições gerais não definidas nas configurações.'}
                                </div>
                            </div>
                        </div>
                    </div>

                    {/* Footer Page 1 */}
                    <div className="absolute bottom-[10mm] left-0 right-0 text-center text-xs text-metal-400 px-12">
                        {companySettings.quoteFooterText}
                    </div>
                </div>

                {/* PAGE 2+: DETAILS TABLE */}
                {/* Added html2pdf__page-break class for explicit break */}
                <div id="page2-start" className="pt-10 px-[15mm] html2pdf__page-break">

                    <div className="mb-6 border-b border-metal-300 pb-2 flex justify-between items-end">
                        <h2 className="text-xl font-bold text-metal-800">
                            Descrição Detalhada
                        </h2>
                        <span className="text-sm text-metal-500">Orçamento Nº {currentQuote.number}</span>
                    </div>

                    {/* Table Optimized: Image Left, Text Right */}
                    <table className="w-full mb-8 border-collapse">
                        <thead className="border-b-2 border-metal-800 bg-gray-50">
                            <tr className="text-left text-sm font-bold uppercase text-metal-900">
                                <th className="py-2 pl-2 w-32">Imagem</th>
                                <th className="py-2 pl-4">Descrição</th>
                                <th className="py-2 text-center w-24">Qtd</th>
                                <th className="py-2 text-right w-24">Unitário</th>
                                <th className="py-2 text-right w-24 pr-2">Total</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-metal-200">
                            {currentQuote.items.map(item => (
                                <tr key={item.id} className="break-inside-avoid">
                                    {/* Column 1: Image */}
                                    <td className="py-4 pl-2 align-top">
                                         {item.image ? (
                                            <div className="w-28 h-28 border border-gray-200 bg-white rounded p-1 flex items-center justify-center">
                                                <img src={item.image} alt="Item" className="max-w-full max-h-full object-contain" />
                                            </div>
                                        ) : (
                                            <div className="w-28 h-28 bg-gray-50 rounded flex items-center justify-center text-gray-300 text-xs">Sem Imagem</div>
                                        )}
                                    </td>

                                    {/* Column 2: Description */}
                                    <td className="py-4 pl-4 align-top">
                                        <div className="font-bold text-metal-800 text-base">{item.name}</div>
                                        <div className="text-sm text-metal-600 mt-1 whitespace-pre-line">{item.description}</div>
                                        {item.details && item.details.length > 0 && (
                                            <div className="mt-2 text-xs text-metal-500 bg-metal-50 p-2 rounded inline-block">
                                                {item.details.map((d, idx) => (
                                                    <div key={d.id} className="mr-3 inline-block">
                                                        <span className="font-semibold">{d.label}:</span> {d.value} 
                                                        {d.price && d.price > 0 && <span className="text-metal-400 ml-1">(+{d.price.toFixed(2)}€)</span>}
                                                    </div>
                                                ))}
                                            </div>
                                        )}
                                    </td>

                                    {/* Other Columns */}
                                    <td className="py-4 text-center align-top font-medium text-metal-700">{item.quantity} {item.unit}</td>
                                    <td className="py-4 text-right align-top text-metal-700">{item.unitPrice.toFixed(2)} €</td>
                                    <td className="py-4 text-right align-top font-bold text-metal-900 pr-2">{item.total.toFixed(2)} €</td>
                                </tr>
                            ))}
                        </tbody>
                    </table>

                    {/* Specific Notes for these items if any */}
                    {currentQuote.notes && (
                        <div className="bg-metal-50 p-4 rounded-lg border border-metal-100 mb-8 break-inside-avoid">
                            <h4 className="text-xs font-bold uppercase text-metal-500 mb-2">Notas Técnicas / Observações</h4>
                            <p className="text-sm text-metal-700 whitespace-pre-line">{currentQuote.notes}</p>
                        </div>
                    )}

                    {/* Small Repeater of Total at end of items (Optional but helpful) */}
                    <div className="text-right border-t border-metal-200 pt-4 mb-8 break-inside-avoid">
                         <span className="text-sm text-metal-500 mr-4">Total Geral:</span>
                         <span className="text-xl font-bold text-metal-900">{currentQuote.total.toFixed(2)} €</span>
                    </div>

                    <div className="text-center text-xs text-metal-400 mt-12 pt-4 border-t border-metal-100">
                        {companySettings.quoteFooterText}
                    </div>
                </div>
            </div>
        </div>
     )
  }

  return null;
};

export default QuoteManager;

export enum UnitType {
  UN = 'un',
  KG = 'kg',
  M = 'm',
  M2 = 'm²',
  HOUR = 'h'
}

export interface Client {
  id: string;
  name: string;
  email: string;
  phone: string;
  nif: string; // Tax ID
  address: string;
  postalCode: string;
  city: string;
}

export interface Article {
  id: string;
  name: string;
  description: string;
  price: number;
  unit: UnitType;
  image?: string; // Base64
}

export interface QuoteItemDetail {
  id: string;
  label: string;
  value: string;
  price?: number;
}

export interface QuoteItem {
  id: string;
  articleId: string;
  name: string;
  description?: string;
  quantity: number;
  unitPrice: number;
  unit: UnitType;
  total: number;
  image?: string;
  details?: QuoteItemDetail[];
}

export enum QuoteStatus {
  DRAFT = 'Rascunho',
  SENT = 'Enviado',
  ACCEPTED = 'Aprovado',
  REJECTED = 'Rejeitado',
  CLOSED = 'Concluído'
}

export interface Quote {
  id: string;
  clientId: string;
  number: number;
  date: string;
  validUntil: string;
  items: QuoteItem[];
  subtotal: number;
  taxRate: number;
  taxAmount: number;
  total: number;
  status: QuoteStatus;
  notes: string;
  internalNotes?: string;
  upfrontPercentage?: number; // % de Adjudicação
  enableUpfrontPayment?: boolean; // Se deve mostrar/calcular a entrada inicial
  includeInstallation?: boolean; // Novo: Se inclui mão de obra/instalação
}

export interface User {
  id: string;
  username: string;
  password: string;
  name: string;
  role: 'admin' | 'user';
}

export interface CompanySettings {
  name: string;
  address: string;
  postalCode: string;
  city: string;
  nif: string;
  phone: string;
  email: string;
  logo?: string;
  quoteFooterText: string;
  quoteIntroText?: string; // Novo: Texto inicial da carta/orçamento
  generalConditions?: string; // Texto longo para capa
  materialTypes: string[]; // Tipos dinâmicos de materiais
  // Supabase Sync Config
  supabaseUrl?: string;
  supabaseKey?: string;
}

export interface RawMaterial {
  id: string;
  name: string;
  type: string; // Agora é string dinâmica
  unit: UnitType;
  pricePerUnit: number;
}

export interface AppData {
  clients: Client[];
  articles: Article[];
  quotes: Quote[];
  nextQuoteNumber: number;
  users: User[];
  companySettings: CompanySettings;
  rawMaterials: RawMaterial[];
}

import React, { useState, useRef } from 'react';
import { 
  PlusIcon, 
  PrinterIcon, 
  TrashIcon, 
  ArrowLeftIcon, 
  SparklesIcon, 
  CameraIcon,
  MagnifyingGlassIcon,
  XMarkIcon,
  EnvelopeIcon,
  ArrowDownTrayIcon,
  CheckBadgeIcon,
  WrenchScrewdriverIcon
} from '@heroicons/react/24/outline';
import { Quote, Client, Article, QuoteItem, QuoteStatus, UnitType, CompanySettings, QuoteItemDetail } from '../types';
import { generateQuoteNotes } from '../services/geminiService';
import SchematicDesigner from './SchematicDesigner';

declare const html2pdf: any;

interface QuoteManagerProps {
  quotes: Quote[];
  clients: Client[];
  articles: Article[];
  nextQuoteNumber: number;
  companySettings: CompanySettings;
  onSaveQuote: (quote: Quote) => void;
  onDeleteQuote: (id: string) => void;
}

const QuoteManager: React.FC<QuoteManagerProps> = ({ 
  quotes, clients, articles, nextQuoteNumber, companySettings, onSaveQuote, onDeleteQuote 
}) => {
  const [view, setView] = useState<'list' | 'edit' | 'print'>('list');
  const [currentQuote, setCurrentQuote] = useState<Quote | null>(null);
  const [loadingAi, setLoadingAi] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [activeItemIdForUpload, setActiveItemIdForUpload] = useState<string | null>(null);
  const [showSchematicDesigner, setShowSchematicDesigner] = useState(false);

  // List Filters
  const [filterClient, setFilterClient] = useState('');
  const [filterDateStart, setFilterDateStart] = useState('');
  const [filterDateEnd, setFilterDateEnd] = useState('');

  // Client Search State (Edit Mode)
  const [clientSearchTerm, setClientSearchTerm] = useState('');
  const [showClientResults, setShowClientResults] = useState(false);
  const [showClientListModal, setShowClientListModal] = useState(false);

  // Helper to init a new quote
  const initNewQuote = () => {
    const newQuote: Quote = {
      id: crypto.randomUUID(),
      clientId: '',
      number: nextQuoteNumber,
      date: new Date().toISOString().split('T')[0],
      validUntil: new Date(Date.now() + 15 * 24 * 60 * 60 * 1000).toISOString().split('T')[0],
      items: [],
      subtotal: 0,
      taxRate: 23,
      taxAmount: 0,
      total: 0,
      status: QuoteStatus.DRAFT,
      notes: '',
      internalNotes: '',
      upfrontPercentage: 50, // Default 50%
      enableUpfrontPayment: true,
      includeInstallation: false // Default false
    };
    setCurrentQuote(newQuote);
    setClientSearchTerm('');
    setView('edit');
  };

  const calculateTotals = (quote: Quote): Quote => {
    const updatedItems = quote.items.map(item => {
        const detailsSum = item.details?.reduce((acc, d) => acc + (d.price || 0), 0) || 0;
        const total = item.quantity * (item.unitPrice + detailsSum);
        return { ...item, total };
    });

    const subtotal = updatedItems.reduce((sum, item) => sum + item.total, 0);
    const taxAmount = subtotal * (quote.taxRate / 100);
    const total = subtotal + taxAmount;
    return { ...quote, items: updatedItems, subtotal, taxAmount, total };
  };

  const handleAddItem = () => {
    if (!currentQuote) return;
    const newItem: QuoteItem = {
      id: crypto.randomUUID(),
      articleId: '',
      name: '',
      quantity: 1,
      unitPrice: 0,
      unit: UnitType.UN,
      total: 0,
      details: []
    };
    setCurrentQuote({ ...currentQuote, items: [...currentQuote.items, newItem] });
  };

  const handleItemChange = (itemId: string, field: keyof QuoteItem, value: any) => {
    if (!currentQuote) return;
    const updatedItems = currentQuote.items.map(item => {
      if (item.id !== itemId) return item;

      const updatedItem = { ...item, [field]: value };

      // Auto-fill from article
      if (field === 'articleId') {
        const article = articles.find(a => a.id === value);
        if (article) {
          updatedItem.name = article.name;
          updatedItem.description = article.description;
          updatedItem.unitPrice = article.price;
          updatedItem.unit = article.unit;
          // If article has image and item doesn't, use article image
          if(article.image && !updatedItem.image) {
              updatedItem.image = article.image;
          }
        }
      }

      return updatedItem;
    });

    setCurrentQuote(calculateTotals({ ...currentQuote, items: updatedItems }));
  };

  const handleDeleteItem = (itemId: string) => {
    if (!currentQuote) return;
    const updatedItems = currentQuote.items.filter(i => i.id !== itemId);
    setCurrentQuote(calculateTotals({ ...currentQuote, items: updatedItems }));
  };

  // --- ITEM DETAILS / OPTIONS LOGIC ---
  const handleAddDetail = (itemId: string) => {
    if (!currentQuote) return;
    const updatedItems = currentQuote.items.map(item => {
        if (item.id === itemId) {
            const newDetail: QuoteItemDetail = { id: crypto.randomUUID(), label: '', value: '', price: 0 };
            return { ...item, details: [...(item.details || []), newDetail] };
        }
        return item;
    });
    setCurrentQuote(calculateTotals({ ...currentQuote, items: updatedItems }));
  };

  const handleUpdateDetail = (itemId: string, detailId: string, field: 'label' | 'value' | 'price', val: any) => {
    if (!currentQuote) return;
    const updatedItems = currentQuote.items.map(item => {
        if (item.id === itemId) {
            const updatedDetails = (item.details || []).map(d => 
                d.id === detailId ? { ...d, [field]: val } : d
            );
            return { ...item, details: updatedDetails };
        }
        return item;
    });
    setCurrentQuote(calculateTotals({ ...currentQuote, items: updatedItems }));
  };

  const handleDeleteDetail = (itemId: string, detailId: string) => {
    if (!currentQuote) return;
    const updatedItems = currentQuote.items.map(item => {
        if (item.id === itemId) {
            return { ...item, details: (item.details || []).filter(d => d.id !== detailId) };
        }
        return item;
    });
    setCurrentQuote(calculateTotals({ ...currentQuote, items: updatedItems }));
  };

  // Image Upload Logic
  const triggerImageUpload = (itemId: string) => {
    setActiveItemIdForUpload(itemId);
    if (fileInputRef.current) {
        fileInputRef.current.click();
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0] && activeItemIdForUpload) {
        const file = e.target.files[0];
        const reader = new FileReader();
        reader.onload = (event) => {
             handleItemChange(activeItemIdForUpload, 'image', event.target?.result as string);
             setActiveItemIdForUpload(null);
        };
        reader.readAsDataURL(file);
    }
    e.target.value = '';
  };

  const handleSaveSchematic = (imgData: string) => {
      if (activeItemIdForUpload) {
          handleItemChange(activeItemIdForUpload, 'image', imgData);
          setShowSchematicDesigner(false);
          setActiveItemIdForUpload(null);
      }
  };

  const handleGenerateNotes = async () => {
    if (!currentQuote || currentQuote.items.length === 0) return;
    setLoadingAi(true);
    const itemNames = currentQuote.items.map(i => i.name);
    const notes = await generateQuoteNotes(itemNames);
    setCurrentQuote(prev => prev ? { ...prev, notes } : null);
    setLoadingAi(false);
  };

  const handleDownloadPdf = () => {
      // Switch to print view temporarily if not already
      const previousView = view;
      if (view !== 'print') {
          setView('print');
          // Wait for render
          setTimeout(() => executePdfGeneration(previousView), 500);
      } else {
          executePdfGeneration(previousView);
      }
  };

  const executePdfGeneration = (returnView: 'list' | 'edit' | 'print') => {
      const element = document.getElementById('print-area');
      if (!element) return;

      const opt = {
          margin: 0,
          filename: `Orcamento_${currentQuote?.number}.pdf`,
          image: { type: 'jpeg', quality: 0.98 },
          html2canvas: { scale: 2, useCORS: true, scrollY: 0 },
          jsPDF: { unit: 'mm', format: 'a4', orientation: 'portrait' },
          pagebreak: { mode: ['css', 'legacy'] }
      };

      // Gerar PDF e adicionar numeração de páginas
      // @ts-ignore
      html2pdf().from(element).set(opt).toPdf().get('pdf').then(function (pdf) {
        var totalPages = pdf.internal.getNumberOfPages();
        for (let i = 1; i <= totalPages; i++) {
            pdf.setPage(i);
            pdf.setFontSize(8);
            pdf.setTextColor(150);
            // Rodapé: Página X de Y
            pdf.text('Página ' + i + ' de ' + totalPages, pdf.internal.pageSize.getWidth() - 30, pdf.internal.pageSize.getHeight() - 10);
        }
      }).save().then(() => {
          if (returnView !== 'print') {
              setView(returnView);
          }
      });
  };

  const handleSendGmail = () => {
    if (!currentQuote) return;
    const client = clients.find(c => c.id === currentQuote.clientId);
    if (!client || !client.email) {
        alert("Cliente não tem email definido ou selecionado.");
        return;
    }

    const subject = encodeURIComponent(`Orçamento Nº ${currentQuote.number} - ${companySettings.name}`);
    const body = encodeURIComponent(
`Olá ${client.name},

Segue em anexo o Orçamento Nº ${currentQuote.number}.

Valor Total: ${currentQuote.total.toFixed(2)} €
Validade: ${new Date(currentQuote.validUntil).toLocaleDateString('pt-PT')}

Melhores cumprimentos,
${companySettings.name}`
    );

    alert("O PDF será descarregado. Por favor anexe-o manualmente no email que irá abrir.");
    handleDownloadPdf();
    setTimeout(() => {
        window.open(`https://mail.google.com/mail/?view=cm&fs=1&to=${client.email}&su=${subject}&body=${body}`, '_blank');
    }, 1500);
  };

  // --- CLIENT SEARCH & FILTER LOGIC ---
  const filteredClients = clients.filter(c => 
    c.name.toLowerCase().includes(clientSearchTerm.toLowerCase()) || 
    c.nif.includes(clientSearchTerm)
  );

  const selectClient = (client: Client) => {
    if (currentQuote) {
        setCurrentQuote({ ...currentQuote, clientId: client.id });
        setClientSearchTerm('');
        setShowClientResults(false);
        setShowClientListModal(false);
    }
  };

  const filteredQuotes = quotes.filter(q => {
      const client = clients.find(c => c.id === q.clientId);
      const matchesClient = filterClient === '' || client?.name.toLowerCase().includes(filterClient.toLowerCase());
      const matchesDateStart = filterDateStart === '' || q.date >= filterDateStart;
      const matchesDateEnd = filterDateEnd === '' || q.date <= filterDateEnd;
      return matchesClient && matchesDateStart && matchesDateEnd;
  });

  const getStatusColor = (status: QuoteStatus) => {
      switch(status) {
          case QuoteStatus.ACCEPTED: return 'bg-green-100 text-green-700';
          case QuoteStatus.SENT: return 'bg-blue-100 text-blue-700';
          case QuoteStatus.REJECTED: return 'bg-red-100 text-red-700';
          case QuoteStatus.CLOSED: return 'bg-gray-800 text-white';
          default: return 'bg-gray-100 text-gray-700';
      }
  };

  // --- RENDERERS ---

  if (view === 'list') {
    return (
      <div className="max-w-6xl mx-auto">
        <div className="flex justify-between items-center mb-6">
          <h2 className="text-2xl font-bold text-metal-800">Orçamentos</h2>
          <button onClick={initNewQuote} className="bg-primary-600 hover:bg-primary-700 text-white px-4 py-2 rounded-lg flex items-center shadow-sm">
            <PlusIcon className="w-5 h-5 mr-2" />
            Criar Orçamento
          </button>
        </div>

        {/* Filters */}
        <div className="bg-white p-4 rounded-xl shadow-sm border border-metal-200 mb-6 flex flex-wrap gap-4 items-end">
            <div className="flex-1 min-w-[200px]">
                <label className="text-xs text-metal-500 mb-1 block">Filtrar Cliente</label>
                <div className="relative">
                    <MagnifyingGlassIcon className="absolute left-2 top-2.5 w-4 h-4 text-gray-400" />
                    <input type="text" value={filterClient} onChange={e => setFilterClient(e.target.value)} className="w-full pl-8 p-2 border border-gray-300 rounded-lg text-sm bg-white text-gray-900" placeholder="Nome..." />
                </div>
            </div>
            <div>
                <label className="text-xs text-metal-500 mb-1 block">De</label>
                <input type="date" value={filterDateStart} onChange={e => setFilterDateStart(e.target.value)} className="p-2 border border-gray-300 rounded-lg text-sm bg-white text-gray-900" />
            </div>
            <div>
                <label className="text-xs text-metal-500 mb-1 block">Até</label>
                <input type="date" value={filterDateEnd} onChange={e => setFilterDateEnd(e.target.value)} className="p-2 border border-gray-300 rounded-lg text-sm bg-white text-gray-900" />
            </div>
            <button onClick={() => {setFilterClient(''); setFilterDateStart(''); setFilterDateEnd('')}} className="p-2 text-metal-500 hover:text-metal-800" title="Limpar Filtros">
                <XMarkIcon className="w-5 h-5" />
            </button>
        </div>

        <div className="bg-white rounded-xl shadow-sm border border-metal-200 overflow-hidden">
          <table className="w-full text-left">
            <thead className="bg-metal-50 text-metal-600 text-sm font-semibold">
              <tr>
                <th className="p-4">Nº</th>
                <th className="p-4">Cliente</th>
                <th className="p-4">Data</th>
                <th className="p-4">Total</th>
                <th className="p-4">Estado</th>
                <th className="p-4 text-center">Ações</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-metal-100">
              {filteredQuotes.length === 0 && (
                <tr><td colSpan={6} className="p-8 text-center text-metal-400">Sem orçamentos encontrados.</td></tr>
              )}
              {filteredQuotes.map(quote => {
                const client = clients.find(c => c.id === quote.clientId);
                return (
                  <tr key={quote.id} className="hover:bg-metal-50 cursor-pointer" onClick={() => { setCurrentQuote(quote); setView('edit'); }}>
                    <td className="p-4 font-mono text-metal-600">#{quote.number.toString().padStart(4, '0')}</td>
                    <td className="p-4 font-medium text-metal-900">{client?.name || 'Cliente Removido'}</td>
                    <td className="p-4 text-metal-600">{new Date(quote.date).toLocaleDateString('pt-PT')}</td>
                    <td className="p-4 font-bold text-metal-900">{quote.total.toFixed(2)} €</td>
                    <td className="p-4">
                      <span className={`px-2 py-1 rounded-full text-xs font-medium ${getStatusColor(quote.status)}`}>
                        {quote.status}
                      </span>
                    </td>
                    <td className="p-4 text-center">
                      <button 
                        onClick={(e) => { e.stopPropagation(); onDeleteQuote(quote.id); }}
                        className="p-2 text-red-500 hover:bg-red-50 rounded"
                      >
                        <TrashIcon className="w-4 h-4" />
                      </button>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </div>
    );
  }

  if (view === 'edit' && currentQuote) {
    const selectedClient = clients.find(c => c.id === currentQuote.clientId);

    return (
      <div className="max-w-5xl mx-auto space-y-6 pb-20">
        {/* Hidden Inputs/Modals */}
        <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleFileChange} />
        {showSchematicDesigner && (
            <SchematicDesigner 
                onSave={handleSaveSchematic} 
                onCancel={() => { setShowSchematicDesigner(false); setActiveItemIdForUpload(null); }} 
            />
        )}

        {/* Client Selection Modal */}
        {showClientListModal && (
            <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4">
                <div className="bg-white rounded-xl shadow-2xl w-full max-w-2xl max-h-[80vh] flex flex-col">
                    <div className="p-4 border-b border-metal-200 flex justify-between items-center">
                        <h3 className="text-lg font-bold text-metal-800">Selecionar Cliente</h3>
                        <button onClick={() => setShowClientListModal(false)} className="text-metal-400 hover:text-metal-600"><XMarkIcon className="w-6 h-6" /></button>
                    </div>
                    <div className="p-4 border-b border-metal-100">
                        <input 
                            type="text" autoFocus placeholder="Filtrar lista de clientes..." className="w-full p-2 border border-metal-300 rounded-lg text-sm bg-white text-gray-900"
                            value={clientSearchTerm} onChange={(e) => setClientSearchTerm(e.target.value)}
                        />
                    </div>
                    <div className="overflow-y-auto flex-1 p-2">
                        {filteredClients.map(client => (
                            <div key={client.id} onClick={() => selectClient(client)} className="p-3 hover:bg-gray-50 cursor-pointer border-b border-gray-100 flex justify-between">
                                <div>
                                    <div className="font-medium text-gray-900">{client.name}</div>
                                    <div className="text-xs text-gray-500">{client.nif}</div>
                                </div>
                                <button className="px-3 py-1 bg-primary-100 text-primary-700 rounded text-xs">Selecionar</button>
                            </div>
                        ))}
                    </div>
                </div>
            </div>
        )}

        <div className="flex items-center justify-between">
            <button onClick={() => setView('list')} className="flex items-center text-metal-500 hover:text-metal-800">
                <ArrowLeftIcon className="w-4 h-4 mr-1" /> Voltar
            </button>
            <div className="flex gap-2">
                 <button onClick={handleDownloadPdf} className="flex items-center px-3 py-2 bg-green-50 border border-green-200 text-green-700 rounded-lg hover:bg-green-100 text-sm font-medium">
                    <ArrowDownTrayIcon className="w-4 h-4 mr-2" /> Guardar PDF
                 </button>

                 {/* Status Selector */}
                 <div className="relative">
                    <select 
                        value={currentQuote.status}
                        onChange={(e) => setCurrentQuote({...currentQuote, status: e.target.value as QuoteStatus})}
                        className={`appearance-none px-3 py-2 pr-8 border rounded-lg text-sm font-medium ${getStatusColor(currentQuote.status)}`}
                    >
                        {Object.values(QuoteStatus).map(status => (
                            <option key={status} value={status}>{status}</option>
                        ))}
                    </select>
                    <ArrowDownTrayIcon className="w-4 h-4 absolute right-2 top-2.5 opacity-50 pointer-events-none" />
                 </div>

                 <button onClick={handleSendGmail} className="flex items-center px-3 py-2 border border-red-200 text-red-600 rounded-lg hover:bg-red-50 text-sm font-medium">
                    <EnvelopeIcon className="w-4 h-4 mr-1" /> Email
                </button>
                 <button onClick={() => { setView('print'); }} className="flex items-center px-4 py-2 border border-metal-300 rounded-lg bg-white hover:bg-metal-50 text-metal-700">
                    <PrinterIcon className="w-4 h-4 mr-2" /> Pré-visualizar
                </button>
                <button onClick={() => { onSaveQuote(currentQuote); setView('list'); }} className="bg-primary-600 hover:bg-primary-700 text-white px-6 py-2 rounded-lg font-medium shadow-sm">
                    Guardar
                </button>
            </div>
        </div>

        {/* Header Info */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-metal-200 grid grid-cols-1 md:grid-cols-3 gap-6">
           {/* Client Search Section */}
           <div>
             <label className="block text-sm font-medium text-metal-600 mb-1">Cliente</label>
             {selectedClient ? (
                 <div className="flex items-center justify-between p-2 border border-blue-200 bg-blue-50 rounded-lg">
                     <div>
                         <div className="font-bold text-blue-900">{selectedClient.name}</div>
                         <div className="text-xs text-blue-700">NIF: {selectedClient.nif || 'N/A'}</div>
                     </div>
                     <button onClick={() => setCurrentQuote({...currentQuote, clientId: ''})} className="text-blue-500 hover:text-blue-700 p-1"><XMarkIcon className="w-5 h-5" /></button>
                 </div>
             ) : (
                 <div className="flex gap-2">
                    <button onClick={() => setShowClientListModal(true)} className="flex-1 text-left px-3 py-2 border border-metal-300 rounded-lg bg-white text-gray-500 text-sm hover:bg-gray-50">Selecionar Cliente...</button>
                 </div>
             )}
           </div>

           <div>
             <label className="block text-sm font-medium text-metal-600 mb-1">Validade (Data)</label>
             <input type="date" value={currentQuote.validUntil} onChange={(e) => setCurrentQuote({...currentQuote, validUntil: e.target.value})} className="w-full border border-metal-300 rounded-lg p-2 bg-white text-gray-900" />
           </div>

           <div>
             <label className="block text-sm font-medium text-metal-600 mb-1">Condições e Opções</label>
             <div className="space-y-2">
                 <div className="flex items-center gap-2">
                    <input 
                        type="checkbox" 
                        checked={currentQuote.enableUpfrontPayment ?? true}
                        onChange={(e) => setCurrentQuote({...currentQuote, enableUpfrontPayment: e.target.checked})}
                        className="w-4 h-4 text-primary-600 rounded"
                    />
                    <span className="text-sm">Pagamento Adjudicação</span>
                    {(currentQuote.enableUpfrontPayment ?? true) && (
                        <div className="flex items-center ml-2">
                            <input 
                                type="number" min="0" max="100" 
                                value={currentQuote.upfrontPercentage ?? 50} 
                                onChange={(e) => setCurrentQuote({...currentQuote, upfrontPercentage: Number(e.target.value)})} 
                                className="w-14 border border-metal-300 rounded p-1 bg-white text-gray-900 text-right text-xs" 
                            />
                            <span className="text-xs text-metal-600 ml-1">%</span>
                        </div>
                    )}
                 </div>

                 {/* New Installation Toggle */}
                 <div className="flex items-center gap-2">
                     <input 
                         type="checkbox"
                         checked={currentQuote.includeInstallation ?? false}
                         onChange={(e) => setCurrentQuote({...currentQuote, includeInstallation: e.target.checked})}
                         className="w-4 h-4 text-primary-600 rounded"
                     />
                     <span className="text-sm flex items-center gap-1">
                         <WrenchScrewdriverIcon className="w-4 h-4 text-metal-500" />
                         Incluir Instalação / Montagem
                     </span>
                 </div>
             </div>
           </div>
        </div>

        {/* Items */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-metal-200">
            <h3 className="text-lg font-bold text-metal-800 mb-4">Itens do Orçamento</h3>
            <div className="space-y-4">
                {currentQuote.items.map((item, index) => (
                    <div key={item.id} className="p-4 bg-metal-50 rounded-lg border border-metal-100 animate-fade-in">
                        <div className="flex flex-col md:flex-row gap-4 items-start">
                            {/* Image Uploader */}
                            <div className="flex-shrink-0 flex flex-col gap-2">
                                <div 
                                    className="w-24 h-24 rounded-lg border-2 border-dashed border-metal-300 bg-white flex flex-col items-center justify-center overflow-hidden relative"
                                >
                                    {item.image ? (
                                        <img src={item.image} alt="Preview" className="w-full h-full object-contain" />
                                    ) : (
                                        <CameraIcon className="w-6 h-6 text-metal-300" />
                                    )}
                                </div>
                                <div className="flex gap-1">
                                    <button onClick={() => triggerImageUpload(item.id)} className="text-[10px] bg-white border p-1 rounded hover:bg-gray-50 flex-1">Foto</button>
                                    <button onClick={() => { setActiveItemIdForUpload(item.id); setShowSchematicDesigner(true); }} className="text-[10px] bg-white border p-1 rounded hover:bg-gray-50 flex-1">Desenho</button>
                                </div>
                            </div>

                            {/* Main Inputs */}
                            <div className="flex-1 space-y-2 w-full">
                                <div className="flex gap-2">
                                    <select 
                                        value={item.articleId}
                                        onChange={(e) => handleItemChange(item.id, 'articleId', e.target.value)}
                                        className="w-1/3 border border-metal-300 rounded-lg p-2 text-sm bg-white text-gray-900"
                                    >
                                        <option value="">Personalizado</option>
                                        {articles.map(a => <option key={a.id} value={a.id}>{a.name}</option>)}
                                    </select>
                                    <input 
                                        type="text" 
                                        placeholder="Nome do Item"
                                        value={item.name}
                                        onChange={(e) => handleItemChange(item.id, 'name', e.target.value)}
                                        className="flex-1 border border-metal-300 rounded-lg p-2 text-sm font-medium bg-white text-gray-900"
                                    />
                                </div>
                                <textarea 
                                    placeholder="Descrição detalhada..."
                                    value={item.description || ''}
                                    onChange={(e) => handleItemChange(item.id, 'description', e.target.value)}
                                    className="w-full border border-metal-300 rounded-lg p-2 text-sm h-16 resize-none bg-white text-gray-900"
                                />
                            </div>

                            {/* Qty & Price */}
                            <div className="flex gap-2 w-full md:w-auto items-start">
                                <div className="w-20">
                                    <label className="text-xs text-metal-500">Qtd</label>
                                    <input 
                                        type="number"
                                        min="1"
                                        value={item.quantity === 0 ? '' : item.quantity}
                                        onChange={(e) => handleItemChange(item.id, 'quantity', Number(e.target.value))}
                                        className="w-full border border-metal-300 rounded-lg p-2 text-sm bg-white text-gray-900"
                                    />
                                </div>
                                <div className="w-24">
                                    <label className="text-xs text-metal-500">Preço Unit.</label>
                                    <input 
                                        type="number"
                                        min="0"
                                        step="0.01"
                                        value={item.unitPrice === 0 ? '' : item.unitPrice}
                                        onChange={(e) => handleItemChange(item.id, 'unitPrice', Number(e.target.value))}
                                        className="w-full border border-metal-300 rounded-lg p-2 text-sm bg-white text-gray-900"
                                    />
                                </div>
                                <div className="w-24">
                                    <label className="text-xs text-metal-500">Total</label>
                                    <div className="p-2 bg-metal-100 rounded-lg text-sm font-bold text-right text-gray-900">
                                        {item.total.toFixed(2)}€
                                    </div>
                                </div>
                                <button 
                                    onClick={() => handleDeleteItem(item.id)}
                                    className="mt-5 text-red-500 hover:bg-red-50 p-2 rounded"
                                >
                                    <TrashIcon className="w-5 h-5" />
                                </button>
                            </div>
                        </div>

                        {/* PRODUCT OPTIONS / DETAILS */}
                        <div className="mt-4 pl-0 md:pl-28">
                            <h4 className="text-xs font-bold text-gray-500 uppercase mb-2">Acabamentos, Extras e Opções</h4>
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-2">
                                {item.details?.map((detail) => (
                                    <div key={detail.id} className="flex gap-2 items-center">
                                        <input type="text" placeholder="Ex: Cor" value={detail.label} onChange={(e) => handleUpdateDetail(item.id, detail.id, 'label', e.target.value)} className="w-1/4 p-1.5 text-xs border border-gray-300 rounded bg-white" />
                                        <input type="text" placeholder="Ex: Cinza" value={detail.value} onChange={(e) => handleUpdateDetail(item.id, detail.id, 'value', e.target.value)} className="w-1/3 p-1.5 text-xs border border-gray-300 rounded bg-white" />
                                        <div className="flex-1 flex items-center relative">
                                            <span className="absolute left-2 text-xs text-gray-500">+</span>
                                            <input type="number" placeholder="0.00" value={detail.price === 0 ? '' : detail.price} onChange={(e) => handleUpdateDetail(item.id, detail.id, 'price', Number(e.target.value))} className="w-full p-1.5 pl-4 text-xs border border-gray-300 rounded bg-white" />
                                            <span className="absolute right-2 text-xs text-gray-500">€</span>
                                        </div>
                                        <button onClick={() => handleDeleteDetail(item.id, detail.id)} className="text-red-400 hover:text-red-600"><XMarkIcon className="w-4 h-4" /></button>
                                    </div>
                                ))}
                                <button onClick={() => handleAddDetail(item.id)} className="flex items-center text-xs text-blue-600 hover:text-blue-800 font-medium py-1">
                                    <PlusIcon className="w-3 h-3 mr-1" /> Adicionar Opção
                                </button>
                            </div>
                        </div>
                    </div>
                ))}
            </div>

            <button onClick={handleAddItem} className="mt-4 flex items-center text-primary-600 hover:text-primary-700 font-medium">
                <PlusIcon className="w-5 h-5 mr-1" /> Adicionar Novo Item
            </button>
        </div>

        {/* Totals & Notes */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="space-y-6">
                <div className="bg-white p-6 rounded-xl shadow-sm border border-metal-200">
                    <div className="flex justify-between items-center mb-2">
                        <label className="block text-sm font-medium text-metal-600">Notas / Condições (Para o Cliente)</label>
                        <button onClick={handleGenerateNotes} disabled={loadingAi} className="text-purple-600 hover:text-purple-800 text-xs flex items-center font-medium">
