                {/* PAGE 1: COVER PAGE ONLY */}
                {/* Changed h-[297mm] to min-h to prevent cutting off if slightly large, but essentially full page */}
                <div className="min-h-[290mm] flex flex-col relative" style={{ height: '290mm' }}>

                    {/* LEFT HEADER: Logo + Company Info + Quote Info */}
                    <div className="absolute top-[15mm] left-[15mm] w-[90mm]">
                        {/* 1. Logo */}
