                        {/* Financial Summary Box - REDUCED SIZE */}
                        <div className="mb-8">
                            <div className="border border-metal-800 rounded-lg p-4 bg-gray-50 max-w-sm mx-auto">
                                <h3 className="text-xs font-bold uppercase text-metal-500 mb-3 border-b border-metal-300 pb-1 text-center">Resumo da Proposta</h3>

                                <div className="flex justify-between items-center mb-1 text-sm">
                                    <span>Total Ilíquido</span>
